const DATA = [{"name": "ABYC Marine Service Technician Certification", "code": "IRC-1001", "cluster": "Supply Chain & Transportation", "link": "https://www.nocti.org/wp-content/uploads/Blueprints/PartABYCMarineSvcTech9126.pdf", "issuer": "NOCTI", "cost": "The cost is $295 for members and $595 for non-members.", "accommodations": "https://www.nocti.org/credentials/accessibility/", "effDate": "July 1, 2025", "hours": "3-week, live online format (3 days per week) or intensive 3-day in-person sessions, including a 3-hour proctored exam", "trainingNotes": "While training is short, ABYC generally recommends 1\u20135 years of field experience for certification.", "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies ability to service and maintain marine vessels, engines, and equipment to industry standards.", "careerPaths": "Marine Technician, Boat Mechanic, Marine Service Manager, Watercraft Maintenance Specialist", "goodFitFor": "Programs with maritime or transportation focus; Supply chain and logistics-oriented programs; Coastal or waterside community organizations", "detailedDesc": "This credential from NOCTI validates technical skills in marine service including engine repair, electrical systems, and hull maintenance. It prepares youth for careers maintaining recreational and commercial vessels. The credential is recognized across the marine industry and opens pathways to boat manufacturing, repair shops, and marine facilities. Programs can incorporate online theory components with hands-on lab work at partner marine service facilities."}, {"name": "ADDA Apprentice Drafter Exam", "code": "IRC-1002", "cluster": "Advanced Manufacturing", "link": "https://www.adda.org/", "issuer": "American Design Drafting Association", "cost": "Exam costs $85 for non-members and $75 for members.", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations", "effDate": "July 1, 2025", "hours": "Experience Recommended: 1 year of on-the-job training or 400-600 contact hours of education.", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies ability to create technical drawings and designs according to industry standards and conventions.", "careerPaths": "CAD Drafter, Design Technician, Engineering Technician, Architectural Drafter", "goodFitFor": "Advanced manufacturing and engineering programs; Design and architecture-focused pathways; STEM programs emphasizing technical drawing", "detailedDesc": "This American Design Drafting Association credential validates skills in technical drawing, blueprint reading, and CAD fundamentals essential for manufacturing and engineering roles. Youth demonstrate ability to translate designs into precise drawings using industry-standard conventions. The apprentice-level certification prepares youth for manufacturing technician and design roles. Programs benefit from ADDA's standards and curriculum resources."}, {"name": "Adobe Acrobat Pro", "code": "IRC-1003", "cluster": "Arts, Entertainment & Design, Management and Entrepreneurship", "link": "https://certifiedprofessional.adobe.com/acrobat-pro", "issuer": "Adobe (Certiport)", "cost": "The cost is $150", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations", "effDate": "July 1, 2025", "hours": "Adobe Acrobat Pro certification training varies from short, focused courses of 5-6 hours to intensive, multi-day bootcamps (often 2\u20134 days)", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates proficiency in using Adobe Acrobat Pro to create, edit, manage, and secure professional PDF documents in business and legal settings.", "careerPaths": "Administrative Professional, Office Manager, Legal Assistant, Document Specialist, Business Analyst, Operations Coordinator", "goodFitFor": "Programs focused on business, administrative, or office careers; workforce development programs; broadly applicable across many OST program types; particularly useful for programs with administrative or legal sector employer partnerships", "detailedDesc": "The Adobe Acrobat Pro credential validates a student's ability to create, edit, review, protect, and manage PDF documents using Adobe Acrobat Pro, a tool used across virtually every professional sector. Skills covered include form creation, document security, PDF optimization, digital signatures, and collaboration features. This is a practical, broadly applicable credential that adds professional polish to any youth's skill set and is particularly valuable in business, legal, healthcare, and government work environments. Preparation requires relatively few hours and can be integrated into existing business or technology coursework."}, {"name": "Adobe Certified Professional After Effects", "code": "IRC-1004", "cluster": "Arts, Entertainment & Design", "link": "https://certiport.pearsonvue.com/Certifications/Adobe/ACP/Certify", "issuer": "Adobe (Certiport)", "cost": "The cost is $150", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations", "effDate": "July 1, 2025", "hours": "150 hours of instruction and hands-on experience. Structured certificate programs generally span 54 hours of in-depth training, while intensive bootcamps can condense the essential material into 4 days", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": "Arts2Work", "oneLiner": "Validates proficiency in Adobe After Effects for creating motion graphics, visual effects, and animated video content.", "careerPaths": "Motion Graphics Designer, Video Editor, Visual Effects Artist, Content Creator, Broadcast Designer, Digital Media Specialist", "goodFitFor": "Media arts and film production afterschool programs; creative OST programs with video or animation tracks; programs serving youth interested in entertainment, advertising, or digital media careers", "detailedDesc": "The Adobe Certified Professional in After Effects validates a student's ability to create motion graphics, visual effects, and animated video content using Adobe After Effects, the industry standard for broadcast design and digital media production. The exam covers composition creation, keyframe animation, visual effects, and rendering. Recognized by employers in advertising, film, television, and social media, this credential positions youth for creative careers at the intersection of design and technology. It pairs naturally with Adobe Premiere Pro for youth building comprehensive video production skills."}, {"name": "Adobe Certified Professional Animate", "code": "IRC-1005", "cluster": "Arts, Entertainment & Design", "link": "https://certiport.pearsonvue.com/Certifications/Adobe/ACP/Certify", "issuer": "Adobe (Certiport)", "cost": "The cost is $150", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations", "effDate": "July 1, 2025", "hours": "150 hours of instruction and hands-on experience. Comprehensive training courses designed for this certification often span several months to a year", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates proficiency in Adobe Animate for creating interactive animations, web content, and multimedia experiences.", "careerPaths": "Animator, Motion Designer, Interactive Media Developer, Digital Content Creator, Game Designer (entry), UX Designer", "goodFitFor": "Creative arts and digital media programs; programs with animation or game design tracks; STEM or design-focused afterschool programs; programs serving youth interested in entertainment, gaming, or interactive media careers", "detailedDesc": "The Adobe Certified Professional in Animate validates a student's ability to create interactive animations, web banners, cartoon characters, and multimedia content using Adobe Animate. The exam covers drawing tools, animation principles, timeline management, scripting basics, and publishing to web and video formats. This credential connects to careers in animation, game design, interactive media, and digital advertising. It is an excellent fit for creative OST programs with design or media production components and pairs well with other Adobe and digital media credentials."}, {"name": "Adobe Certified Professional Dreamweaver", "code": "IRC-1006", "cluster": "Arts, Entertainment & Design", "link": "https://certiport.pearsonvue.com/Certifications/Adobe/ACP/Certify", "issuer": "Adobe (Certiport)", "cost": "The cost is $150", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations", "effDate": "July 1, 2025", "hours": "While intensive, instructor-led training courses can span 4 days to 7 weeks, comprehensive, self-paced programs may last 12 weeks to 12 months", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates proficiency in using Adobe Dreamweaver to design, build, and manage professional websites and web applications.", "careerPaths": "Web Designer, Front-End Web Developer, Digital Content Specialist, UX/UI Designer (entry), Web Content Manager", "goodFitFor": "Programs with web design or digital media tracks; creative or tech-focused afterschool programs; programs serving youth interested in design and technology careers; summer digital media intensives", "detailedDesc": "The Adobe Certified Professional in Dreamweaver validates a student's ability to build and manage websites using Adobe Dreamweaver, including HTML/CSS editing, responsive design principles, and site structure management. Issued by Adobe through Certiport, this credential is recognized in web design and digital communications fields. Preparation typically takes 40\u201360 hours of instruction and practice. It is well-suited for programs that blend creative design with technical skills and serves as a complementary credential alongside Photoshop or Illustrator certifications."}, {"name": "Adobe Certified Professional Illustrator", "code": "IRC-1007", "cluster": "Arts, Entertainment & Design, Marketing and Sales", "link": "https://certiport.pearsonvue.com/Certifications/Adobe/ACP/Certify", "issuer": "Adobe (Certiport)", "cost": "The cost is $150", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations", "effDate": "July 1, 2025", "hours": "150 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": "Arts2Work", "oneLiner": "Validates professional-level skills in vector graphics creation and digital illustration using Adobe Illustrator.", "careerPaths": "Graphic Designer, Illustrator, Brand Designer, UX/UI Designer, Marketing Designer, Print Production Artist", "goodFitFor": "Creative arts and design afterschool programs; programs with visual arts or marketing tracks; programs serving youth interested in branding, advertising, or illustration careers; summer design intensives", "detailedDesc": "The Adobe Certified Professional in Illustrator validates a student's mastery of vector graphic design using Adobe Illustrator, the industry-standard tool for logos, branding, editorial illustration, and print design. The exam covers drawing tools, typography, color, effects, and file management. Recognized across design, marketing, and media industries, this credential opens doors to careers in graphic design, branding, and visual communications. It pairs well with other Adobe credentials (Photoshop, InDesign) for youth building a comprehensive creative portfolio."}, {"name": "Adobe Certified Professional InDesign", "code": "IRC-1008", "cluster": "Arts, Entertainment & Design", "link": "https://certiport.pearsonvue.com/Certifications/Adobe/ACP/Certify", "issuer": "Adobe (Certiport)", "cost": "The cost is $150", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations", "effDate": "July 1, 2025", "hours": "150 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates expertise in Adobe InDesign for professional print and digital layout design including publications, brochures, and marketing materials.", "careerPaths": "Graphic Designer, Layout Artist, Publication Designer, Marketing Coordinator, Pre-Press Technician, Content Designer", "goodFitFor": "Programs with graphic design, marketing, or print media tracks; creative arts afterschool programs; programs serving youth interested in publishing, communications, or design careers; programs partnered with print shops or marketing agencies", "detailedDesc": "The Adobe Certified Professional in InDesign validates a student's ability to create professional layouts for print and digital publications using Adobe InDesign, the industry standard for magazine layout, book design, brochures, and marketing materials. The exam covers typography, page layout, styles, color management, and document export. This credential is recognized by employers in publishing, communications, and marketing and pairs naturally with Photoshop and Illustrator certifications for youth building a full graphic design portfolio. It is well-suited for OST programs with a print media or communications focus."}, {"name": "Adobe Certified Professional Photoshop", "code": "IRC-1009", "cluster": "Arts, Entertainment & Design, Marketing and Sales", "link": "https://certiport.pearsonvue.com/Certifications/Adobe/ACP/Certify", "issuer": "Adobe (Certiport)", "cost": "The cost is $150", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations", "effDate": "July 1, 2025", "hours": "150 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": "Arts2Work", "oneLiner": "Industry-recognized credential validating expertise in Adobe Photoshop for photo editing, digital design, and visual communications.", "careerPaths": "Graphic Designer, Photographer, Digital Marketing Specialist, Photo Retoucher, Content Creator, Brand Designer", "goodFitFor": "Creative arts and design afterschool programs; programs with photography or digital media tracks; programs serving youth interested in design, photography, or marketing careers; broadly applicable to many OST program types", "detailedDesc": "The Adobe Certified Professional in Photoshop is one of the most widely recognized design credentials, validating a student's ability to edit photos, create digital compositions, and produce visual content using Adobe Photoshop. The exam covers image editing, color correction, layers, selections, and export for print and digital formats. This credential is recognized across virtually every creative and marketing field. Its accessibility and broad relevance make it one of the most practical credentials for OST programs to offer, especially those with creative arts, media, or marketing components."}, {"name": "Adobe Certified Professional Premiere Pro", "code": "IRC-1010", "cluster": "Arts, Entertainment & Design", "link": "https://certiport.pearsonvue.com/Certifications/Adobe/ACP/Certify", "issuer": "Adobe (Certiport)", "cost": "The cost is $150", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations", "effDate": "July 1, 2025", "hours": "150 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Industry-recognized credential validating professional video editing, production, and post-production skills using Adobe Premiere Pro.", "careerPaths": "Video Editor, Content Creator, Media Producer, Broadcast Technician, Digital Marketing Specialist", "goodFitFor": "Programs with media production, film, or broadcasting tracks; creative arts afterschool programs; programs partnered with media companies, TV stations, or marketing firms; summer media intensives", "detailedDesc": "The Adobe Certified Professional in Premiere Pro validates a student's ability to edit and produce professional-quality video content using Adobe Premiere Pro, the industry-standard video editing application. The exam covers project setup, clip management, audio mixing, transitions, color correction, and export settings. This credential is recognized by employers in media production, advertising, social media, and broadcast industries. It is an excellent fit for OST programs with video production equipment and connects well to growing demand for content creators across all sectors."}, {"name": "Adobe Content Creation and Marketing Certification", "code": "IRC-1011", "cluster": "Marketing and Sales", "link": "https://certiport.pearsonvue.com/Certifications/Adobe/ACP/Certify/AdobeProSpecialty", "issuer": "Adobe (Certiport)", "cost": "The cost is $150", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations", "effDate": "July 1, 2025", "hours": "150 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "Yes", "cclExpert": "Dent Education", "oneLiner": "Validates proficiency in using Adobe tools to create digital marketing content for social media, email, and web campaigns.", "careerPaths": "Digital Marketing Specialist, Social Media Manager, Content Creator, Graphic Designer, Marketing Coordinator", "goodFitFor": "Afterschool programs with creative media or marketing tracks; programs serving youth interested in entrepreneurship or social media; summer intensives focused on digital skills", "detailedDesc": "The Adobe Content Creation and Marketing Certification, offered through Certiport, demonstrates a student's ability to design compelling marketing assets using Adobe Creative Cloud tools. It covers digital advertising, social media graphics, email campaigns, and web content. This credential gives youth a direct, employer-recognized pathway into digital marketing and communications roles. Preparation can be completed in approximately 150 hours and integrates well into programs already offering design or technology coursework."}, {"name": "Advanced Engine Performance Specialist Test L1", "code": "IRC-1012", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The tests are $59 each and a $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": "Some programs allow for a combination of education (e.g., a 720-hour program) and one year of experience.", "trainingNotes": null, "prereqs": "Automobile Engine Performance (A8) exam", "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies advanced-level automotive engine performance diagnosis and repair expertise.", "careerPaths": "Engine Performance Specialist, Diagnostic Technician, Advanced Automotive Technician, Service Manager, Technical Trainer", "goodFitFor": "Advanced automotive specialization and diagnostic career pathways; Professional development for experienced technicians; STEM-focused vehicle systems programs", "detailedDesc": "This credential, issued by ASE, represents advanced-level expertise in engine performance systems, requiring significant hands-on experience and mastery of diagnostic tools. Specialists with L1 certification earn premium wages and often move into service management or technical roles. The credential signals mastery of modern vehicle computer systems. Programs should position this as an advanced step for youth with foundational automotive experience."}, {"name": "American Welding Society Qualification", "code": "IRC-1013", "cluster": "Construction", "link": "https://www.aws.org/certification-and-education/program-price-list/", "issuer": "American Welding Society (AWS)", "cost": "The  exam costs $100, while Associate-level exams are $150 each", "accommodations": "https://aws-p-001-delivery.sitecorecontenthub.cloud/api/public/content/Certification-Examination-ADA", "effDate": "July 1, 2025", "hours": "AWS welding certification training varies from 40-hour targeted courses to 7-month to 2-year programs, or 3-4 year apprenticeships", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates proficiency in welding techniques and safety practices as established by industry standards.", "careerPaths": "Welder, Welding Inspector, Structural Welder, Pipe Welder, Certified Welding Technician, Fabrication Specialist", "goodFitFor": "Construction career pathway programs; Workforce development programs with union or apprenticeship partnerships; Programs serving youth interested in skilled trades", "detailedDesc": "The American Welding Society (AWS) qualifications test youth on fundamental welding skills, safety protocols, and quality standards essential for entry into apprenticeships and construction careers. This is often an entry-level credential that prepares youth for more specialized AWS process certifications. Youth gain hands-on experience in a high-demand field with strong wage progression. Programs typically require welding equipment and instructor certification to deliver training."}, {"name": "Animal Science Specialist Certification (AEST)", "code": "IRC-1014", "cluster": "Agriculture", "link": "https://aest.ag/certify/certifications/animal-science/", "issuer": "Agriculture Education Services & Technology Inc. (AEST)", "cost": "The initial exam fee is $85 and retake exam fees are $50", "accommodations": "https://acvp.org/examination/ada-accommodations-request/#:~:text=Extended%20Time%20(1.5X),Report%20from%20licensed%20professional%20*", "effDate": "July 1, 2025", "hours": "at least 300 hours of training or two years of experience in the agriculture industry", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies knowledge of animal science principles, animal management, and agricultural practices.", "careerPaths": "Animal Science Specialist, Farm Manager, Livestock Technician, Agricultural Specialist", "goodFitFor": "Agriculture and agribusiness programs; Rural education partnerships; Programs serving students with farming or ranching interests", "detailedDesc": "This AEST credential validates comprehensive knowledge of animal biology, management practices, and agricultural operations. Youth learn to apply scientific principles to livestock and animal agriculture. The certification demonstrates readiness for farm management, breeding programs, and agricultural technical roles. Programs often partner with farms or agricultural extension offices."}, {"name": "Apple Swift Level 1", "code": "IRC-1015", "cluster": "Digital Technology", "link": "https://certiport.pearsonvue.com/Certifications/Apple/App-Dev-With-Swift/Overview.aspx", "issuer": "Certiport", "cost": "The Cost is $140", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "150 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates foundational proficiency in Swift programming and iOS app development using Apple's curriculum and development tools.", "careerPaths": "iOS App Developer, Mobile Software Developer, Software Engineer (entry), Front-End Developer, UX Designer", "goodFitFor": "Coding and technology afterschool programs; programs using Apple's Everyone Can Code curriculum; programs serving youth interested in app development or entrepreneurship; school-based OST programs with iPads or Mac computers", "detailedDesc": "The Apple Swift Level 1 certification, offered through Certiport, validates a student's foundational knowledge of Swift programming\u2014Apple's language for developing iOS, macOS, and other Apple platform apps. It aligns with Apple's Everyone Can Code curriculum and covers programming fundamentals, app structure, and basic Swift syntax. This credential is recognized by employers in mobile app development and software engineering fields and serves as a strong introduction for youth exploring coding careers. It is particularly well-suited for programs with Apple device ecosystems."}, {"name": "ASE Entry-Level Engine Repair", "code": "IRC-1016", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/entry-level", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The test are $59 each and $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": "range from 13 months to 2 years for full automotive programs", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates entry-level knowledge of engine repair procedures and diagnostics for automotive technicians.", "careerPaths": "Automotive Service Technician, Engine Repair Specialist, Automotive Technician, Service Technician, Quick Lube Technician", "goodFitFor": "Entry-level automotive career pathways; Engine repair and diagnostics programs; Youth beginning vehicle service careers", "detailedDesc": "This credential, issued by ASE, certifies entry-level competency in engine systems including assembly, disassembly, and basic repairs. It's a natural progression from G1 maintenance certification and opens roles in automotive service centers. Engine specialists earn solid wages with advancement opportunities. Programs should provide hands-on training on actual engines with proper tools and diagnostics equipment."}, {"name": "ASE Entry-Level Automatic Transmission/Transaxle", "code": "IRC-1017", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/entry-level", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The test are $59 each and $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": "1 to 2 years of automotive training, or roughly 64 weeks of instruction", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies entry-level automatic transmission diagnosis and repair competencies for light-duty vehicles.", "careerPaths": "Transmission Technician, Automotive Service Technician, Transmission Repair Specialist, Service Technician, Diagnostic Technician", "goodFitFor": "Entry-level automotive specialization; Transmission and drivetrain career pathways; Youth interested in complex mechanical systems", "detailedDesc": "This credential, issued by ASE, validates understanding of automatic transmission systems, fluid types, and basic repair procedures for passenger vehicles. Transmission specialists are in high demand and earn above-average wages. The specialization offers clear pathways to advanced transmission work or broader automotive expertise. Programs should emphasize hands-on transmission service and testing."}, {"name": "ASE Entry-Level Manual Drive Train & Axles", "code": "IRC-1018", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/entry-level", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The test are $59 each and $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates entry-level manual transmission, drive train, and differential diagnosis and repair skills.", "careerPaths": "Transmission Technician, Drive Train Specialist, Manual Transmission Expert, Service Technician, Heavy-Duty Technician", "goodFitFor": "Entry-level automotive specialization; Manual drivetrain and transmission career pathways; Youth interested in drivetrain systems", "detailedDesc": "This credential, issued by ASE, certifies competency in manual transmission, clutch systems, and drive axles for light-duty vehicles. It opens specialized careers in transmission repair and prepares youth for heavy-duty transmission work. Drivetrain specialists earn solid wages with steady demand. Programs should provide hands-on experience with various transmission types and diagnostic procedures."}, {"name": "ASE Entry-Level Suspension & Steering", "code": "IRC-1019", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/entry-level", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The test are $59 each and $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies entry-level suspension and steering system diagnosis and repair for automotive technicians.", "careerPaths": "Suspension Technician, Service Technician, Alignment Technician, Steering Specialist, Automotive Technician", "goodFitFor": "Entry-level automotive specialization; Suspension and steering career pathways; Safety-focused vehicle maintenance programs", "detailedDesc": "This credential, issued by ASE, validates competency in suspension systems, steering mechanisms, and alignment for safe vehicle operation. Suspension work is critical to vehicle safety and is always in demand. Technicians with this specialty earn solid wages and have excellent job stability. Programs should emphasize safety implications and provide training on alignment equipment and diagnostic tools."}, {"name": "ASE Entry-Level Brakes", "code": "IRC-1020", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/entry-level", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The test are $59 each and $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates entry-level brake system diagnosis, repair, and maintenance for safe vehicle operation.", "careerPaths": "Brake Service Technician, Brake Specialist, Service Technician, Automotive Technician, Safety Inspector", "goodFitFor": "Entry-level automotive specialization; Brake service and safety-focused career pathways; Vehicle maintenance and inspection programs", "detailedDesc": "This credential, issued by ASE, certifies understanding of brake systems including hydraulics, friction materials, and electronic components. Brake work is essential to vehicle safety and is consistently in demand. Brake specialists earn solid wages with excellent job security. Programs should emphasize safety-critical knowledge and provide hands-on training on various brake systems."}, {"name": "ASE Entry-Level Electrical/Electronic Systems", "code": "IRC-1021", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/entry-level", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The test are $59 each and $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies entry-level electrical and electronic system diagnosis and repair for modern vehicles.", "careerPaths": "Electrical Technician, Service Technician, Diagnostic Technician, Electronics Specialist, Automotive Technician", "goodFitFor": "Entry-level automotive specialization; Electrical and electronics career pathways; STEM-focused vehicle systems programs", "detailedDesc": "This credential, issued by ASE, validates competency in automotive electrical systems, battery, starting, charging, and basic electronics. Modern vehicles rely heavily on electrical systems, making this specialty valuable and increasingly in-demand. Electrical specialists earn above-average wages. Programs should integrate computer diagnostic tools and circuit analysis with hands-on work."}, {"name": "ASE Entry-Level Heating & Air Conditioning", "code": "IRC-1022", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/entry-level", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The test are $59 each and $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates entry-level heating and air conditioning system service, diagnostics, and repair for vehicles.", "careerPaths": "HVAC Technician, Refrigeration Technician, Climate Control Specialist, Service Technician, Automotive Technician", "goodFitFor": "Entry-level automotive specialization; HVAC and climate control career pathways; Environmental compliance and refrigerant handling programs", "detailedDesc": "This credential, issued by ASE, certifies competency in automotive climate control systems and requires EPA Section 609 certification for refrigerant handling. HVAC specialists earn solid wages and work is steady year-round. The specialty transitions well to building HVAC careers. Programs should emphasize environmental compliance and provide hands-on training on diagnostic and recovery equipment."}, {"name": "ASE Entry-Level Engine Performance", "code": "IRC-1023", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/entry-level", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The test are $59 each and $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies entry-level engine performance system diagnosis using modern diagnostic equipment.", "careerPaths": "Engine Performance Specialist, Diagnostic Technician, Service Technician, Automotive Technician, Technical Support", "goodFitFor": "Entry-level automotive specialization; Diagnostic and troubleshooting career pathways; STEM-focused vehicle systems programs", "detailedDesc": "This credential, issued by ASE, validates understanding of engine performance systems including sensors, fuel systems, and emission controls. Modern vehicles require sophisticated diagnostics, making performance specialists increasingly valuable. These technicians earn above-average wages. Programs should emphasize computer diagnostic tools and sensor systems alongside traditional troubleshooting."}, {"name": "ASE Entry-Level Diesel Engines", "code": "IRC-1024", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/entry-level", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The test are $59 each and $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates entry-level diesel engine mechanics, diagnostics, and repair for heavy-duty applications.", "careerPaths": "Diesel Technician, Heavy-Duty Technician, Diesel Engine Specialist, Fleet Maintenance Technician, Service Technician", "goodFitFor": "Entry-level diesel and heavy-duty career pathways; Truck and fleet maintenance programs; Commercial vehicle specialist programs", "detailedDesc": "This credential, issued by ASE, certifies diesel engine systems knowledge for light and medium-duty diesel applications. Diesel technicians are in high demand in commercial and industrial sectors, earning above-average wages. The specialty opens pathways to heavy-duty truck work and fleet management. Programs should provide hands-on training on diesel-specific tools and systems."}, {"name": "ASE Entry-Level Automobile Service Technology", "code": "IRC-1025", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/entry-level", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The test are $59 each and $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates comprehensive entry-level automotive service knowledge covering multiple vehicle systems.", "careerPaths": "Automotive Service Technician, General Technician, Diagnostic Technician, Fleet Maintenance Technician, Quick Lube Manager", "goodFitFor": "Entry-level comprehensive automotive career pathways; General automotive service programs; Multi-skill vehicle maintenance programs", "detailedDesc": "This credential, issued by ASE, tests broad competency across vehicle systems (engine, transmission, brakes, electrical) rather than single specialties. It demonstrates well-rounded technical knowledge and is attractive to employers seeking versatile technicians. Successful technicians can earn solid wages and specialize later. Programs should provide broad exposure to multiple vehicle systems to build flexibility."}, {"name": "ASE Entry-Level Maintenance and Light Repair", "code": "IRC-1026", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/entry-level", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The test are $59 each and $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies entry-level automotive maintenance and light repair competencies across vehicle systems.", "careerPaths": "Service Technician, Maintenance Technician, Quick Lube Technician, General Service Technician, Automotive Assistant", "goodFitFor": "Entry-level automotive career pathways; General maintenance and light repair programs; Youth beginning automotive service careers", "detailedDesc": "This credential, issued by ASE, validates basic maintenance knowledge (fluids, filters, adjustments) and light repairs across all vehicle systems. It prepares youth for entry-level service technician roles in dealerships, independent shops, and quick-lube facilities. Technicians earn entry-level wages with advancement potential. Programs should emphasize practical experience in working service environments."}, {"name": "ASE Entry-Level Painting and Refinishing", "code": "IRC-1027", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/entry-level", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The test are $59 each and $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates entry-level automotive painting, refinishing, and coating application competencies.", "careerPaths": "Automotive Painter, Collision Repair Technician, Paint Specialist, Refinish Technician, Custom Painter", "goodFitFor": "Entry-level collision and paint repair career pathways; Specialty finishing and restoration programs; Craft-focused vehicle repair programs", "detailedDesc": "This credential, issued by ASE, certifies spray painting skills, surface preparation, coating selection, and finishing techniques for collision repair. Painters are in high demand and earn strong wages, often supplemented by productivity bonuses. The specialty offers advancement to supervisory roles or specialty paint work. Programs should emphasize safety with proper ventilation and protective equipment."}, {"name": "ASE/609 Refrigerant Recovery and Recycling", "code": "IRC-1028", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/refrigerant-recovery-and-recycling-program", "issuer": "ASE Refrigerant Recovery and Recycling Program", "cost": "The cost is $23 for the online test and $27 for the printed version.", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": "Training typically involves completing an ASE-accredited curriculum, which can take up to 2 years (approx. 64 weeks)", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies environmental competency in refrigerant recovery and recycling for air conditioning systems.", "careerPaths": "Refrigeration Technician, HVAC Technician, Environmental Compliance Specialist, Equipment Service Technician, Automotive Technician", "goodFitFor": "Environmental compliance and safety-focused technical programs; HVAC and refrigeration career pathways; Legal compliance training for technicians", "detailedDesc": "This credential, issued by the ASE Refrigerant Recovery Program, certifies EPA Section 609 compliance for handling automotive refrigerants responsibly. Required for anyone servicing vehicle air conditioning, this certification protects the environment and keeps technicians legal. It's often combined with broader HVAC certification. Programs must include environmental impact discussion alongside technical training."}, {"name": "ASE Entry-Level  Inspection Maintenance & Minor Repair", "code": "IRC-1029", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/entry-level", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The tests are $59 each and a $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Validates entry-level knowledge of vehicle inspection procedures, basic maintenance tasks, and minor repair operations for light vehicles.", "careerPaths": "Automotive Service Technician (entry), Lube Technician, Vehicle Inspector, Quick Service Technician, Fleet Maintenance Assistant", "goodFitFor": "Programs with automotive technology or transportation career tracks; programs serving youth 16+ interested in entry-level automotive employment; workforce development programs partnered with automotive dealerships, repair shops, or fleet operators; broadly accessible for programs introducing youth to the automotive trades", "detailedDesc": "The ASE Entry-Level Inspection, Maintenance & Minor Repair certification validates foundational knowledge of routine vehicle inspection procedures, preventive maintenance services, and minor repairs for light-duty vehicles. It is designed as an entry point for youth beginning automotive careers, covering oil changes, tire rotations, fluid checks, brake inspections, and basic safety assessments. This credential is recognized by employers at dealerships, quick-lube shops, and fleet maintenance facilities as a sign of job-readiness. It pairs naturally with other ASE entry-level credentials for youth building a comprehensive automotive service skillset."}, {"name": "Autodesk 360 Fusion", "code": "IRC-1030", "cluster": "Advanced Manufacturing", "link": "https://www.autodesk.com/certification/overview", "issuer": "Autodesk", "cost": "The cost can range from $150 to $250.", "accommodations": "https://www.autodesk.com/certification/support", "effDate": "July 1, 2025", "hours": "Certificate programs generally span 60 to 80 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": "OpenWorks", "oneLiner": "Validates ability to use Autodesk Fusion 360 for 3D modeling, simulation, and computer-aided design in manufacturing contexts.", "careerPaths": "CAD Technician, Product Designer, Manufacturing Engineer (entry), 3D Modeling Specialist, Mechanical Designer", "goodFitFor": "Programs with maker spaces or fabrication labs; STEM afterschool programs focused on engineering or manufacturing; programs serving youth interested in product design or engineering; summer maker or engineering intensives", "detailedDesc": "The Autodesk Fusion 360 credential certifies a student's ability to create and modify 3D models, run simulations, and prepare designs for manufacturing using Autodesk Fusion 360, an industry-standard CAD/CAM software platform. Certificate preparation generally spans 60\u201380 hours of combined instruction and hands-on practice. This credential is increasingly valued in advanced manufacturing, product design, and engineering fields as companies adopt integrated design-to-manufacturing workflows. Programs with access to 3D printers or CNC machines will find it pairs especially well with hands-on fabrication activities."}, {"name": "Autodesk AutoCAD Certified User", "code": "IRC-1031", "cluster": "Advanced Manufacturing", "link": "https://www.autodesk.com/certification/overview", "issuer": "Autodesk", "cost": "Exam voucher ranges from $94 to $113.", "accommodations": "https://www.autodesk.com/certification/support", "effDate": "July 1, 2025", "hours": "100 to 200 hours of hands-on experience or study, usually completed over 1\u20133 months, though some structured courses allow up to 6 months", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates foundational proficiency in AutoCAD, the industry-standard computer-aided design software used across architecture, engineering, and manufacturing.", "careerPaths": "CAD Drafter, Engineering Technician, Architectural Designer (entry), Manufacturing Designer, Construction Project Coordinator", "goodFitFor": "Programs with STEM, engineering, or design tracks; afterschool programs with access to design software; programs aligned with construction, architecture, or manufacturing career pathways; CTE-aligned OST programs", "detailedDesc": "The Autodesk AutoCAD Certified User credential validates a student's ability to create, modify, and manage 2D and 3D drawings using AutoCAD, the most widely used CAD software in the world. It is recognized by employers in architecture, engineering, construction, and manufacturing. Preparation typically takes 30\u201350 hours of instruction and practice. This credential gives youth a strong foundation for drafting and design careers and is an excellent entry point for students interested in engineering, architecture, or advanced manufacturing."}, {"name": "Autodesk Inventor Certified User", "code": "IRC-1032", "cluster": "Advanced Manufacturing", "link": "https://www.autodesk.com/certification/overview", "issuer": "Autodesk", "cost": "The exam costs between $110 and $140, including the proctoring fee.", "accommodations": "https://www.autodesk.com/certification/support", "effDate": "July 1, 2025", "hours": "50\u2013150 hours of combined instruction and hands-on use.", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": "OpenWorks", "oneLiner": "Credential certifying proficiency in Autodesk Inventor for parametric 3D mechanical design and engineering drawing.", "careerPaths": "Mechanical Designer, CAD Technician, Manufacturing Engineer (entry), Product Development Technician, Drafting Technician", "goodFitFor": "Programs with STEM or engineering career tracks; OST programs with access to design software and engineering tools; programs serving youth interested in manufacturing or mechanical engineering; CTE-aligned afterschool programs", "detailedDesc": "The Autodesk Inventor Certified User credential validates a student's proficiency in parametric 3D modeling, assembly design, and engineering drawing using Autodesk Inventor, a leading tool in mechanical product design. Preparation typically requires 50\u2013150 hours depending on prior CAD experience. This credential is recognized by employers in manufacturing, automotive, aerospace, and product design industries. It is best suited for programs with access to design workstations and instructors or partners with engineering or CAD backgrounds."}, {"name": "Autodesk Revit Certified User", "code": "IRC-1033", "cluster": "Construction, Advanced Manufacturing", "link": "https://www.autodesk.com/certification/overview", "issuer": "Autodesk", "cost": "The cost ranges from $100 to $140", "accommodations": "https://www.autodesk.com/certification/support", "effDate": "July 1, 2025", "hours": "40\u2013150+ hours of study and practice over 1\u20133 months", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates proficiency in Autodesk Revit for Building Information Modeling (BIM) in architecture, engineering, and construction projects.", "careerPaths": "Architectural Designer, BIM Technician, Construction Project Coordinator, Civil Engineering Technician, Facilities Designer", "goodFitFor": "Programs with architecture, construction management, or engineering design tracks; STEM programs with a built environment focus; programs partnered with architecture firms, engineering companies, or general contractors; CTE-aligned OST programs", "detailedDesc": "The Autodesk Revit Certified User credential validates a student's ability to use Autodesk Revit for Building Information Modeling (BIM), the increasingly standard workflow for designing and documenting construction projects in architecture, engineering, and construction (AEC). Preparation typically requires 40\u201380 hours of instruction and hands-on practice. As the AEC industry rapidly adopts BIM workflows, Revit skills are in high demand from architecture firms, engineering consultancies, and large contractors. This credential is an excellent fit for programs building youth pathways into the design and construction professions."}, {"name": "AVID Pro Tools", "code": "IRC-1034", "cluster": "Arts, Entertainment & Design", "link": "https://www.avid.com/pro-tools", "issuer": "AVID", "cost": "The certification itself cost around $150", "accommodations": "https://www.avid.com/learning/certification", "effDate": "July 1, 2025", "hours": "42\u201348 hours of combined instruction and study to achieve User Certification (101 & 110 levels), typically structured as two, 3-day courses (about 6 days total)", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Industry-standard audio production credential validating proficiency in Pro Tools software for recording, editing, and mixing professional audio.", "careerPaths": "Audio Engineer, Music Producer, Podcast Producer, Broadcast Audio Technician, Sound Designer, Recording Studio Technician", "goodFitFor": "Programs with music production, audio engineering, or media arts tracks; creative OST programs with recording studios or audio labs; programs serving youth interested in the music industry; performing arts afterschool programs", "detailedDesc": "The AVID Pro Tools User Certification validates a student's ability to record, edit, mix, and produce audio using Pro Tools, the dominant digital audio workstation (DAW) in professional recording studios and broadcast facilities. Issued by AVID, this credential is recognized across the music, film, television, and podcast industries. Preparation typically takes 40\u201360 hours of hands-on studio practice. It is an ideal credential for programs already incorporating music or audio production and gives youth a competitive edge when pursuing careers in the music, entertainment, or media industries."}, {"name": "AWS Certified Welding - BZ or NZ?", "code": "IRC-1035", "cluster": "Construction", "link": "https://www.aws.org/certification-and-education/program-price-list/", "issuer": "American Welding Society (AWS)", "cost": "The  exam costs $100, while Associate-level exams are $150 each", "accommodations": "https://aws-p-001-delivery.sitecorecontenthub.cloud/api/public/content/Certification-Examination-ADA", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies competency in flux-cored arc welding (FCAW) and solid wire GMAW-P processes.", "careerPaths": "Welder, Structural Welder, Pipe Welder, Certification Examiner, Field Technician, Production Welder", "goodFitFor": "Construction programs with welding labs; Apprenticeship preparation programs; Workforce development programs partnered with manufacturing or construction employers", "detailedDesc": "This AWS credential specifically validates skills in two critical welding processes used in steel fabrication and structural work. The certification requires passing a performance test that demonstrates proper technique, penetration, and bead quality. Youth who earn this credential gain a recognized qualification that construction employers actively recruit for. Programs must have access to welding equipment, certified instructors, and may need to arrange testing through AWS-approved testing facilities."}, {"name": "AWS Certified Welding - FCAW", "code": "IRC-1036", "cluster": "Construction", "link": "https://www.aws.org/certification-and-education/program-price-list/", "issuer": "American Welding Society (AWS)", "cost": "The  exam costs $100, while Associate-level exams are $150 each", "accommodations": "https://aws-p-001-delivery.sitecorecontenthub.cloud/api/public/content/Certification-Examination-ADA", "effDate": "July 1, 2025", "hours": "4 to 10 weeks (approx. 42 to 180+ hours)", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates proficiency in flux-cored arc welding (FCAW), a common process in structural and pipe welding.", "careerPaths": "Welder, Structural Welder, Pipe Welder, Certified Welding Technician, Fabrication Technician, Welding Inspector", "goodFitFor": "Construction skill-building programs; Industrial training centers; Apprenticeship preparation programs for union or non-union trades", "detailedDesc": "AWS certification in FCAW demonstrates competency in one of the most widely used welding processes in construction and manufacturing. The certification test evaluates proper arc initiation, travel speed, heat control, and penetration quality. This credential opens doors to apprenticeships and immediate employment in high-wage fields. OST programs typically deliver this through partnership with community colleges or trade schools that maintain certified testing facilities."}, {"name": "AWS Certified Welding - GMAW", "code": "IRC-1037", "cluster": "Construction", "link": "https://www.aws.org/certification-and-education/program-price-list/", "issuer": "American Welding Society (AWS)", "cost": "The  exam costs $100, while Associate-level exams are $150 each", "accommodations": "https://aws-p-001-delivery.sitecorecontenthub.cloud/api/public/content/Certification-Examination-ADA", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies competency in gas metal arc welding (GMAW), the most common industrial welding process.", "careerPaths": "Welder, Manufacturing Technician, Pipe Welder, Structural Welder, Production Specialist, Certified Welding Inspector", "goodFitFor": "Manufacturing-focused career programs; Construction and skilled trades pipelines; Workforce development programs with industry employer partnerships", "detailedDesc": "GMAW is the fastest-growing and most widely used welding process in manufacturing and construction, making this AWS credential highly employable. The certification test measures skill in controlling the arc, maintaining proper travel speed, and producing quality welds in various positions. Youth completing this credential are immediately job-ready for entry-level manufacturing and construction positions with competitive wages. Programs need welding equipment and access to AWS-certified testing."}, {"name": "AWS Certified Welding - GTAW", "code": "IRC-1038", "cluster": "Construction", "link": "https://www.aws.org/certification-and-education/program-price-list/", "issuer": "American Welding Society (AWS)", "cost": "The  exam costs $100, while Associate-level exams are $150 each", "accommodations": "https://aws-p-001-delivery.sitecorecontenthub.cloud/api/public/content/Certification-Examination-ADA", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates proficiency in gas tungsten arc welding (GTAW), a precision process used in specialized applications.", "careerPaths": "Welder, Pipe Welder, Aircraft Fabricator, Aerospace Technician, Certified Welding Inspector, Precision Fabricator", "goodFitFor": "Advanced welding programs for experienced youth; STEM programs with precision manufacturing focus; Programs serving rural or underserved areas with industrial jobs", "detailedDesc": "GTAW is a precision welding process essential in aerospace, nuclear, and high-reliability industries where quality cannot be compromised. This AWS credential demonstrates advanced technical skill and attention to detail, opening doors to specialized, higher-wage positions. The certification test evaluates consistency, aesthetic quality, and penetration in demanding materials like stainless steel and aluminum. Programs offering GTAW should pair it with GMAW training to create comprehensive welding pathways."}, {"name": "AWS Certified Welding - SAW", "code": "IRC-1039", "cluster": "Construction", "link": "https://www.aws.org/certification-and-education/program-price-list/", "issuer": "American Welding Society (AWS)", "cost": "The  exam costs $100, while Associate-level exams are $150 each", "accommodations": "https://aws-p-001-delivery.sitecorecontenthub.cloud/api/public/content/Certification-Examination-ADA", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies competency in submerged arc welding (SAW), a high-productivity process for heavy fabrication.", "careerPaths": "Structural Welder, Pipe Welder, Fabrication Specialist, Production Supervisor, Quality Control Inspector, Field Technician", "goodFitFor": "Heavy construction or shipbuilding career programs; Apprenticeship preparation programs; Workforce development programs in industrial manufacturing regions", "detailedDesc": "SAW is a specialized welding process used primarily in structural steel and heavy fabrication where high deposition rates and deep penetration are critical. This AWS credential qualifies youth for positions in bridge building, offshore structures, and heavy equipment manufacturing\u2014fields known for strong wages and stable employment. The certification test is rigorous, requiring expertise in setup, travel technique, and quality control. Programs typically partner with community colleges or specialized training centers."}, {"name": "AWS Certified Welding - GMAW-S", "code": "IRC-1040", "cluster": "Construction", "link": "https://www.aws.org/certification-and-education/program-price-list/", "issuer": "American Welding Society (AWS)", "cost": "The  exam costs $100, while Associate-level exams are $150 each", "accommodations": "https://aws-p-001-delivery.sitecorecontenthub.cloud/api/public/content/Certification-Examination-ADA", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates competency in short-circuit gas metal arc welding (GMAW-S), used for thin materials and out-of-position work.", "careerPaths": "Welder, Fabrication Technician, Pipe Welder, Manufacturing Technician, Structural Welder, Quality Control Technician", "goodFitFor": "Welding programs emphasizing versatility; Advanced manufacturing career pathways; Apprenticeship preparation with multiple process options", "detailedDesc": "GMAW-S is particularly valued for its ability to weld thin materials and maintain position control in difficult-to-reach areas, making it essential in automotive, aerospace, and precision manufacturing. This AWS credential demonstrates mastery of a specialized technique that employers actively seek. The certification test evaluates control in positions that challenge welders and require finesse. Including GMAW-S alongside other GMAW variants creates a well-rounded welder prepared for diverse job opportunities."}, {"name": "AWS Certified Welding - SMAW", "code": "IRC-1041", "cluster": "Construction", "link": "https://www.aws.org/certification-and-education/program-price-list/", "issuer": "American Welding Society (AWS)", "cost": "The  exam costs $100, while Associate-level exams are $150 each", "accommodations": "https://aws-p-001-delivery.sitecorecontenthub.cloud/api/public/content/Certification-Examination-ADA", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies competency in shielded metal arc welding (SMAW), a foundational process widely used in construction and fabrication.", "careerPaths": "Welder, Structural Welder, Pipe Welder, Certified Welding Technician, Maintenance Technician, Field Welder", "goodFitFor": "Construction career pathways; Apprenticeship preparation programs; Workforce development programs serving youth interested in skilled trades", "detailedDesc": "SMAW is one of the oldest and still most versatile welding processes, valued for its simplicity, portability, and effectiveness in field conditions. This AWS credential is an excellent starting point for youth new to welding and leads naturally to more specialized process certifications. The certification test evaluates basic technique fundamentals including arc length control, travel speed, and bead quality. Programs can deliver SMAW training with relatively accessible equipment and then progress to more advanced processes."}, {"name": "AWS-CP (Amazon Web Services Cloud Practitioner)", "code": "IRC-1042", "cluster": "Digital Technology", "link": "https://aws.amazon.com/certification/certified-cloud-practitioner/", "issuer": "Amazon Web Services", "cost": "The cost is $100", "accommodations": "https://aws.amazon.com/certification/policies/before-testing/", "effDate": "July 1, 2025", "hours": "25\u201340 hours of total study time for individuals with some IT background, often completed within 1\u20132 months of part-time study. For beginners, it may take 3\u20136 months, while accelerated, dedicated study can take 1-2 weeks.", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Amazon's foundational cloud certification validating broad knowledge of AWS cloud services, infrastructure, pricing, and security.", "careerPaths": "Cloud Support Specialist, IT Support Analyst, Cloud Administrator (entry), Solutions Architect (entry), DevOps Engineer (entry)", "goodFitFor": "Technology pathway programs serving older high school youth; programs partnered with AWS or tech employers; OST programs with IT or cloud computing tracks; summer tech intensives", "detailedDesc": "The AWS Certified Cloud Practitioner (CLF-C02) is Amazon Web Services' entry-level cloud certification, validating broad understanding of the AWS platform, cloud concepts, pricing models, security basics, and architectural best practices. It requires approximately 20\u201340 hours of preparation and is widely recognized across industries as cloud infrastructure becomes foundational to nearly every sector. This credential is particularly strong for youth in programs with technology employer partnerships, as AWS is the world's leading cloud provider. It complements other IT credentials and positions students well for cloud-focused careers."}, {"name": "AWS-SA (Amazon Web Services Solutions Architect Associate)", "code": "IRC-1043", "cluster": "Digital Technology", "link": "https://aws.amazon.com/certification/certified-solutions-architect-associate/", "issuer": "Amazon Web Services", "cost": "The cost is $150", "accommodations": "https://aws.amazon.com/certification/policies/before-testing/", "effDate": "July 1, 2025", "hours": "3 to 6 months of study for most professionals, or roughly 80-120 hours of dedicated training. While intensive, full-time study can allow preparation in under 6 weeks", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates competency in designing and deploying cloud infrastructure solutions on Amazon Web Services platforms.", "careerPaths": "Solutions Architect, Cloud Engineer, DevOps Engineer, Systems Administrator, Cloud Infrastructure Specialist, IT Consultant", "goodFitFor": "STEM programs with cloud computing focus; Technology career pathways for older youth; Workforce development programs in tech-forward regions", "detailedDesc": "AWS Solutions Architect Associate is an industry-leading cloud certification that validates expertise in designing scalable, reliable, and cost-effective cloud solutions. Amazon Web Services offers this credential to professionals demonstrating hands-on experience with AWS services and architectural best practices. Youth earning this credential gain access to high-wage cloud technology careers as organizations increasingly rely on cloud infrastructure. Programs should include hands-on labs using AWS free tier resources and connect youth to AWS-authorized training partners."}, {"name": "Barber License", "code": "IRC-1044", "cluster": "Healthcare & Human Services", "link": "https://labor.maryland.gov/license/barbers/barbersaff.shtml", "issuer": "Maryland Department of Labor", "cost": "The cost is $56", "accommodations": "https://www.labor.maryland.gov/license/barbers/barbersexam.shtml", "effDate": "July 1, 2025", "hours": "Barber license training in Maryland requires completing 1,200 hours at an approved school (typically 7.5 to 12 months)", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates competency to practice barbering including cutting, shaving, and hair care within Maryland licensing requirements.", "careerPaths": "Barber, Hair Stylist, Salon Owner, Image Consultant, Barber Shop Manager, Self-Employed Barber", "goodFitFor": "Cosmetology or personal care career programs; Entrepreneurship-focused youth programs; Community-based workforce development in personal services", "detailedDesc": "Maryland's Barber License, issued by the Department of Labor, certifies that practitioners meet state standards for barbering skills, safety, and hygiene. This is a regulated license required to legally practice barbering in Maryland, making it an essential credential for youth pursuing barber careers. Barbering offers strong earning potential, flexible scheduling, and entrepreneurship opportunities. Programs must partner with Maryland-licensed barbering schools and ensure compliance with apprenticeship hour requirements."}, {"name": "Barber Stylist License", "code": "IRC-1045", "cluster": "Healthcare & Human Services", "link": "https://labor.maryland.gov/license/barbers/barbersaff.shtml", "issuer": "Maryland Department of Labor", "cost": "The cost is $56", "accommodations": "https://www.ada.gov/resources/testing-accommodations/#who-is-eligible-to-receive-testing-accommodations", "effDate": "July 1, 2025", "hours": "Barber license training in Maryland requires completing 1,200 hours at an approved school (typically 7.5 to 12 months)", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates competency in barbering and beauty services including styling, cutting, and product knowledge required in Maryland.", "careerPaths": "Barber Stylist, Hair Stylist, Salon Professional, Barber Shop Owner, Beauty Consultant, Self-Employed Salon Provider", "goodFitFor": "Cosmetology and personal care career programs; Beauty and wellness-focused youth development; Entrepreneurship programs in beauty or personal services industries", "detailedDesc": "Maryland's Barber Stylist License, issued by the Department of Labor, certifies combined barbering and styling skills meeting state requirements. This credential is essential for legal practice and allows practitioners to offer a broader range of hair and grooming services. Barber stylists enjoy strong earning potential, flexible work arrangements, and opportunities to build private clienteles. Programs must use Maryland-licensed instructors and schools meeting state apprenticeship hour requirements."}, {"name": "BASF Plant Science", "code": "IRC-1046", "cluster": "Agriculture", "link": "https://agriculture.basf.us/community-relations/educational-resources/plant-science-certification.html", "issuer": "BASF (iCEV)", "cost": "The exam cost is $40", "accommodations": "https://www.icevonline.com/accommodations", "effDate": "July 1, 2025", "hours": "about one academic year to complete in partnered educational institutions", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies understanding of plant science, crop production, and sustainable agricultural practices.", "careerPaths": "Crop Consultant, Agronomist, Plant Science Technician, Agricultural Specialist", "goodFitFor": "Agriculture and crop science programs; Sustainability-focused pathways; Programs partnered with agricultural extension services", "detailedDesc": "BASF's Plant Science credential (through iCEV) validates knowledge of plant biology, soil science, and crop management. Youth learn practical agriculture science applicable to crop production and farm management. The credential connects to BASF and agricultural industry careers. Programs can emphasize modern agricultural chemistry and precision farming applications."}, {"name": "Biotechnician Assistant Credentialing Exam (BACE)", "code": "IRC-1047", "cluster": "Healthcare & Human Services", "link": "https://biotility.research.ufl.edu/bace/", "issuer": "Biotility", "cost": "The exam fee is $185", "accommodations": "https://biotility.research.ufl.edu/bace/faq/", "effDate": "July 1, 2025", "hours": "4-5 months of study, and the exam assesses knowledge typically gained in high school biotech programs, community college courses, or professional training", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies foundational biotechnology laboratory skills and competency in common biotech techniques.", "careerPaths": "Biotechnology Technician, Laboratory Technician, Quality Control Technician, Research Assistant, Biomanufacturing Technician, Pharmaceutical Technician", "goodFitFor": "STEM programs with life sciences or biotech focus; Healthcare-related career pathways; Workforce development programs in biotech hubs or pharmaceutical regions", "detailedDesc": "Biotility's Biotechnician Assistant Credentialing Exam (BACE) validates hands-on skills in laboratory techniques, safety, and quality assurance essential in biotech and pharmaceutical industries. This credential demonstrates practical laboratory competency and readiness for entry-level biotech positions in a rapidly growing field. Youth earning BACE gain access to well-paying technical careers in high-demand sectors. Programs should partner with biotech companies, pharmaceutical employers, or community colleges with life sciences labs."}, {"name": "CCNA (200-301 Implementing and Administering Cisco Solutions)", "code": "IRC-1048", "cluster": "Digital Technology", "link": "https://certiport.pearsonvue.com/Certifications/Cisco/Certified-Support-Technician/Overview.aspx", "issuer": "Cisco (Certiport)", "cost": "The cost is $150", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Cisco's professional-level networking certification validating ability to implement, manage, and troubleshoot enterprise networking solutions.", "careerPaths": "Network Administrator, Systems Engineer, Network Engineer, IT Infrastructure Specialist, Cloud Networking Engineer", "goodFitFor": "Advanced technology programs for older youth (17\u201321) with prior networking experience; programs with IT career tracks at the advanced level; programs partnered with telecommunications, enterprise IT, or managed services employers; youth apprenticeship programs in IT", "detailedDesc": "The Cisco Certified Network Associate (CCNA) is one of the most respected and widely recognized certifications in enterprise networking, validating ability to configure, manage, and troubleshoot Cisco-based network infrastructure including routing, switching, security, and network automation. Preparation typically requires 150\u2013300 hours of study and hands-on lab practice. The CCNA is best suited for older youth in advanced IT programs who have completed foundational networking credentials (CCST Networking, CompTIA Network+). It positions youth for well-paying network engineering roles and serves as a gateway to Cisco's professional-level certifications."}, {"name": "CCST Cybersecurity", "code": "IRC-1049", "cluster": "Digital Technology", "link": "https://www.cisco.com/site/us/en/learn/training-certifications/exams/ccst-cybersecurity.html", "issuer": "Cisco (Certiport)", "cost": "The cost is $125", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "120 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Entry-level Cisco credential validating foundational knowledge of cybersecurity threats, defenses, and network security practices.", "careerPaths": "Cybersecurity Analyst (entry), IT Security Technician, Help Desk Specialist, Security Operations Center Analyst (entry), Network Security Technician", "goodFitFor": "STEM and technology afterschool programs; programs with cybersecurity or IT career tracks; programs partnered with government, defense, or tech employers; summer cybersecurity bootcamps", "detailedDesc": "The CCST Cybersecurity credential from Cisco (via Certiport) validates a student's foundational understanding of cybersecurity concepts including threat detection, network security, and defensive practices. Preparation requires approximately 120 hours, making it suitable for semester-long or multi-month program formats. It serves as an excellent entry point into the rapidly growing cybersecurity field, which consistently ranks among the highest-demand career areas. This credential pairs well with CompTIA Security+ for youth building a cybersecurity career pathway."}, {"name": "CCST IT Support", "code": "IRC-1050", "cluster": "Digital Technology", "link": "https://www.cisco.com/site/us/en/learn/training-certifications/exams/ccst-it-support.html", "issuer": "Cisco (Certiport)", "cost": "The cost is $125", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "30\u201332 hours of study", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": "Pass IT On", "oneLiner": "Entry-level Cisco credential validating skills in diagnosing, troubleshooting, and supporting IT systems and end-user devices.", "careerPaths": "IT Help Desk Technician, Technical Support Specialist, Desktop Support Analyst, Systems Support Technician", "goodFitFor": "Technology-focused afterschool programs; programs offering IT career pathways; summer tech bootcamps; programs partnered with IT staffing firms or managed service providers", "detailedDesc": "The CCST IT Support credential from Cisco (delivered via Certiport) validates a student's ability to support and troubleshoot hardware, software, networks, and operating systems at an entry level. It requires approximately 30\u201332 hours of preparation, making it one of the more accessible credentials for shorter program cycles. This certification is a recognized starting point for careers in IT support and customer-facing technical roles. It pairs well with CompTIA A+ for youth building a strong IT foundation."}, {"name": "CCST Networking", "code": "IRC-1051", "cluster": "Digital Technology", "link": "https://www.cisco.com/site/us/en/learn/training-certifications/exams/ccst-networking.html", "issuer": "Cisco (Certiport)", "cost": "The cost is $125", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "70 hours of study time", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "Yes", "cclExpert": "Pass IT On", "oneLiner": "Cisco-issued entry-level credential that validates foundational knowledge of computer networking concepts and infrastructure.", "careerPaths": "Network Support Technician, Help Desk Specialist, IT Technician, Network Administrator (entry), Systems Support Analyst", "goodFitFor": "STEM-focused afterschool programs; technology pathway programs for high school youth; programs partnered with community colleges or IT employers; summer tech intensives", "detailedDesc": "The Cisco Certified Support Technician (CCST) Networking credential is an entry-level certification from Cisco, delivered through Certiport, designed to validate foundational networking skills including network components, IP addressing, and troubleshooting basics. It is widely recognized by employers in IT support and network administration. Preparation typically requires approximately 70 hours of study, making it appropriate for extended afterschool or summer programs. The CCST Networking serves as a strong stepping stone toward the more advanced CCNA certification."}, {"name": "Certified Additive Manufacturing Fundamentals", "code": "IRC-1052", "cluster": "Advanced Manufacturing", "link": "https://www.sme.org/training/additive-manufacturing-certification/additive-manufacturing-certification-process/", "issuer": "Society of Manufacturing Engineers", "cost": "The cost can go up to $279 or more.", "accommodations": "https://www.sme.org/training/additive-manufacturing-certification/", "effDate": "July 1, 2025", "hours": "3 months to complete", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies foundational knowledge of additive manufacturing technologies, processes, and applications.", "careerPaths": "Additive Manufacturing Technician, 3D Printing Specialist, Manufacturing Engineer, Design Technician", "goodFitFor": "Advanced manufacturing programs; STEM programs with maker or fabrication focus; Programs exploring emerging manufacturing technologies", "detailedDesc": "This SME credential validates understanding of 3D printing technologies, materials, design considerations, and quality assurance in additive manufacturing. Youth learn emerging skills applicable across industries from aerospace to healthcare. The credential demonstrates readiness for advanced manufacturing roles in the growing 3D printing sector. Programs can incorporate hands-on 3D printing lab experiences."}, {"name": "Certified Associate Webmaster (CAW)", "code": "IRC-1053", "cluster": "Arts, Entertainment & Design", "link": "https://webprofessionals.org/certification", "issuer": "WOW", "cost": "The cost is $95", "accommodations": "https://www.ada.gov/resources/testing-accommodations/", "effDate": "July 1, 2025", "hours": "100 to 140 hours of course time for Level 1 certification, often taken over 2-3 semesters in college programs. Accelerated, non-credit, or self-paced training options can range from 1 to 4 weeks.", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Entry-level credential validating knowledge of website management, web technologies, and the business of maintaining professional web presence.", "careerPaths": "Web Content Manager, Webmaster, Digital Marketing Coordinator, Web Designer (entry), E-Commerce Specialist", "goodFitFor": "Technology or digital media afterschool programs; programs with web management or digital communications tracks; programs serving youth interested in running websites or digital content; programs partnered with small businesses or nonprofits needing web support", "detailedDesc": "The Certified Associate Webmaster (CAW), issued by the World Organization of Webmasters (WOW), validates entry-level knowledge of web management including site architecture, content management, web standards, and basic search engine optimization (SEO). It is designed for students entering roles that involve maintaining and managing websites for organizations. This credential is a strong fit for programs introducing youth to digital communications and web management, and it provides practical skills that are immediately applicable to freelance work, nonprofit support, or entry-level digital roles."}, {"name": "Certified Clinical Medical Assistant (CCMA)", "code": "IRC-1054", "cluster": "Healthcare & Human Services", "link": "https://www.nhanow.com/?utm_medium=cpc&utm_term=national%20healthcareer%20association%20nha&utm_source=google&utm_campaign=gs_br_mixed_certifications&utm_content=mixed_brand-pr-search&hsa_kw=national%20healthcareer%20association%20nha&hsa_acc=4754401107&hsa_ad=680953840234&hsa_net=adwords&hsa_src=g&hsa_tgt=kwd-2253119419653&hsa_grp=148129285605&hsa_mt=p&hsa_cam=20224135184&hsa_ver=3&gad_source=1&gad_campaignid=20224135184&gbraid=0AAAAAC2kImfyrH6ck0gU-Fw9Zor_MEF62&gclid=CjwKCAjwwqfABhBcEiwAZJjC3pVOYTsinCIX0QMSRj4d0NtzWUwV2zhReYNve7NNDfc-R6rCeJmrRhoCtscQAvD_BwE", "issuer": "National Healthcareer Association", "cost": "The exam fee is $165", "accommodations": "https://healthscienceconsulting.com/wp-content/uploads/2016/10/nha-accommodation-form.pdf", "effDate": "July 1, 2025", "hours": "2 to 12 months to complete, with many accelerated, comprehensive, and online options available in 3 to 6 months", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates competency to function as a clinical medical assistant including patient care, clinical procedures, and administrative tasks.", "careerPaths": "Clinical Medical Assistant, Medical Assistant, Healthcare Technician, Phlebotomist, Patient Care Technician, Medical Clinic Assistant", "goodFitFor": "Healthcare career pipelines; Medical and clinical training programs; Community health programs preparing youth for healthcare careers", "detailedDesc": "The National Healthcareer Association's CCMA credential certifies that medical assistants can safely perform clinical and administrative healthcare tasks under practitioner supervision. This credential is highly sought by healthcare employers and demonstrates professional standards. Youth with CCMA certification access immediate employment in doctors' offices, clinics, and hospitals with competitive wages and job stability. Programs should partner with healthcare facilities for clinical experience and use curricula aligned with NHA standards."}, {"name": "Certified Dental Assistant (DANB)", "code": "IRC-1055", "cluster": "Healthcare & Human Services", "link": "https://www.danb.org/exams/exam/cda-exam", "issuer": "Dental Assisting National Board, Inc.", "cost": null, "accommodations": "https://www.danb.org/exams/exam/cda-exam", "effDate": "July 1, 2025", "hours": "9 to 12 months for accredited programs, though some accelerated, specialized, or on-the-job training pathways can range from 3 months to over a year", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies competency to assist dentists and hygienists including infection control, patient assistance, and office procedures.", "careerPaths": "Dental Assistant, Dental Administrative Assistant, Dental Technician, Chairside Assistant, Office Manager, Sterilization Technician", "goodFitFor": "Healthcare and dental career programs; Medical assistant pathways; Community health programs with dental focus; Workforce development through dental clinics", "detailedDesc": "The Dental Assisting National Board's certification validates competency in chairside assisting, infection control, radiography basics, and dental office operations. This credential is recognized across dental practices and demonstrates professional dental assisting standards. Youth with DANB certification are job-ready for immediate dental practice employment with strong earning potential and career advancement opportunities. Programs should partner with dental practices and community health centers for hands-on clinical experience and arrange DANB exam registration."}, {"name": "Certified Dental Assistant (MSBDE)", "code": "IRC-1056", "cluster": "Healthcare & Human Services", "link": "https://health.maryland.gov/dental/Pages/home.aspx", "issuer": "Maryland State Board of Dental Examiners", "cost": null, "accommodations": "https://danbsfprodassets.azureedge.net/assets/docs/default-source/state-application-packets/mdg_mdo.pdf?sfvrsn=3e155b14_9#:~:text=Canceling%20or%20Rescheduling%20an%20Exam,not%20been%20canceled%20or%20rescheduled.", "effDate": "July 1, 2025", "hours": "9 to 12 months for certificate programs, with accelerated options as fast as 10 weeks", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies readiness to assist dentists and support patient care in clinical dental settings.", "careerPaths": "Dental Assistant, Dental Hygiene Assistant, Chairside Assistant, Sterilization Technician, Administrative Dental Assistant", "goodFitFor": "Health sciences and medical career pathways; Programs partnering with dental offices or community health centers; Youth ages 16+ with interest in healthcare", "detailedDesc": "This credential validates competency in patient care, instrument handling, sterilization, and administrative tasks in dental practice. Issued by the Maryland State Board of Dental Examiners, it requires supervised clinical experience and passing an exam. Youth gain entry-level access to well-paying dental assistant positions with pathways to dental hygiene or dentistry. Programs should connect with local dental offices for clinical placements."}, {"name": "Certified Floral Designer", "code": "IRC-1057", "cluster": "Agriculture", "link": "https://aifd.org/membership/becoming-a-cfd/", "issuer": "American Institute of Floral Designers (AIFD)", "cost": "The cost will varies for high school students.", "accommodations": "https://aifd.org/membership/becoming-a-cfd/", "effDate": "July 1, 2025", "hours": "56 to 240 hours of training, usually completed within 3 to 12 months", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies expertise in floral design, arrangement techniques, and professional floral industry standards.", "careerPaths": "Floral Designer, Floral Shop Manager, Event Florist, Floral Entrepreneur", "goodFitFor": "Agriculture and horticulture programs; Small business and entrepreneurship pathways; Creative and design-focused programs", "detailedDesc": "The American Institute of Floral Designers' credential validates professional floral design skills, arrangement techniques, and industry standards. Youth demonstrate artistic and technical competency in floral design. The credential opens pathways to floral retail, event design, and floral business ownership. Programs can emphasize the creative and entrepreneurial aspects of floral design careers."}, {"name": "Certified Fundamentals Cook (CFC)", "code": "IRC-1058", "cluster": "Hospitality, Events, and Tourism", "link": "https://www.acfchefs.org/ACF/Certify/Levels/Savory/CFC/ACF/Certify/Levels/CFC/default.aspx?section=certify&hkey=86de8c61-9d7d-4cbf-af4a-e4cb43a2fda6", "issuer": "American Culinary Federation (ACF)", "cost": "ACF members - $75 & Non-Members $95", "accommodations": "https://www.acfchefs.org/Downloads/Certification/Request-for-Special-Accommodations.pdf", "effDate": "July 1, 2025", "hours": "1,000 hours of on-the-job training and 90 hours of related instruction. Some programs offer a shorter, 6-month, or accelerated pathway to prepare for the certification exam", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies foundational culinary skills and food safety knowledge in professional kitchen environments.", "careerPaths": "Line Cook, Prep Cook, Short Order Cook, Kitchen Assistant, Restaurant Cook", "goodFitFor": "Culinary and food service career pathways; Hospitality and restaurant management programs; Community-based cooking and entrepreneurship programs", "detailedDesc": "This credential, issued by the American Culinary Federation (ACF), validates basic knife skills, cooking techniques, food safety, and kitchen operations knowledge. It's designed for entry-level cooks transitioning from home cooking to professional kitchens. Certified cooks earn more than non-certified peers and have clear pathways to head cook, sous chef, or executive chef roles. Programs should use working kitchens, restaurant partnerships, and hands-on practice to build competency."}, {"name": "Certified Fundamentals Pastry Cook (CFPC)", "code": "IRC-1059", "cluster": "Hospitality, Events, and Tourism", "link": "https://www.acfchefs.org/ACF/Certify/Levels/Pastry/CFPC/ACF/Certify/Levels/CFPC/default.aspx?section=certify&hkey=b1aa12e8-dc21-40d4-ab14-b4cd4cedf879", "issuer": "American Culinary Federation (ACF)", "cost": "Members $35 & Non-Members $50", "accommodations": "https://www.acfchefs.org/Downloads/Certification/Request-for-Special-Accommodations.pdf", "effDate": "July 1, 2025", "hours": "464 hours of related instruction or a 12-week to 5-month intensive training program", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies fundamental baking and pastry production skills for professional bakery and kitchen environments.", "careerPaths": "Pastry Cook, Baker, Pastry Chef Assistant, Bakery Technician, Pastry Production Specialist", "goodFitFor": "Culinary arts and pastry career pathways; Hospitality and food service programs; Entrepreneurship pathways for baking businesses", "detailedDesc": "This credential, issued by the American Culinary Federation (ACF), tests mastery of baking fundamentals, pastry techniques, ingredient knowledge, and food safety. Pastry specialists are in high demand at hotels, bakeries, restaurants, and catering companies, often earning premium wages. Youth can pursue this as a standalone career or combination with savory cooking. Programs should partner with bakeries, pastry shops, and fine dining establishments for authentic training environments."}, {"name": "Certified Logistics Associate", "code": "IRC-1060", "cluster": "Advanced Manufacturing", "link": "https://www.msscusa.org/certified-logistics-associate-cla-key-activities/", "issuer": "Manufacturing Skill Standards Council (MSSC)", "cost": "$25", "accommodations": "https://www.msscusa.org/wp-content/uploads/2022/10/CLT-4.0-Candidate-Handbook-v-15-Online.pdf", "effDate": "July 1, 2025", "hours": "35 to 40 hours of instruction. The training can be completed in a few weeks through flexible, self-paced online modules or accelerated, in-person classroom sessions", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Foundational MSSC credential validating knowledge of workplace safety, quality, production, and basic logistics concepts for entry-level manufacturing roles.", "careerPaths": "Warehouse Associate, Logistics Technician, Production Worker, Supply Chain Assistant, Material Handler", "goodFitFor": "Workforce development programs focused on manufacturing and logistics; programs serving youth 14\u201321 interested in immediate employment opportunities; programs near industrial employers; pre-employment training programs", "detailedDesc": "The Certified Logistics Associate (CLA), issued by the Manufacturing Skill Standards Council (MSSC), is the entry-level credential in MSSC's logistics pathway, preceding the Certified Logistics Technician (CLT). It validates foundational knowledge of workplace safety, quality concepts, manufacturing processes, and logistics operations. The CLA is designed to be accessible for younger youth or those new to manufacturing concepts, with preparation achievable in as few as 8\u201316 hours. It is an excellent first credential for programs introducing youth to supply chain and industrial careers."}, {"name": "Certified Logistics Technician", "code": "IRC-1061", "cluster": "Advanced Manufacturing", "link": "https://www.msscusa.org/certification/", "issuer": "Manufacturing Skill Standards Council (MSSC)", "cost": "$25", "accommodations": "https://www.msscusa.org/wp-content/uploads/2022/10/CLT-4.0-Candidate-Handbook-v-15-Online.pdf", "effDate": "July 1, 2025", "hours": "35 to 80 hours of training, usually completed within 4 to 14 weeks", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Entry-level manufacturing and logistics credential that validates knowledge of safety, quality, production, and supply chain processes.", "careerPaths": "Logistics Technician, Warehouse Associate, Supply Chain Coordinator, Distribution Center Operator, Production Planner", "goodFitFor": "Workforce development programs partnered with manufacturing or logistics employers; programs near industrial or distribution hubs serving youth 16+; career pathway programs focused on trades and technical careers", "detailedDesc": "The Certified Logistics Technician (CLT), issued by the Manufacturing Skill Standards Council (MSSC), is a nationally recognized entry-level credential for the manufacturing and logistics fields. It covers workplace safety, quality systems, manufacturing processes, and maintenance fundamentals. Earning the CLT signals to employers that a young person is ready for real-world work in warehousing, distribution, and production settings. Preparation typically requires 35\u201380 hours of instruction, making it achievable within a semester-length program."}, {"name": "Certified Manufacturing Associate", "code": "IRC-1062", "cluster": "Advanced Manufacturing", "link": "https://www.sme.org/training/technical-certification/certified-manufacturing-associate/", "issuer": "Society of Manufacturing Engineers", "cost": "The cost is around $795 to $895, including training and the exam.", "accommodations": "https://www.sme.org/training/technical-certification/certified-manufacturing-associate/", "effDate": "July 1, 2025", "hours": "35 hours of coursework to complete", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Foundational manufacturing credential from the Society of Manufacturing Engineers validating broad knowledge of manufacturing processes, safety, and quality.", "careerPaths": "Manufacturing Technician, Production Associate, Quality Control Inspector, Process Improvement Technician, Industrial Technician", "goodFitFor": "Programs with manufacturing or STEM career tracks; workforce development programs serving youth 16+ interested in industrial careers; programs partnered with manufacturing employers; OST programs in industrial communities", "detailedDesc": "The Certified Manufacturing Associate (CMfgA), issued by the Society of Manufacturing Engineers (SME), is a foundational credential that validates broad knowledge of manufacturing processes, materials, safety practices, and quality management. It is designed for students and early-career professionals entering the manufacturing workforce and is recognized by employers across sectors including automotive, aerospace, medical devices, and consumer products. Preparation typically takes 40\u201360 hours. This credential is an excellent choice for programs introducing youth to advanced manufacturing careers, especially when paired with hands-on shop or lab experiences."}, {"name": "Certified Manufacturing Technologist", "code": "IRC-1063", "cluster": "Advanced Manufacturing", "link": "https://www.sme.org/certification/", "issuer": "Society of Manufacturing Engineers", "cost": "The cost for online exam is $245, while non-members pay $490", "accommodations": "https://www.sme.org/training/technical-certification/certified-manufacturing-associate/", "effDate": "July 1, 2025", "hours": "165 hours of training, often completed within 6 months through online self-paced programs. The certification itself requires 4 years of combined manufacturing-related experience and/or education, making it an entry-to-mid-level credential", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies comprehensive knowledge of manufacturing processes, materials, and quality control practices.", "careerPaths": "Manufacturing Technologist, Process Engineer, Quality Control Specialist, Production Supervisor", "goodFitFor": "Advanced manufacturing career pathways; Manufacturing employer partnerships; Workforce development programs in industrial communities", "detailedDesc": "The Society of Manufacturing Engineers' Certified Manufacturing Technologist credential validates broad technical knowledge essential for manufacturing supervisory and technical roles. Youth demonstrate competency in process optimization, quality assurance, and equipment operation. This credential signals advanced manufacturing readiness and career progression potential. Programs should emphasize the credential's connection to supervisory and higher-wage manufacturing positions."}, {"name": "Certified Medical Administrative Assistant (CMAA)", "code": "IRC-1064", "cluster": "Healthcare & Human Services", "link": "https://www.nhanow.com/certification/nha-certifications/certified-clinical-medical-assistant-(ccma)", "issuer": "National Trade Institute", "cost": "The cost ranges from $117  to  $200", "accommodations": "https://www.naham.org/page/TestingAccommodations", "effDate": "July 1, 2025", "hours": "between 3 and 10 months to complete", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates skills in managing medical office operations, scheduling, and patient communication.", "careerPaths": "Medical Administrative Assistant, Front Office Specialist, Patient Scheduler, Medical Records Clerk, Billing Clerk", "goodFitFor": "Healthcare career exploration programs; Administrative career pathways; Programs in partnership with medical practices or clinics", "detailedDesc": "This credential tests knowledge of medical office procedures, insurance billing basics, patient privacy (HIPAA), and customer service. Issued by National Trade Institute, it prepares youth for the operational side of healthcare without requiring clinical certifications. The role is growing as healthcare practices expand, making this a strong entry point. Programs can integrate online learning with volunteer placements in medical offices."}, {"name": "Certified Nursing Assistant (CNA)", "code": "IRC-1065", "cluster": "Healthcare & Human Services", "link": "https://health.maryland.gov/mbon/pages/default.aspx", "issuer": "Maryland Board of Nursing", "cost": "The cost is $20", "accommodations": "https://www.nursingworld.org/certification/certification-policies/special-accommodations/#:~:text=The%20American%20Nurses%20Credentialing%20Center,See%20Important%20Notice%2C%20below.", "effDate": "July 1, 2025", "hours": "between 4 and 12 weeks to complete, with many programs lasting approximately 6 to 8 weeks", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies competency in providing personal care and support to patients under nursing supervision.", "careerPaths": "Certified Nursing Assistant, Patient Care Assistant, Nursing Assistant, Home Health Aide, Hospital Care Assistant", "goodFitFor": "Health sciences and nursing pathways; Long-term care and community health programs; Programs with healthcare facility partnerships", "detailedDesc": "This widely-recognized credential validates hands-on patient care skills including hygiene, vital signs, and patient comfort. Issued by the Maryland Board of Nursing, it requires classroom training and clinical skills testing. CNA is often the entry point to nursing careers and offers strong employment prospects in hospitals and care facilities. Programs should provide supervised clinical practice in real healthcare settings."}, {"name": "Certified Onshape Professional", "code": "IRC-1066", "cluster": "Advanced Manufacturing", "link": "https://learn.onshape.com/courses/certified-onshape-professional", "issuer": "Onshape", "cost": "The exam costs $100 per attempt.", "accommodations": "https://learn.onshape.com/courses/certified-onshape-professional", "effDate": "July 1, 2025", "hours": "100 hours of practical experience, designed for advanced users who should have significantly more experience than the 35-50 hours recommended for the Associate-level exam", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": "OpenWorks", "oneLiner": "Certifies proficiency using Onshape cloud-based CAD software for product design and engineering.", "careerPaths": "CAD Designer, Product Designer, Engineering Technician, Manufacturing Designer", "goodFitFor": "Advanced manufacturing and design programs; STEM and engineering pathways; Programs utilizing cloud-based design tools", "detailedDesc": "Onshape's cloud-based CAD platform offers certification for youth skilled in modern product design and documentation. The credential validates ability to create professional 3D models and technical drawings essential for manufacturing and engineering roles. Onshape's accessibility and cloud-first approach make it ideal for OST settings without expensive software licensing. Programs can emphasize the modern, employer-valued skill set."}, {"name": "Certified Personal Trainer", "code": "IRC-1067", "cluster": "Healthcare & Human Services", "link": "https://nspainc.com", "issuer": "National Strength Professionals Association (NSPA)", "cost": "The cost ranges from $395 to $595", "accommodations": "https://fit-pro.com/article-292-Special-Accommodations-Available-for-Candidates-with-Disabilities.html#:~:text=9%202007-,Special%20Accommodations%20Available%", "effDate": "July 1, 2025", "hours": "3 to 6 months to complete for most, with options ranging from accelerated, one-month programs to self-paced, six-month timelines", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates foundational knowledge of exercise science, fitness programming, and client instruction to work as a personal trainer.", "careerPaths": "Personal Trainer, Fitness Instructor, Health Coach, Recreation Program Leader, Wellness Coordinator", "goodFitFor": "Programs focused on health and wellness careers; recreation-based OST programs; programs serving youth interested in sports, fitness, or health science; programs in communities with fitness or recreation employers", "detailedDesc": "The Certified Personal Trainer credential from the National Strength Professionals Association (NSPA) demonstrates a student's ability to design and deliver fitness programs, assess client needs, and apply exercise science principles safely and effectively. Preparation typically takes 3\u20136 months, though accelerated one-month options are available. This credential opens doors to entry-level employment in gyms, recreation centers, schools, and community health programs. It is a natural fit for OST programs with a health and wellness or sports-focused curriculum."}, {"name": "Certified Pharmacy Technician (CPhT)", "code": "IRC-1068", "cluster": "Healthcare & Human Services", "link": "https://www.ptcb.org/credentials/certified-pharmacy-technician", "issuer": "Pharmacy Technician Certification Board", "cost": "The fee is $45 for MD", "accommodations": "https://ptcb.zendesk.com/hc/en-us/articles/360042628112-Testing-with-Accommodations#:~:text=PTCB%20offers%20testing%20accommodations%20for,%2C%20additional%20breaks%2C%20and%20more.&text=Some%20accommodations%20are%20available%20for,Waiver%20of%20automation%20tools", "effDate": "July 1, 2025", "hours": "between 3 months and 1 year to complete through formal programs, while accelerated or on-the-job training can take as little as 6\u201315 weeks", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates knowledge of pharmacy operations, medication management, and patient safety protocols.", "careerPaths": "Pharmacy Technician, Medication Technician, Pharmacy Clerk, Pharmacy Support Specialist, Retail Pharmacy Assistant", "goodFitFor": "Healthcare and pharmaceutical career pathways; STEM-focused youth programs; Programs with pharmacy partnerships", "detailedDesc": "This credential demonstrates competency in pharmaceutical calculations, inventory management, federal regulations, and customer service. Issued by the Pharmacy Technician Certification Board (PTCB), it is nationally recognized and highly valued by employers. Youth gain access to stable pharmacy careers in hospitals, retail, and specialty practices with potential advancement to pharmacy administration. Programs should partner with pharmacies for internship opportunities."}, {"name": "Certified Pharmacy Technician (ExCPT)", "code": "IRC-1069", "cluster": "Healthcare & Human Services", "link": "https://www.pharmtechs.org/pharmacy-technician-certification/#:~:text=What%20is%20certification?,two%20years%20to%20maintain%20certification.", "issuer": "National Healthcareer Association", "cost": "The fee is $129", "accommodations": "https://healthscienceconsulting.com/wp-content/uploads/2016/10/nha-accommodation-form.pdf", "effDate": "July 1, 2025", "hours": "between 3 to 9 months to complete, with many accelerated programs finishing in about 4 months (15-16 weeks)", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates pharmacy technician knowledge through an alternative national certification pathway.", "careerPaths": "Pharmacy Technician, Medication Technician, Pharmacy Support Specialist, Retail Pharmacy Assistant, Hospital Pharmacy Technician", "goodFitFor": "Healthcare and pharmaceutical career pathways; Alternative certification programs; National credential pathway programs", "detailedDesc": "This credential, offered by the National Healthcareer Association (ExCPT), provides an alternative to PTCB certification while testing the same pharmacy competencies. Issued through computerized testing, it is recognized across states and offers flexibility in timing. Youth can pursue this credential while working or attending school, making it accessible for working youth. Programs can use ExCPT to reach youth seeking faster certification timelines."}, {"name": "Certified Production Technician 4.0", "code": "IRC-1070", "cluster": "Advanced Manufacturing", "link": "https://www.msscusa.org/certification/production-certification-cpt/", "issuer": "Manufacturing Skill Standards Council (MSSC)", "cost": "The cost ranges from $160 to $200", "accommodations": "https://www.msscusa.org/wp-content/uploads/2022/10/CLT-4.0-Candidate-Handbook-v-15-Online.pdf", "effDate": "July 1, 2025", "hours": "90 to 160 hours of instruction, usually completed over 8 to 12 weeks, though some programs allow up to 6 months", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies core competencies in production and manufacturing operations aligned with industry standards.", "careerPaths": "Production Technician, Manufacturing Operator, Quality Assurance Technician, Production Supervisor", "goodFitFor": "Advanced manufacturing programs; Manufacturing employer partnerships; Workforce development programs serving manufacturing communities", "detailedDesc": "MSSC's Certified Production Technician 4.0 validates essential competencies in safety, quality, production systems, and maintenance. The credential is widely recognized by manufacturers seeking entry-level production workers. Youth demonstrate readiness for immediate employment in manufacturing environments. Programs benefit from MSSC's structured curriculum and alignment with manufacturing best practices."}, {"name": "Certified Production Technician CPT+ Skill Boss", "code": "IRC-1071", "cluster": "Advanced Manufacturing", "link": "https://www.msscusa.org/cpt-skill-boss/", "issuer": "Manufacturing Skill Standards Council (MSSC)", "cost": "The initial cost if $300", "accommodations": "https://www.msscusa.org/wp-content/uploads/2022/10/CLT-4.0-Candidate-Handbook-v-15-Online.pdf", "effDate": "July 1, 2025", "hours": "90 to 160+ total hours, with completion generally taking three to six months", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies production technician competencies with advanced digital and automation skills using Skill Boss platform.", "careerPaths": "Production Technician, Manufacturing Operator, Maintenance Technician, Automation Specialist", "goodFitFor": "Advanced manufacturing programs emphasizing automation; Programs utilizing digital learning platforms; Manufacturing modernization initiatives", "detailedDesc": "MSSC's CPT+ Skill Boss integrates traditional production technician competencies with digital skills and automation knowledge. The platform-based delivery engages youth in modern learning while building skills for 21st-century manufacturing. The credential signals readiness for tech-forward manufacturing roles and competitive wage positions. Programs value the interactive Skill Boss platform and progressive skill building."}, {"name": "Certified Professional Horticulturist (CPH)", "code": "IRC-1072", "cluster": "Agriculture", "link": "https://mnlga.org/page/CPH", "issuer": "Maryland Nursery, Landscape and Greenhouse Association, Inc.", "cost": "The cost for MCPH exam is $35", "accommodations": "https://www.nbphe.org/certified-in-public-health/faqs/#:~:text=What%20about%20candidates%20with%20disabilities,before%20scheduling%20the%20CPH%20exam.", "effDate": "July 1, 2025", "hours": "1 to 4+ years of combined education and industry experience", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies professional knowledge of horticulture, plant care, and landscape management practices.", "careerPaths": "Landscape Technician, Nursery Manager, Horticulturist, Grounds Manager", "goodFitFor": "Agriculture, horticulture, and landscaping programs; Environmental and green career pathways; Community-based garden programs", "detailedDesc": "The Maryland Nursery, Landscape and Greenhouse Association's Certified Professional Horticulturist credential validates comprehensive horticultural knowledge and management skills. Youth demonstrate competency in plant science, pest management, and landscape design. The Maryland-specific credential connects directly to state industry employers and professional networks. Programs benefit from local partnership and employment connections."}, {"name": "Certified Radio Operator", "code": "IRC-1073", "cluster": "Arts, Entertainment & Design", "link": "https://sbe.org/certification/certification-levels/certified-radio-operator-cro-and-certified-television-operator-cto/", "issuer": "Society of Broadcast Engineers", "cost": "The license fee is $35", "accommodations": "https://sbe.org/certification/applications/#:~:text=If%20the%20candidate%20is%20unable,appropriate%20facilities%20can%20be%20provided.", "effDate": "July 1, 2025", "hours": "FCC Marine Radio Operator Permits (MROP) often take only 8 hours (one day), while more advanced General Radiotelephone Operator Licenses (GROL) can require 2 days to 30+ hours of study", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Society of Broadcast Engineers credential validating foundational knowledge of radio broadcasting operations, FCC regulations, and transmission equipment.", "careerPaths": "Radio Broadcast Technician, Radio Station Operator, Broadcast Engineer, Media Production Technician, Communications Specialist", "goodFitFor": "Programs with media production, journalism, or broadcasting career tracks; programs serving youth interested in radio, podcasting, or broadcast media; programs affiliated with school or community radio stations; arts and communications afterschool programs", "detailedDesc": "The Certified Radio Operator (CRO) credential, issued by the Society of Broadcast Engineers (SBE), validates foundational knowledge of radio station operations, FCC licensing rules, transmitter operation, and broadcast engineering fundamentals. It is recognized by radio stations and broadcast facilities as an entry-level professional standard. This credential is a strong fit for OST programs with access to radio or audio production equipment and particularly meaningful for youth pursuing careers in broadcasting, media production, or communications. It pairs well with audio production credentials like AVID Pro Tools."}, {"name": "Certified SolidWorks Associate (CSWA-Mechanical Design)", "code": "IRC-1074", "cluster": "Advanced Manufacturing", "link": "https://www.solidworks.com/certifications/mechanical-design-cswa-mechanical-design", "issuer": "SolidWorks", "cost": "Generally the cost is $99", "accommodations": "https://www.solidworks.com/certifications/mechanical-design-cswa-mechanical-design", "effDate": "July 1, 2025", "hours": "2 to 9 weeks of training, depending on prior experience, with a recommended 150 hours of total CAD exposure", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Entry-level SolidWorks credential validating ability to create basic 3D models and drawings using SolidWorks CAD software.", "careerPaths": "CAD Technician, Mechanical Designer (entry), Drafting Technician, Manufacturing Associate, Product Design Assistant", "goodFitFor": "CTE-aligned STEM programs; programs with engineering or design tracks for high school youth; programs with access to CAD software; programs partnered with engineering or manufacturing employers", "detailedDesc": "The Certified SolidWorks Associate (CSWA) in Mechanical Design validates a student's foundational ability to create 3D parts, basic assemblies, and 2D engineering drawings using SolidWorks, a leading CAD platform widely used in mechanical engineering and manufacturing. Preparation typically requires 30\u201360 hours of hands-on practice and instruction. This credential is recognized by engineering and manufacturing employers as a starting point for CAD-related roles. The CSWA is the prerequisite foundation for the more advanced Certified SolidWorks Professional (CSWP) and is an excellent fit for youth exploring engineering design careers."}, {"name": "Certified SolidWorks Professional (CSWP-Mechanical Design)", "code": "IRC-1075", "cluster": "Advanced Manufacturing", "link": "https://www.solidworks.com/solidworks-certification-program", "issuer": "SolidWorks", "cost": "Generally the cost is $99", "accommodations": "https://www.solidworks.com/certifications/solidworks-cad-design-professional", "effDate": "July 1, 2025", "hours": "20\u201332 hours of structured coursework, often spread over 3\u20134 weeks for preparation, depending on experience", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Advanced credential validating professional-level proficiency in SolidWorks 3D CAD software for mechanical design and engineering.", "careerPaths": "Mechanical Design Engineer, Product Designer, CAD Specialist, Structural Engineer (entry), Manufacturing Engineer", "goodFitFor": "Advanced CTE or STEM programs for older high school youth with prior CAD experience; programs partnered with engineering or manufacturing firms; specialized programs serving youth heading toward engineering or design careers", "detailedDesc": "The Certified SolidWorks Professional (CSWP) in Mechanical Design, issued by Dassault Syst\u00e8mes SolidWorks Corporation, validates advanced proficiency in parametric 3D modeling, complex assembly design, and design configuration. It is a widely respected credential in mechanical engineering and manufacturing industries. The CSWP requires prior SolidWorks experience and is best suited for older youth with a foundation in 3D CAD who are preparing for engineering-level roles. Programs offering this credential benefit from strong industry partnerships and instructor expertise in mechanical design."}, {"name": "Certified Web and Mobile App Developer Associate", "code": "IRC-1076", "cluster": "Arts, Entertainment & Design", "link": "https://webprofessionals.org/certification", "issuer": "WOW", "cost": "The cost is $95", "accommodations": "https://www.ada.gov/resources/testing-accommodations/", "effDate": "July 1, 2025", "hours": "intensive 2-week bootcamps to 350-hour, 24\u201328 week programs or 2-year associate degrees", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Credential certifying foundational skills in developing, testing, and deploying web and mobile applications.", "careerPaths": "Web Developer, Mobile App Developer, Front-End Developer, Software Developer (entry), Digital Product Designer", "goodFitFor": "Technology pathway programs for high school youth; coding-focused afterschool programs; programs partnered with tech startups or software companies; summer coding bootcamps", "detailedDesc": "The Certified Web and Mobile App Developer Associate (CWMDA), issued by the World Organization of Webmasters (WOW), validates a student's ability to plan, develop, and deploy functional web and mobile applications. It covers programming fundamentals, UI design principles, testing, and deployment workflows. This credential is suited for programs offering web development or app creation coursework and serves as a portfolio-backed credential for youth pursuing technology careers. It pairs well with other WOW credentials such as the Certified Web Designer or Web Developer Associate."}, {"name": "Certified Web Animator Associate", "code": "IRC-1077", "cluster": "Arts, Entertainment & Design", "link": "https://webprofessionals.org/certification", "issuer": "WOW", "cost": "The cost is $95", "accommodations": "https://www.ada.gov/resources/testing-accommodations/", "effDate": "July 1, 2025", "hours": "one to four weeks or span several months", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates entry-level skills in creating web-based animations and interactive motion content for digital platforms.", "careerPaths": "Web Animator, Motion Graphics Designer, Interactive Media Developer, Digital Content Creator, UX/UI Designer", "goodFitFor": "Creative digital media programs; afterschool programs with animation or interactive design tracks; programs serving youth interested in web-based creative careers; programs with design software and digital media tools", "detailedDesc": "The Certified Web Animator Associate, offered through the World Organization of Webmasters (WOW), certifies a student's ability to create animations and interactive motion content for websites and digital media platforms. It covers animation principles, web-based animation tools, and integration of motion content into web projects. This credential is suitable for youth building creative digital portfolios and pursuing careers in web design, motion graphics, or interactive media. It complements other WOW and Adobe credentials for students developing comprehensive digital design skills."}, {"name": "Certified Web Designer Associate (CWDSA)", "code": "IRC-1078", "cluster": "Arts, Entertainment & Design", "link": "https://webprofessionals.org/certification", "issuer": "WOW", "cost": "The cost is $95", "accommodations": "https://www.ada.gov/resources/testing-accommodations/", "effDate": "July 1, 2025", "hours": "100 to 140 hours of course time for Level 1, often completed in a few weeks to several months depending on intensity", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates foundational web design skills including layout, user experience, visual design principles, and basic front-end coding.", "careerPaths": "Web Designer, UX/UI Designer (entry), Front-End Developer, Digital Content Specialist, Graphic Designer", "goodFitFor": "Creative or technology-focused afterschool programs; programs with web design or digital media tracks; programs serving youth interested in design and user experience; summer creative tech intensives", "detailedDesc": "The Certified Web Designer Associate (CWDSA), offered by the World Organization of Webmasters (WOW), certifies a student's understanding of web design principles including layout, typography, color theory, user experience, and basic HTML/CSS. It is designed for students entering the field and is recognized by employers hiring junior designers and front-end developers. Preparation typically takes 30\u201350 hours. This credential is a strong addition for programs that blend creative and technical skills and pairs naturally with Adobe Creative Suite credentials."}, {"name": "Certified Web Developer Associate (CWDVA)", "code": "IRC-1079", "cluster": "Arts, Entertainment & Design", "link": "https://webprofessionals.org/certification", "issuer": "WOW", "cost": "The cost is $95", "accommodations": "https://www.ada.gov/resources/testing-accommodations/", "effDate": "July 1, 2025", "hours": "1 to 4 weeks for specialized, non-credit programs", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Credential certifying entry-level proficiency in web development including HTML, CSS, JavaScript, and site deployment.", "careerPaths": "Web Developer, Front-End Developer, Software Developer (entry), Web Content Manager, E-Commerce Specialist", "goodFitFor": "Coding and technology afterschool programs; programs with web development or software career tracks; programs partnered with digital agencies or tech employers; summer coding intensives", "detailedDesc": "The Certified Web Developer Associate (CWDVA), issued by the World Organization of Webmasters (WOW), validates entry-level skills in building functional websites using HTML, CSS, JavaScript, and related technologies. It is designed to demonstrate that a student can create and maintain basic websites and understand core development workflows. This credential is appropriate for programs offering coding or web development coursework and serves as a practical credential for youth assembling a professional portfolio. It complements other WOW certifications and technology pathway credentials."}, {"name": "Child Development Associate", "code": "IRC-1080", "cluster": "Education", "link": "https://www.cdacouncil.org/en/", "issuer": "Council for Professional Recognition", "cost": "Initial CDA fee is $525 for online applications and $600 for paper", "accommodations": "https://www.cdacouncil.org/en/cda-exam-special-accommodations/", "effDate": "July 1, 2025", "hours": "3 to 6 months to complete, requiring 120 hours of formal education alongside 480 hours of work experience", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates competency in early childhood development, education practices, and cultural responsiveness for teachers and caregivers.", "careerPaths": "Preschool Teacher, Childcare Provider, Lead Teacher, Early Childhood Educator, Family Support Worker, Instructional Assistant", "goodFitFor": "Early childhood education programs; Education and youth development career pipelines; Community-based childcare or family support programs", "detailedDesc": "The Council for Professional Recognition's Child Development Associate (CDA) is the widely recognized credential for early childhood educators, validating knowledge of child development, family engagement, and inclusive practices. This credential is required or preferred for many early childhood positions and supports career advancement. Youth interested in education and childcare gain professional validation and access to better-paying positions. Programs should partner with early childhood centers and community colleges that offer CDA preparation courses."}, {"name": "Class A Commercial Driver License (CDL)", "code": "IRC-1081", "cluster": "Supply Chain & Transportation", "link": "https://mva.maryland.gov/drivers/Pages/cdl-commercial.aspx", "issuer": "Maryland Department of Transportation", "cost": "The cost can range from $1500 to $5500", "accommodations": "https://mva.maryland.gov/about-mva/Pages/Persons-With-Disabilities.aspx", "effDate": "July 1, 2025", "hours": "3 to 9 weeks to complete, with full-time programs often lasting 4 to 8 weeks (approx. 160\u2013300 hours) and part-time/weekend programs running up to 16 weeks", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies readiness to operate heavy commercial vehicles and transport goods legally and safely.", "careerPaths": "Commercial Truck Driver, Delivery Driver, Long-Haul Trucker, Local Delivery Driver, Fleet Driver", "goodFitFor": "Transportation and commercial driving career pathways; Logistics and supply chain career programs; Youth ages 18+ interested in trucking", "detailedDesc": "This credential, issued by the Maryland Department of Transportation, certifies ability to legally operate Class A commercial vehicles (tractor-trailers, tankers, buses). Class A CDL drivers are in high demand with strong wages, benefits, and job security. Drivers can specialize in hazmat, tanker, or oversized loads for higher pay. Programs should include both classroom instruction and supervised in-vehicle training."}, {"name": "Class B Commercial Driver License (CDL)", "code": "IRC-1082", "cluster": "Supply Chain & Transportation", "link": "https://mva.maryland.gov/drivers/Pages/cdl-commercial.aspx", "issuer": "Maryland Department of Transportation", "cost": "The cost in MD is $2200", "accommodations": "https://mva.maryland.gov/about-mva/Pages/Persons-With-Disabilities.aspx", "effDate": "July 1, 2025", "hours": "between 2 to 6 weeks to complete", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies legal and safe operation of medium-duty commercial vehicles for local and regional transport.", "careerPaths": "Delivery Driver, Bus Operator, School Bus Driver, Local Delivery Specialist, Commercial Vehicle Operator", "goodFitFor": "Transportation and commercial driving career pathways; Local delivery and service vehicle programs; Youth ages 18+ interested in commercial driving", "detailedDesc": "This credential, issued by the Maryland Department of Transportation, certifies ability to operate Class B commercial vehicles (straight trucks, small buses) within legal and safety limits. Class B CDL opens steady local delivery and public transit careers. Drivers earn solid wages with excellent benefits and job stability. Programs should provide classroom and behind-the-wheel training with experienced instructors."}, {"name": "Commercial Learner's Permit (CLP)", "code": "IRC-1083", "cluster": "Supply Chain & Transportation", "link": "https://mva.maryland.gov/drivers/Pages/cdl-commercial.aspx", "issuer": "Maryland Department of Transportation", "cost": "Maryland cost is $106", "accommodations": "https://mva.maryland.gov/about-mva/Pages/Persons-With-Disabilities.aspx", "effDate": "July 1, 2025", "hours": "a few days to a few weeks of studying for written exams, with some specific courses taking only 4 days", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies foundational knowledge and preliminary approval for commercial driver licensing pathway.", "careerPaths": "Commercial Driver-in-Training, CDL Student, Future Commercial Driver, Transportation Career Starter, Driver Trainee", "goodFitFor": "Commercial driving pathway initiation; Pre-licensing and preparation programs; Youth ages 18+ preparing for CDL certification", "detailedDesc": "This credential, issued by the Maryland Department of Transportation, represents the first step toward CDL, granting permission to practice under supervision before testing for full licensure. CLP holders can drive commercial vehicles while supervised by a licensed CDL driver. It's designed for youth committed to commercial driving careers. Programs should clarify the progression from CLP to Class A or B CDL."}, {"name": "CompTIA A+", "code": "IRC-1084", "cluster": "Digital Technology", "link": "https://www.comptia.org/certifications/a", "issuer": "Computing Technology Industry Association (CompTIA)", "cost": "The cost is $492", "accommodations": "https://help.comptia.org/hc/en-us/articles/11183018549780-What-Are-Accommodations-and-How-Do-I-Request-One-If-Eligible", "effDate": "July 1, 2025", "hours": "1\u20133 months of training for those with some IT knowledge, or 3\u20136 months for beginners, averaging roughly 80\u2013100 hours of total study time for both Core 1 and Core 2 exams", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "The industry-standard entry-level IT certification validating skills in hardware, software, networking, and technical support for computing devices.", "careerPaths": "IT Support Specialist, Help Desk Technician, Desktop Support Technician, Field Service Technician, Systems Administrator (entry)", "goodFitFor": "Technology pathway programs for high school youth; STEM-focused afterschool programs; programs partnered with IT employers, managed service providers, or school districts; workforce development programs with IT career tracks", "detailedDesc": "CompTIA A+ is widely regarded as the most recognized entry-level IT certification in the industry, validating skills in hardware configuration, operating systems, networking, troubleshooting, security, and customer service. Issued by the Computing Technology Industry Association (CompTIA), it is a two-exam certification (Core 1 and Core 2) that typically requires 60\u2013100+ hours of preparation. Employers across virtually every sector recognize it as a baseline qualification for IT support roles. It is a strong credential for OST programs with a technology focus, as it opens doors to IT careers that offer competitive entry-level salaries."}, {"name": "CompTIA Linux+", "code": "IRC-1085", "cluster": "Digital Technology", "link": "https://www.comptia.org/certifications/a", "issuer": "Computing Technology Industry Association (CompTIA)", "cost": "The cost is $369", "accommodations": "https://help.comptia.org/hc/en-us/articles/11183018549780-What-Are-Accommodations-and-How-Do-I-Request-One-If-Eligible", "effDate": "July 1, 2025", "hours": "between 4 weeks and 6 months, depending on experience, with many professionals spending 1\u20133 months studying", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies competency in Linux operating system administration, command-line skills, and system management.", "careerPaths": "Linux Systems Administrator, DevOps Engineer, Cloud Systems Administrator, IT Support Technician, Systems Engineer, Infrastructure Technician", "goodFitFor": "Technology-focused afterschool programs; Cybersecurity or IT career pathways; Workforce development programs in tech companies or corporate environments", "detailedDesc": "CompTIA Linux+ validates deep knowledge of Linux administration, user management, security, and troubleshooting\u2014skills essential in modern IT infrastructure where Linux powers much of the internet. This vendor-neutral credential is recognized across industries and demonstrates serious technical competency to employers. Youth with Linux+ skills are well-positioned for IT career advancement and cloud technology roles. Programs can use free Linux distributions and online labs to provide hands-on experience without significant equipment costs."}, {"name": "CompTIA Network+", "code": "IRC-1086", "cluster": "Digital Technology", "link": "https://www.comptia.org/certifications/a", "issuer": "Computing Technology Industry Association (CompTIA)", "cost": "The cost is $369", "accommodations": "https://help.comptia.org/hc/en-us/articles/11183018549780-What-Are-Accommodations-and-How-Do-I-Request-One-If-Eligible", "effDate": "July 1, 2025", "hours": "6 to 12 weeks of study for most individuals, often totaling 80\u2013120 hours of, with preparation time heavily dependent on prior networking experience. Beginners may need up to 4 months, while experienced IT professionals might prepare in 4\u20136 weeks", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates proficiency in network infrastructure, troubleshooting, and security fundamentals.", "careerPaths": "Network Administrator, Network Technician, IT Support Specialist, Systems Administrator, Network Support Engineer, IT Consultant", "goodFitFor": "IT and technology career pipelines; Cybersecurity-focused programs; Corporate or government IT workforce development programs", "detailedDesc": "CompTIA Network+ is a foundational IT certification covering network design, implementation, maintenance, and troubleshooting. It validates understanding of networking protocols, devices, and security fundamentals required for most IT careers. Youth earning Network+ demonstrate readiness for entry-level IT support roles and create a foundation for advanced certifications like Security+. Programs should include hands-on networking simulations and partner with IT departments or managed service providers for real-world exposure."}, {"name": "CompTIA PenTest+", "code": "IRC-1087", "cluster": "Digital Technology", "link": "https://www.comptia.org/certifications/a", "issuer": "Computing Technology Industry Association (CompTIA)", "cost": "The cost is $392", "accommodations": "https://help.comptia.org/hc/en-us/articles/11183018549780-What-Are-Accommodations-and-How-Do-I-Request-One-If-Eligible", "effDate": "July 1, 2025", "hours": "5-day (40-hour) intensive bootcamp for fast-tracked preparation. For self-paced study, candidates often take 1.5 to 3 months, assuming prior IT security experience. The certification is designed for professionals with 3-4 years of experience, often in conjunction with Network+ or Security+ knowledge", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies advanced penetration testing and ethical hacking skills including vulnerability assessment and remediation.", "careerPaths": "Penetration Tester, Ethical Hacker, Security Researcher, Vulnerability Assessor, Incident Response Specialist, Security Consultant", "goodFitFor": "Advanced cybersecurity programs for experienced IT youth; Specialized security training through government or corporate partnerships; Programs targeting high-achieving STEM students", "detailedDesc": "CompTIA PenTest+ is an advanced credential validating hands-on offensive security skills\u2014penetration testing, vulnerability analysis, and exploitation techniques used to identify system weaknesses. This is appropriate for youth with prior IT experience and demonstrates cutting-edge security expertise. Penetration testers are highly sought and command premium salaries in cybersecurity roles. Programs require advanced curriculum, specialized lab environments, and ideally partnerships with cybersecurity firms for mentorship."}, {"name": "CompTIA Security+", "code": "IRC-1088", "cluster": "Digital Technology", "link": "https://www.comptia.org/certifications/a", "issuer": "Computing Technology Industry Association (CompTIA)", "cost": "The cost is $404", "accommodations": "https://help.comptia.org/hc/en-us/articles/11183018549780-What-Are-Accommodations-and-How-Do-I-Request-One-If-Eligible", "effDate": "July 1, 2025", "hours": "30 to 45 days (4-6 weeks) of focused study for IT professionals, but beginners should plan for 2 to 3 months", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates foundational cybersecurity knowledge and practical skills protecting IT systems and networks.", "careerPaths": "Cybersecurity Analyst, Security Administrator, IT Security Specialist, Compliance Officer, Network Security Technician, SOC Analyst", "goodFitFor": "Cybersecurity-focused youth programs; IT and technology career pathways; Government or financial services workforce development programs", "detailedDesc": "CompTIA Security+ is the gold-standard entry-level cybersecurity credential covering threat identification, defense mechanisms, access control, and incident response. Many government and defense positions require Security+ for hiring, making it exceptionally valuable for youth interested in those sectors. This credential demonstrates serious cybersecurity commitment and opens doors to analyst and specialist roles. Programs should include hands-on lab scenarios and connect youth to cybersecurity professionals and organizations."}, {"name": "Cosmetology License", "code": "IRC-1089", "cluster": "Healthcare & Human Services", "link": "https://www.labor.maryland.gov/license/cos/cosexam.shtml", "issuer": "Maryland Department of Labor", "cost": "The cost I $77 Practical & Theory", "accommodations": "https://www.labor.maryland.gov/license/cos/cosexam.shtml", "effDate": "July 1, 2025", "hours": "1,500 hours (roughly 9\u201312 months full-time) in a school or 24 months via a registered apprenticeship", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies completion of comprehensive cosmetology training and passage of state licensing exam.", "careerPaths": "Cosmetologist, Hair Stylist, Esthetician Assistant, Salon Manager, Beauty Consultant", "goodFitFor": "Beauty and personal services career pathways; Entrepreneurship-focused programs; Community-based training with salon partnerships", "detailedDesc": "This credential validates skills in hair care, cutting, coloring, chemical treatments, and customer service through rigorous state-mandated training and exam. Issued by the Maryland Department of Labor, it requires at least 1,200 hours of classroom and hands-on training. The cosmetology license opens doors to salon work, specializations in coloring or extensions, salon ownership, or product sales. Programs should partner with licensed cosmetology schools and salons for real-world experience."}, {"name": "Cyber Crime Investigator (CCI)", "code": "IRC-1090", "cluster": "Digital Technology", "link": "https://www.cool.osd.mil/dciv/credential/index.html?cert=ceci8720#:~:text=CECIs%20are%20experts%20in%20the,must%20pass%20a%20written%20exam.", "issuer": "Department of Defense", "cost": "The costs will vary", "accommodations": "https://www.dodea.edu/offices/equal-employment-opportunity-programs/reasonable-accommodations#:~:text=If%20you%20believe%20you%20need,throughout%20the%20reasonable%20accommodation%20process.", "effDate": "July 1, 2025", "hours": "intensive 8-day courses to comprehensive 4-6 month programs", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies competency in identifying, analyzing, and investigating cybercrimes and digital forensics.", "careerPaths": "Cyber Crime Investigator, Digital Forensics Analyst, Incident Response Specialist, Law Enforcement Technician, Cybersecurity Analyst, Intelligence Analyst", "goodFitFor": "Law enforcement career pipelines; Advanced cybersecurity programs with forensics focus; Government workforce development programs; Criminal justice youth programs", "detailedDesc": "The Department of Defense's Cyber Crime Investigator credential validates skills in digital forensics, crime scene analysis, evidence handling, and investigation protocols. This credential is particularly valuable for youth interested in law enforcement, homeland security, or government cybersecurity roles. It combines technical skills with investigative training and requires understanding of legal frameworks. Programs typically require partnerships with law enforcement agencies or specialized training providers to deliver this curriculum."}, {"name": "Cyber Ops", "code": "IRC-1091", "cluster": "Digital Technology", "link": "https://www.cisco.com/site/us/en/learn/training-certifications/certifications/cybersecurity/index.html", "issuer": "Cisco (Certiport)", "cost": "The costs is $300", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "2 to 5 months for most individuals, though dedicated study can reduce this to about 8\u201312 weeks. Intensive, full-time, or accelerated bootcamps may allow completion in as little as 4\u20137 days", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates foundational Cisco networking and cybersecurity operations skills.", "careerPaths": "Network Technician, Cybersecurity Technician, IT Support Specialist, Systems Administrator, Junior Network Engineer, SOC Technician", "goodFitFor": "STEM programs with networking or cybersecurity focus; Technology career pathways for older youth; Cisco Academy partnership programs", "detailedDesc": "Cisco's Cyber Ops credential covers network monitoring, threat identification, and incident response fundamentals aligned with Cisco's industry-leading networking platform. This certification, offered through Certiport, demonstrates practical knowledge of network security operations. Youth earning Cyber Ops are positioned for entry-level roles in network operations centers and security operations centers, which are growing rapidly. Programs should partner with Cisco Academies, which provide curriculum and instructor training."}, {"name": "CYSA+ (Cybersecurity Analyst)", "code": "IRC-1092", "cluster": "Digital Technology", "link": "https://www.comptia.org/certifications/cybersecurity-analyst", "issuer": "CompTIA", "cost": "The cost is $392", "accommodations": "https://help.comptia.org/hc/en-us/articles/11183018549780-What-Are-Accommodations-and-How-Do-I-Request-One-If-Eligible#:~:text=Understanding%20CompTIA%20CompCerts:%20Certificates%20of,Exam%20with%20an%20Approved%20Accommodation", "effDate": "July 1, 2025", "hours": "4-to-5-day intensive boot camp, though comprehensive self-study or preparation often spans 8 to 12 weeks for exam readiness. The certification is designed for professionals with 3\u20134 years of experience", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies cybersecurity analyst competencies in threat assessment, vulnerability identification, and defense strategies.", "careerPaths": "Cybersecurity Analyst, Security Analyst, Systems Security Analyst, IT Security Specialist, Compliance Analyst, Security Engineer", "goodFitFor": "Advanced cybersecurity programs; IT career pathways for college-bound youth; Workforce development programs in tech hubs or corporate environments", "detailedDesc": "CompTIA CySA+ (Cybersecurity Analyst) validates practical skills in analyzing security data, identifying threats, and recommending defense improvements. This credential demonstrates hands-on security expertise and is often required or preferred for analyst positions in corporations and government. Youth with CySA+ gain access to mid-level security roles with strong earning potential. Programs should combine theoretical instruction with real-world scenario labs and threat intelligence analysis exercises."}, {"name": "Siemens Automation Fundamentals Certification: PLC", "code": "IRC-1093", "cluster": "Advanced Manufacturing", "link": "https://www.siemens.com/us/en/products/automation/systems/sce/certificates.html", "issuer": "Siemens", "cost": "$165.00", "accommodations": "https://training.plm.automation.siemens.com/support/cert_guide.pdf", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Validates foundational knowledge of programmable logic controllers (PLCs) and industrial automation using Siemens TIA Portal and SIMATIC systems.", "careerPaths": "PLC Technician, Automation Technician, Industrial Controls Technician, Manufacturing Systems Operator, Electrical Controls Engineer (entry)", "goodFitFor": "Programs with advanced manufacturing or industrial automation career tracks; programs with CNC, robotics, or industrial controls equipment; programs partnered with manufacturers using Siemens automation systems; STEM programs with engineering or electronics components", "detailedDesc": "The Siemens Automation Fundamentals Certification: PLC validates a student's understanding of programmable logic controller (PLC) programming and industrial automation using Siemens' TIA Portal software and SIMATIC hardware, the most widely deployed automation platform in global manufacturing. PLCs are the control backbone of virtually every automated production line, and PLC technicians are in extremely high demand across all manufacturing sectors. This credential is best suited for programs with access to Siemens automation equipment or simulators and instructors with industrial controls experience. It positions youth for well-paying, highly technical careers in smart manufacturing and Industry 4.0 environments."}, {"name": "Differential and 4WD Systems", "code": "IRC-1094", "cluster": "Supply Chain & Transportation", "link": "https://www.newfordtech.com/programs#:~:text=OUR%20PROGRAMS,The%20FACT%20Program", "issuer": "Ford Motor Company", "cost": "Cost Varies", "accommodations": "https://www.newfordtech.com/", "effDate": "July 1, 2025", "hours": "varies from focused, 1-week certification intensives (e.g., I4WDTA) to 8-week college courses", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies technical knowledge of differential systems and 4-wheel drive components in vehicles.", "careerPaths": "Automotive Technician, Powertrain Specialist, Drivetrain Service Technician, Ford Service Technician", "goodFitFor": "Automotive career programs; Ford-partnered training initiatives; Advanced automotive or transportation pathway programs", "detailedDesc": "This Ford Motor Company credential validates specialized knowledge of differential and 4WD systems essential for modern vehicle service and repair. Youth learn how these critical drivetrain components function, interact, and are serviced. The credential is particularly valuable for Ford service centers and dealerships seeking trained technicians. Programs can leverage Ford curriculum materials and connect youth directly with Ford employment opportunities."}, {"name": "Digital Forensic Examiner (DFE)", "code": "IRC-1095", "cluster": "Digital Technology", "link": "https://www.eccouncil.org/train-certify/digital-forensics-essentials-dfe/", "issuer": "Department of Defense", "cost": null, "accommodations": "https://www.dodea.edu/offices/equal-employment-opportunity-programs/reasonable-accommodations#:~:text=If%20you%20believe%20you%20need,throughout%20the%20reasonable%20accommodation%20process.", "effDate": "July 1, 2025", "hours": "5 days for most professional certifications, though specialized, intensive programs (like Federal Law Enforcement Training Centers) may last up to 10 days", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates knowledge and skills in collecting, preserving, and analyzing digital evidence for cybercrime investigations.", "careerPaths": "Digital Forensic Examiner, Cybercrime Investigator, Law Enforcement Technology Specialist, Cybersecurity Analyst, Intelligence Analyst", "goodFitFor": "Programs with law enforcement, cybersecurity, or public safety career tracks; programs partnered with law enforcement agencies or defense organizations; older youth workforce programs focused on national security or criminal justice careers", "detailedDesc": "The Digital Forensic Examiner (DFE) credential, issued by the Department of Defense, validates a student's ability to collect, preserve, and analyze digital evidence in a forensically sound manner for use in criminal investigations. It covers evidence acquisition, chain of custody, file system analysis, and report writing. This credential is best suited for programs with connections to law enforcement, cybersecurity, or national security career pathways. It pairs well with courses in cybersecurity, criminal justice, or computer science."}, {"name": "Digital Media Collector (DMC)", "code": "IRC-1096", "cluster": "Digital Technology", "link": "https://www.dcita.edu/", "issuer": "Department of Defense", "cost": null, "accommodations": "https://www.dodea.edu/offices/equal-employment-opportunity-programs/reasonable-accommodations#:~:text=If%20you%20believe%20you%20need,throughout%20the%20reasonable%20accommodation%20process.", "effDate": "July 1, 2025", "hours": "2 to 4 months", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates skills in managing and securing digital media assets within government or organizational systems.", "careerPaths": "Digital Media Specialist, Information Security Analyst, Records Manager, Digital Assets Manager, IT Security Technician, Data Protection Specialist", "goodFitFor": "Government or corporate IT workforce programs; Records management or information governance programs; Advanced security-focused youth pathways", "detailedDesc": "The Department of Defense's Digital Media Collector credential certifies expertise in managing, cataloging, and protecting digital information assets\u2014increasingly critical as organizations handle sensitive data. This credential is particularly relevant for government positions and contractors dealing with classified or sensitive information. Youth with this credential demonstrate understanding of data management and security essentials. Programs typically require government or defense contractor partnerships and security clearance-related training."}, {"name": "Ducks Unlimited Ecology Conservation & Management Certification", "code": "IRC-1097", "cluster": "Agriculture", "link": "https://www.ducks.org/get-involved/youth-programs/ducks-unlimited-ecology-conservation-and-management-certification", "issuer": "Ducks Unlimited", "cost": "The cost is $299 for the exam", "accommodations": "https://www.icevonline.com/accommodations", "effDate": "July 1, 2025", "hours": "150 hours of instruction", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates knowledge of wetland ecology, wildlife conservation, and natural resource management as aligned with Ducks Unlimited curricula.", "careerPaths": "Wildlife Conservation Technician, Natural Resource Manager, Environmental Educator, Park Ranger (entry), Conservation Scientist", "goodFitFor": "Programs with environmental science, agriculture, or natural resource career tracks; outdoor education and conservation-focused OST programs; programs in rural or environmental communities; programs partnered with conservation organizations or state environmental agencies", "detailedDesc": "The Ducks Unlimited Ecology, Conservation & Management Certification validates student knowledge of wetland ecosystems, waterfowl biology, wildlife habitat management, and conservation practices as taught through Ducks Unlimited's educational programs. It is designed for students in agricultural and environmental science courses and is recognized within conservation-focused career pathways. This credential is well-suited for OST programs that incorporate outdoor learning, environmental stewardship, or natural resource management. It connects youth to careers in wildlife management, conservation, and environmental science."}, {"name": "EETC Principles of Small Engine Technology", "code": "IRC-1098", "cluster": "Agriculture, Supply Chain & Transportation,", "link": "https://www.icevonline.com/small-engines", "issuer": "Engine & Equipment Training Council (EETC) through iCEV", "cost": "The cost is $59 per exam", "accommodations": "https://www.icevonline.com/accommodations", "effDate": "July 1, 2025", "hours": "3-day workshops to comprehensive, multi-week high school Career and Technical Education (CTE) programs, often spanning 36 weeks", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies technical knowledge of small engine operation, repair, and maintenance principles.", "careerPaths": "Small Engine Technician, Equipment Repair Specialist, Maintenance Technician, Equipment Operator", "goodFitFor": "Agriculture, supply chain, and equipment maintenance programs; Trade skill pathways; Programs with hands-on equipment access", "detailedDesc": "The Engine & Equipment Training Council's Small Engine Technology credential (through iCEV) validates competency in small engine mechanics, maintenance, and troubleshooting. Youth learn skills applicable across agriculture, landscaping, and equipment industries. The credential demonstrates readiness for equipment repair and maintenance careers. Programs can offer hands-on training with common small engines and equipment."}, {"name": "Elanco Animal Science", "code": "IRC-1099", "cluster": "Agriculture", "link": "https://www.icevonline.com/animal-science", "issuer": "Elanco", "cost": "The exam voucher is $40 and non-subscriber, it is $50", "accommodations": "https://www.elanco.com/us/contact", "effDate": "July 1, 2025", "hours": "150 hours of related instructional time", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Industry-backed credential validating foundational knowledge of animal science, livestock production, and animal care principles.", "careerPaths": "Veterinary Technician (entry), Animal Care Specialist, Livestock Producer, Agricultural Science Technician, Farm Manager", "goodFitFor": "Agriculture and animal science programs; programs in rural communities with farming or livestock industry connections; OST programs affiliated with FFA or 4-H; programs partnered with veterinary clinics or agricultural employers", "detailedDesc": "The Elanco Animal Science credential, offered through iCEV and sponsored by Elanco, validates student knowledge of animal biology, nutrition, health management, and production systems across livestock species. It is aligned with industry standards in agriculture and animal science and recognized by employers in veterinary, livestock, and animal care fields. This credential is an excellent fit for programs with an agricultural focus and particularly strong for youth involved in FFA, 4-H, or other agricultural youth organizations. It provides a strong foundation for further study in veterinary technology or animal science."}, {"name": "Elanco Vet Medicine", "code": "IRC-1100", "cluster": "Agriculture", "link": "https://www.icevonline.com/vet-med", "issuer": "Elanco", "cost": "The exam voucher is $40 and non-subscriber, it is $50", "accommodations": "https://www.elanco.com/us/contact", "effDate": "July 1, 2025", "hours": "60 to 100 hours of instructional training to complete", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates knowledge of veterinary medicine principles, animal health, pharmaceutical care, and clinical practices relevant to entry-level veterinary roles.", "careerPaths": "Veterinary Assistant, Veterinary Technician (pathway), Animal Health Technician, Livestock Health Manager, Pharmaceutical Sales Representative (agriculture)", "goodFitFor": "Programs with veterinary or animal science career tracks; programs partnered with veterinary clinics, animal shelters, or agricultural businesses; OST programs with FFA or 4-H connections; rural programs serving youth interested in animal health careers", "detailedDesc": "The Elanco Vet Medicine credential, developed with Elanco through iCEV, covers veterinary medicine fundamentals including animal physiology, disease prevention, pharmaceutical products, and clinical care procedures. It is designed for students pursuing careers in veterinary technology or animal health and reflects industry knowledge valued by employers in veterinary practices, animal agriculture, and pharmaceutical companies. This credential pairs naturally with the Elanco Animal Science credential and is a strong fit for programs building structured agricultural or veterinary career pathways."}, {"name": "Electrical Line Worker Program Pre-Apprenticeship Certificate", "code": "IRC-1101", "cluster": "Construction", "link": "https://www.utilitrain.org", "issuer": "Utilitrain", "cost": null, "accommodations": null, "effDate": "July 1, 2025", "hours": "5 to 15 weeks to complete", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates completion of pre-apprenticeship training preparing youth for entry into union electrical line worker apprenticeships.", "careerPaths": "Electrical Line Worker, Utility Technician, Power Line Technician, Substation Technician, Cable Installer, Electrical Apprentice", "goodFitFor": "Workforce development programs with utility company partnerships; Union apprenticeship preparation programs; Programs serving youth in energy and infrastructure sectors", "detailedDesc": "Utilitrain's pre-apprenticeship certificate provides classroom and hands-on training aligned with union electrical line worker standards, including safety, climbing, rigging, and basic electrical theory. Youth completing this certificate are qualified to apply directly to utility apprenticeships where they can earn while learning. This is a high-wage career path with strong benefits and job security in essential infrastructure. Programs should partner with local utilities or unions to ensure training aligns with local hiring requirements."}, {"name": "Emergency Medical Responder (EMR) (MIEMSS)", "code": "IRC-1102", "cluster": "Public Service & Safety", "link": "https://www.miemss.org/home/", "issuer": "Maryland Institute for Emergency Medical Services Systems (MIEMSS)", "cost": "The cost may vary for high school students", "accommodations": "https://www.nremt.org/Policies/Examination-Policies/ADA-Accommodations", "effDate": "July 1, 2025", "hours": "minimum of 50 hours of training", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Maryland-recognized credential for the first level of emergency medical services training, qualifying holders to provide immediate care at emergency scenes.", "careerPaths": "Emergency Medical Responder, Firefighter (first response), EMT (entry), First Responder, EMS Crew Member", "goodFitFor": "Programs with public safety or emergency services career tracks; programs partnered with fire departments, EMS agencies, or hospitals; community-based programs serving youth interested in healthcare or first response careers", "detailedDesc": "The Emergency Medical Responder (EMR) credential, recognized by the Maryland Institute for Emergency Medical Services Systems (MIEMSS), certifies a student's ability to provide initial emergency medical care including CPR, bleeding control, patient assessment, and airway management. It is the first rung of the EMS career ladder, preceding EMT and Paramedic certifications. Preparation typically requires 40\u201380 hours of combined classroom and hands-on training. This credential is an excellent fit for programs building youth career pathways in healthcare, public safety, or first responder fields."}, {"name": "Emergency Medical Technician (EMT) (MIEMSS)", "code": "IRC-1103", "cluster": "Public Service & Safety", "link": "https://www.miemss.org/home/", "issuer": "Maryland Institute for Emergency Medical Services Systems (MIEMSS)", "cost": "The cost may vary for high school students", "accommodations": "https://www.nremt.org/Policies/Examination-Policies/ADA-Accommodations", "effDate": "July 1, 2025", "hours": "minimum of 165 to 199+ hours of instruction, usually completed in 3 to 5 months", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies readiness to provide pre-hospital emergency medical care under Maryland's MIEMSS authority.", "careerPaths": "Emergency Medical Technician, Ambulance Crew, Emergency Responder, Paramedic Assistant, Mobile Intensive Care Technician", "goodFitFor": "Emergency services and public safety career pathways; Rescue and emergency response programs; Youth interested in helping professions", "detailedDesc": "This credential, issued by the Maryland Institute for Emergency Medical Services Systems (MIEMSS), certifies EMT knowledge and skills through classroom training and practical skills testing. It's the foundation for emergency response careers in fire departments, ambulance services, hospitals, and rescue operations. EMT positions offer strong job security, benefits, and pathways to paramedic certification. Programs should partner with fire departments or ambulance services for supervised field experience."}, {"name": "Emergency Medical Technician (EMT) (NREMT)", "code": "IRC-1104", "cluster": "Public Service & Safety", "link": "https://www.nremt.org/", "issuer": "National Registry of Emergency Medical Technicians", "cost": "The cost may vary for high school students", "accommodations": "https://www.nremt.org/Policies/Examination-Policies/ADA-Accommodations", "effDate": "July 1, 2025", "hours": "3 to 6 months to complete, involving approximately 120 to 160+ hours of classroom, lab, and clinical training", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies nationally-recognized emergency medical technician competencies for pre-hospital emergency care.", "careerPaths": "Emergency Medical Technician, Paramedic, Ambulance Crew, Emergency Responder, Critical Care Technician", "goodFitFor": "Emergency services and public safety career pathways; National certification and professional development programs; Youth interested in rescue services", "detailedDesc": "This credential, issued by the National Registry of EMTs (NREMT), is the gold standard for EMT certification, recognized across all 50 states and accepted by most employers nationwide. It validates knowledge of patient assessment, treatment protocols, and emergency procedures. NREMT certification opens career mobility and is required for many ambulance services and fire departments. Programs should ensure youth meet state prerequisites and provide mentorship through the exam process."}, {"name": "Entrepreneurship and Small Business", "code": "IRC-1105", "cluster": "Management and Entrepreneurship", "link": "https://certiport.pearsonvue.com/Certifications/ESB/Certification/Overview", "issuer": "Certiport", "cost": "Exam is $84", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "8 weeks and 9 months, with typical programs offering roughly 80 to 200+ hours of instruction", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": "Pass IT On", "oneLiner": "Certifies foundational knowledge of entrepreneurship, small business planning, and startup management.", "careerPaths": "Entrepreneur, Small Business Owner, Business Manager, Start-up Operations Specialist", "goodFitFor": "Youth entrepreneurship programs; Business and career pathway programs; Programs emphasizing youth agency and economic opportunity", "detailedDesc": "This Certiport credential validates understanding of business planning, marketing, financial management, and operations essential for aspiring entrepreneurs. Youth learn practical skills for launching and managing small businesses. The credential signals business acumen and readiness for self-employment or small business roles. Programs can emphasize the credential as validation for youth pitches, grant applications, or investor presentations."}, {"name": "EPA Section 608 Core plus Type I", "code": "IRC-1106", "cluster": "Construction", "link": "https://www.escogroup.org/training/epa608.aspx", "issuer": "ESCO Group", "cost": "The cost ranges from $10 to $220", "accommodations": "https://www.epa.gov/ocr/reasonable-accommodation", "effDate": "July 1, 2025", "hours": "4 to 8 hours of review, often structured as a one-day, 4-hour, or, in some cases, a two-day workshop", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Federal certification to legally handle refrigerants in small appliances like household refrigerators and window air conditioners.", "careerPaths": "Appliance Repair Technician, HVAC Technician, Refrigeration Technician, Facilities Maintenance Worker, Building Systems Technician", "goodFitFor": "Programs with HVAC, appliance repair, or building trades tracks; programs serving youth 16+ interested in trades careers; pre-apprenticeship programs in HVAC or facilities maintenance; workforce development programs in residential maintenance", "detailedDesc": "The EPA Section 608 Core plus Type I certification authorizes technicians to handle refrigerants specifically in small appliances such as household refrigerators, freezers, and window air conditioners. This combination credential covers both core refrigerant safety knowledge and Type I-specific regulations. As one of the most entry-accessible EPA 608 certifications, it is a strong fit for youth programs introducing HVAC or appliance repair skills. Preparation can be completed in as few as 5\u201310 hours. This credential is required by federal law for anyone servicing refrigerant-containing small appliances."}, {"name": "EPA Section 608 Core plus Type II", "code": "IRC-1107", "cluster": "Construction", "link": "https://www.escogroup.org/training/epa608.aspx", "issuer": "ESCO Group", "cost": "The cost ranges from $10 to $220", "accommodations": "https://www.epa.gov/ocr/reasonable-accommodation", "effDate": "July 1, 2025", "hours": "1.5 to 2 days for in-person seminars or about 6 to 8 hours for accelerated, focused, or online courses", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Federal certification authorizing technicians to handle high-pressure refrigerants used in residential and light commercial air conditioning systems.", "careerPaths": "HVAC Technician, Air Conditioning Technician, Refrigeration Mechanic, Facilities Maintenance Technician, Building Systems Engineer", "goodFitFor": "Programs with HVAC career tracks; programs serving youth 16+ pursuing skilled trades; workforce development programs partnered with HVAC contractors; pre-apprenticeship programs in construction or facilities management", "detailedDesc": "The EPA Section 608 Core plus Type II certification authorizes technicians to work with high-pressure refrigerants found in residential and light commercial air conditioning systems, the most common type of HVAC equipment. This is a critical credential for anyone pursuing a career as an HVAC technician and is required by federal law before handling these refrigerants. Preparation can be completed in approximately 10\u201320 hours. Programs with HVAC career tracks should consider offering this alongside Type I and Universal certifications to maximize youth employability."}, {"name": "EPA Section 608 Core plus Type III", "code": "IRC-1108", "cluster": "Construction", "link": "https://www.escogroup.org/training/epa608.aspx", "issuer": "ESCO Group", "cost": "The cost ranges from $10 to $220", "accommodations": "https://www.epa.gov/ocr/reasonable-accommodation", "effDate": "July 1, 2025", "hours": "1 to 2 days for in-person, instructor-led courses or 4 to 8 hours for accelerated/online prep sessions", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Federal certification authorizing technicians to handle low-pressure refrigerants used in large commercial HVAC systems and chillers.", "careerPaths": "Commercial HVAC Technician, Chiller Technician, Building Systems Engineer, Facilities Manager, Refrigeration Mechanic", "goodFitFor": "Programs with advanced HVAC or commercial building systems career tracks; programs partnered with commercial HVAC contractors or building management companies; advanced workforce development programs for older youth pursuing high-value trades careers", "detailedDesc": "The EPA Section 608 Core plus Type III certification authorizes technicians to work with low-pressure refrigerants used in large commercial HVAC systems such as centrifugal chillers. This is a more specialized certification within the HVAC field, typically relevant to commercial and industrial building systems rather than residential work. It is best suited for advanced programs with partnerships in commercial construction or facilities management. Combined with Type I and II certifications, it contributes to a full EPA 608 Universal certification, maximizing a technician's employability."}, {"name": "EPA Section 608 Technician", "code": "IRC-1109", "cluster": "Construction", "link": "https://www.escogroup.org/training/epa608.aspx", "issuer": "ESCO Group", "cost": "The cost ranges from $10 to $220", "accommodations": "https://www.epa.gov/ocr/reasonable-accommodation", "effDate": "July 1, 2025", "hours": "between 4 and 8 hours for accelerated or one-day courses, while self-paced, online, or in-depth programs may span a few days to several weeks", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Federal certification required to legally purchase and handle refrigerants when servicing, repairing, or disposing of HVAC and refrigeration equipment.", "careerPaths": "HVAC Technician, Refrigeration Mechanic, Facilities Maintenance Technician, Appliance Repair Technician, Building Systems Technician", "goodFitFor": "Programs with HVAC or building trades pathways; workforce development programs serving youth 16+ interested in the trades; programs partnered with HVAC contractors or facilities management companies; summer pre-apprenticeship programs", "detailedDesc": "The EPA Section 608 Universal Technician certification is a federally mandated credential required by the Environmental Protection Agency for anyone who purchases or handles refrigerants in HVAC and refrigeration systems. Covering all equipment types (small appliances, high-pressure, low-pressure, and universal systems), this certification is a prerequisite for employment in HVAC, refrigeration, and facilities maintenance roles. Preparation typically requires 10\u201320 hours of study. It is a fast, high-value credential for youth programs offering HVAC or building trades pathways."}, {"name": "Equine Management & Evaluation Certification", "code": "IRC-1110", "cluster": "Agriculture", "link": "https://www.icevonline.com/equine-management", "issuer": "National Horse Judging Team Coaches' Association (NHJTCA)", "cost": "The exam voucher is $40 and non-subscriber, it is $50", "accommodations": "https://www.icevonline.com/accommodations", "effDate": "July 1, 2025", "hours": "intensive short-term workshops (4-5 days) to year-long programs (12 months or ~400+ hours)", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies knowledge and evaluation skills in equine management, health, and breeding practices.", "careerPaths": "Equine Manager, Horse Trainer, Breeding Specialist, Equine Facility Manager", "goodFitFor": "Agriculture and animal science programs; Equestrian center partnerships; Programs serving rural communities with horse industry presence", "detailedDesc": "This National Horse Judging Team Coaches Association credential validates expertise in evaluating and managing horses, including conformation, health, and breeding considerations. Youth learn professional equine management practices and evaluation standards. The credential demonstrates readiness for careers in horse breeding, training, and facility management. Programs should partner with equestrian facilities for hands-on experience."}, {"name": "Erosion and Sediment Control", "code": "IRC-1111", "cluster": "Agriculture", "link": "https://roads.maryland.gov/mdotsha/pages/Index.aspx?PageId=56#:~:text=There%20is%20no%20fee%20for,finish%20it%20in%20one%20sitting.", "issuer": "Maryland Department of the Environment (MDE)", "cost": "No fee", "accommodations": "https://mde.maryland.gov/programs/water/pages/index.aspx", "effDate": "July 1, 2025", "hours": "4 to 16 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Maryland state credential validating knowledge of erosion and sediment control practices required for construction site and land disturbance compliance.", "careerPaths": "Stormwater Management Technician, Construction Site Manager, Environmental Compliance Specialist, Landscaper, Civil Engineering Technician", "goodFitFor": "Programs with construction, environmental science, or landscaping career tracks; programs in Maryland serving youth interested in civil construction or environmental compliance; programs partnered with construction companies or environmental agencies; green infrastructure or sustainability-focused programs", "detailedDesc": "The Erosion and Sediment Control credential, administered by the Maryland Department of the Environment (MDE), validates knowledge of stormwater management, erosion prevention techniques, and sediment control practices required under Maryland law for construction and land disturbance activities. This credential is required for individuals responsible for overseeing erosion and sediment control on construction sites in Maryland. It is a practical, state-specific credential that connects directly to employment in civil construction, site management, and environmental compliance. Programs in Maryland offering construction or environmental science pathways should strongly consider this credential."}, {"name": "ESRI ArcGIS Desktop Certification - NOTE: POS for JRUSAF", "code": "IRC-1112", "cluster": "Agriculture, Public Service & Safety", "link": "https://community.esri.com/t5/esri-technical-certification-program-information/esri-exam-voucher-pricing-and-purchase-options/ba-p/1568115/jump-to/first-unread-message#:~:text=You%20can%20learn%20more%20about,a%20credit%20card%20or%20PayPal.", "issuer": "ESRI Academy", "cost": "The exam voucher is $275.00", "accommodations": "https://www.esri.com/training/certification-take-exam/", "effDate": "July 1, 2025", "hours": "1\u20133 days of instructor-led courses (16\u201324 hours) for specific topics like ArcGIS Pro, or 4\u20136 week self-paced Massive Open Online Courses (MOOCs)", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies proficiency in geographic information systems and spatial analysis using ESRI ArcGIS software.", "careerPaths": "GIS Analyst, Cartographer, Environmental Analyst, Planning Technician", "goodFitFor": "STEM and environmental science programs; Agriculture and natural resources pathways; Public service and planning programs", "detailedDesc": "ESRI ArcGIS Desktop certification validates skills in geographic data analysis, mapping, and spatial problem-solving. Youth learn tools used across agriculture, environmental management, and government planning. The credential demonstrates readiness for GIS technician and analyst roles in growing fields. Programs appreciate ESRI's resources and industry recognition."}, {"name": "ESRI GIS Fundamentals Foundation (EGFF2201)", "code": "IRC-1113", "cluster": "Public Service & Safety", "link": "https://community.esri.com/t5/esri-technical-certification-program-information/esri-exam-voucher-pricing-and-purchase-options/ba-p/1568115/jump-to/first-unread-message#:~:text=You%20can%20learn%20more%20about,a%20credit%20card%20or%20PayPal.", "issuer": "ESRI Academy", "cost": "The cost is $275", "accommodations": "https://www.esri.com/training/certification-take-exam/", "effDate": "July 1, 2025", "hours": "100 to 150 hours of GIS coursework or 3\u20136 months of workplace experience", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates foundational geographic information systems (GIS) skills for data mapping and spatial analysis.", "careerPaths": "GIS Technician, Data Analyst, Mapping Specialist, Urban Planner Assistant, Environmental Analyst", "goodFitFor": "STEM, environmental science, and data analysis programs; Urban planning and sustainability career pathways; Technology-focused youth initiatives", "detailedDesc": "This credential, issued by ESRI Academy, certifies basic GIS software competency and spatial analysis skills used in planning, environmental work, and government. GIS is increasingly valuable in urban planning, natural resource management, and climate adaptation work. Youth with GIS skills gain access to growing fields in environmental work, smart cities, and data analysis. Programs should emphasize real-world applications like community mapping projects."}, {"name": "FAA Part 107 Drone Pilot License", "code": "IRC-1114", "cluster": "Supply Chain & Transportation, Agriculture", "link": "https://www.faa.gov/uas/commercial_operators/become_a_drone_pilot", "issuer": "Federal Aviation Administration", "cost": "The Part 107 test costs is $175. Each drone must registered at a cost of $5 per drone for three years.", "accommodations": "https://www.neurodiversityworks.org/post/part-107-exam-disability-accommodations-resource", "effDate": "July 1, 2025", "hours": "15\u201320 hours of study over 2\u20133 weeks, with 4\u20136 weeks for the total certification process", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies ability to legally operate unmanned aircraft systems for commercial applications and data collection.", "careerPaths": "Commercial Drone Pilot, UAS Operator, Survey Technician, Aerial Photographer, Agriculture Specialist", "goodFitFor": "Emerging technology and aviation career pathways; STEM and data collection programs; Agriculture, real estate, and infrastructure programs", "detailedDesc": "This credential, issued by the Federal Aviation Administration (Part 107), certifies knowledge of drone regulations, safety, and operation for commercial use. Drone pilots are in rapidly growing demand in agriculture, surveying, real estate, construction, and infrastructure inspection. Part 107 opens emerging careers with strong growth potential and competitive wages. Programs should emphasize safety, regulations, and practical applications across industries."}, {"name": "FCR-O1 (Operator 1)", "code": "IRC-1115", "cluster": "Advanced Manufacturing", "link": "https://www.fanucamerica.com/education/nocti-certifications-robotics", "issuer": "FANUC America", "cost": "Typically costs around $2000", "accommodations": "https://www.azed.gov/sites/default/files/2019/08/Fanuc%20NOCTI%20Fact%20sheet.pdf?id=5d4b3a441dcb2512042e9879#:~:text=online%20test%20order%20is%202,requiring%20accommodations%20during%20test%20administration", "effDate": "July 1, 2025", "hours": "45 to 80 hours of instructional training and hands-on experience", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Entry-level FANUC robotics credential validating basic knowledge of industrial robot operation, safety, and programming fundamentals.", "careerPaths": "Robotics Technician, Automation Operator, CNC Machine Operator, Manufacturing Technician, Industrial Maintenance Technician", "goodFitFor": "Programs with advanced manufacturing or robotics tracks; programs with access to FANUC equipment or simulators; workforce development programs partnered with manufacturing employers using automation; STEM-focused OST programs", "detailedDesc": "The FANUC Certified Robot Operator Level 1 (FCR-O1) credential, issued by FANUC America, validates a student's foundational ability to safely operate FANUC industrial robots, including basic programming, startup, and shutdown procedures. As industrial automation becomes central to modern manufacturing, this credential signals readiness for entry-level robotics and automation roles. Programs typically prepare students through FANUC's authorized training curriculum, available through schools and training centers. It is an excellent fit for programs partnered with manufacturers who use robotic automation in their facilities."}, {"name": "FCR-O2 (Operator 2)", "code": "IRC-1116", "cluster": "Advanced Manufacturing", "link": "https://www.fanucamerica.com/education/nocti-certifications-robotics", "issuer": "FANUC America", "cost": "Typically costs around $2000", "accommodations": "https://www.azed.gov/sites/default/files/2019/08/Fanuc%20NOCTI%20Fact%20sheet.pdf?id=5d4b3a441dcb2512042e9879#:~:text=online%20test%20order%20is%202,requiring%20accommodations%20during%20test%20administration", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Intermediate FANUC robotics credential that builds on Operator 1, validating more advanced robot programming, maintenance, and troubleshooting skills.", "careerPaths": "Robotics Technician, Automation Specialist, CNC/Robotics Operator, Advanced Manufacturing Technician, Industrial Maintenance Technician", "goodFitFor": "Advanced manufacturing programs for youth who have completed FCR-O1; programs with robotics labs or FANUC equipment partnerships; workforce development programs focused on automation and advanced manufacturing careers", "detailedDesc": "The FANUC Certified Robot Operator Level 2 (FCR-O2) builds on the FCR-O1, validating a student's ability to handle more complex programming tasks, robot maintenance procedures, and advanced troubleshooting. This credential demonstrates a deeper level of proficiency in FANUC robotic systems and is recognized by manufacturers who rely on automation for production efficiency. It is best suited as a follow-on credential for youth who have already completed FCR-O1 training and are building toward roles as robotics or automation technicians. Programs should have access to FANUC hardware or certified simulators."}, {"name": "Fire Fighter I", "code": "IRC-1117", "cluster": "Public Service & Safety", "link": "https://www.mfri.org/", "issuer": "Maryland Fire and Rescue Institute", "cost": "Cost not listed for high school students.", "accommodations": "https://www.mfri.org/equity/", "effDate": "July 1, 2025", "hours": "between 3 to 6 months", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies foundational firefighting knowledge, safety procedures, and readiness for professional fire service.", "careerPaths": "Firefighter, Emergency Responder, Fire Academy Graduate, Fire Department Recruit, Public Safety Officer", "goodFitFor": "Emergency services and fire rescue career pathways; Public safety and heroic service programs; Youth interested in protective services", "detailedDesc": "This credential, issued by the Maryland Fire and Rescue Institute, validates core firefighting skills, hazard awareness, and emergency response knowledge required for entry into fire service. Fire Fighter I is essential for employment with fire departments and is respected across the state. Firefighters enjoy strong benefits, job security, and public service opportunities. Programs should clarify the fitness requirements and career pathway to Fire Fighter II and specializations."}, {"name": "Fire Fighter II", "code": "IRC-1118", "cluster": "Public Service & Safety", "link": "https://www.mfri.org/", "issuer": "Maryland Fire and Rescue Institute", "cost": "Cost not listed for high school students.", "accommodations": "https://www.mfri.org/equity/", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies advanced firefighting competencies including tactics, incident command, and specialized rescue techniques.", "careerPaths": "Firefighter, Fire Captain, Incident Commander, Hazmat Specialist, Technical Rescue Specialist", "goodFitFor": "Emergency services and advanced fire rescue career pathways; Professional development for firefighters; Public safety leadership programs", "detailedDesc": "This credential, issued by the Maryland Fire and Rescue Institute, represents advancement beyond entry-level firefighting, certifying ability to lead crews, manage incidents, and handle complex emergencies. It is required for promotion within most fire departments. Fire Fighter II holders have expanded career options in command roles, specialized teams, and fire prevention. Programs should position this as a natural progression for Fire Fighter I holders seeking advancement."}, {"name": "Forklift Operator Certificate", "code": "IRC-1119", "cluster": "Supply Chain & Transportation", "link": "https://www.nationalforkliftfoundation.com/?utm_term=forklift%20certification%20online&utm_campaign=Exact&utm_source=adwords&utm_medium=ppc&hsa_acc=8277891997&hsa_cam=9818171279&hsa_grp=102965267467&hsa_ad=644109356840&hsa_src=g&hsa_tgt=kwd-297834637596&hsa_kw=forklift%20certification%20online&hsa_mt=b&hsa_net=adwords&hsa_ver=3&gad_source=1&gad_campaignid=9818171279&gbraid=0AAAAACcgF1w6t4hcOVKOwIMZIvOIr8sT5&gclid=CjwKCAjwwqfABhBcEiwAZJjC3lcr8WF2TnIQUqGdHNIQE6CK0qbYw6P291dVqYZg8iwhfW8yOOJJsBoC1FMQAvD_BwE", "issuer": "Multiple: Must be Occupational Safety and Health Administration Approved", "cost": "The cost range from $50 to $300", "accommodations": "https://www.ada.gov/resources/testing-accommodations/", "effDate": "July 1, 2025", "hours": "1 to 4 hours for the online, OSHA-aligned, or classroom portion, with full certification often completed within one to two days", "trainingNotes": null, "prereqs": "At least 18 years old", "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies safe and proper operation of forklifts and other powered industrial trucks.", "careerPaths": "Forklift Operator, Warehouse Specialist, Material Handler, Logistics Technician", "goodFitFor": "Workforce development programs; Supply chain and distribution partnerships; Programs serving youth entering warehouse or manufacturing roles", "detailedDesc": "This OSHA-approved certification validates that operators can safely handle powered industrial trucks in warehouse and manufacturing environments. Training includes practical operation, safety procedures, and workplace compliance. The credential is highly valued by employers in logistics, manufacturing, and retail distribution. Programs can deliver this quickly (typically 1-2 days) as part of supply chain or warehousing career pathways."}, {"name": "Geographic Information System (GIS) Certification", "code": "IRC-1120", "cluster": "Energy and Natural Resources, Agriculture, Public Service & Safety", "link": "http://www.digitalquest.com/certification.html", "issuer": "Digital Quest", "cost": "Cost between $450 to $500", "accommodations": "https://www.gisci.org/Want-to-be-a-GISP/The-Exam/Accommodations#:~:text=Contact%20GISCI%20in%20advance%20of,documentation%20that%20verifies%20their%20disability.", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Certifies competency in geographic information systems (GIS) analysis, mapping, and spatial data interpretation.", "careerPaths": "GIS Analyst, Cartographer, Environmental Technician, Urban Planner, Geospatial Technician, Conservation Specialist", "goodFitFor": "Environmental science and sustainability programs; Land management or conservation-focused youth programs; STEM programs with geospatial or mapping focus", "detailedDesc": "Digital Quest's GIS certification validates practical skills in mapping, spatial analysis, and geographic information systems used in environmental management, urban planning, and natural resource sectors. GIS skills are increasingly valuable as organizations leverage location data for decision-making. Youth with GIS expertise gain access to emerging green and tech-related careers. Programs can use free GIS software like QGIS and partner with government agencies or nonprofits doing mapping work."}, {"name": "Geriatric Nursing Assistant (GNA)", "code": "IRC-1121", "cluster": "Healthcare & Human Services", "link": "https://health.maryland.gov/mbon/pages/default.aspx", "issuer": "Maryland Board of Nursing", "cost": "No fee", "accommodations": "https://www.nursingworld.org/certification/certification-policies/special-accommodations/#:~:text=The%20American%20Nurses%20Credentialing%20Center,See%20Important%20Notice%2C%20below.", "effDate": "July 1, 2025", "hours": "6 to 15 weeks to complete, involving 100\u2013150 total hours of training", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies specialized skills in caring for elderly patients and addressing age-related health needs.", "careerPaths": "Geriatric Nursing Assistant, Senior Care Assistant, Long-Term Care Assistant, Home Care Aide, Assisted Living Assistant", "goodFitFor": "Healthcare and gerontology career pathways; Aging services programs; Youth interested in senior care and compassionate work", "detailedDesc": "This credential builds on nursing assistant foundations with specialized training in dementia care, mobility assistance, and emotional support for older adults. Issued by the Maryland Board of Nursing, it opens careers in the rapidly growing senior care field. As Maryland's aging population increases, GNA positions are abundant with strong job security. Programs can partner with senior living facilities and in-home care agencies for practical experience."}, {"name": "Google Data Analytics Professional Certificate", "code": "IRC-1122", "cluster": "Digital Technology", "link": "https://www.coursera.org/professional-certificates/google-data-analytics", "issuer": "Google", "cost": "The cost is $300", "accommodations": "https://edu.google.com/our-values/accessibility/#:~:text=files%20to%20video.-,Google%20Workspace%20for%20Education%20Features,Learn%20More", "effDate": "July 1, 2025", "hours": "3\u20136 months, assuming a pace of 10 hours of study per week", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": "We Love Philly", "oneLiner": "Certifies foundational and intermediate data analytics skills using Google tools and methodologies.", "careerPaths": "Data Analyst, Business Intelligence Specialist, Marketing Analyst, Operations Analyst", "goodFitFor": "STEM-focused programs; College preparation and career readiness initiatives; Technology and digital skills programs", "detailedDesc": "Google's Data Analytics Professional Certificate validates skills in data collection, visualization, and analysis using industry-standard tools. The course covers data cleaning, statistical analysis, and presentation\u2014core competencies for modern careers. This globally recognized credential opens pathways to entry-level analytics roles and demonstrates digital literacy. Programs appreciate Google's self-paced format and affordable pricing structure."}, {"name": "Hairstylist License", "code": "IRC-1123", "cluster": "Healthcare & Human Services", "link": "https://www.labor.maryland.gov/license/cos/cosexam.shtml", "issuer": "Maryland Department of Labor", "cost": "The cost is $77 Practical & Theory", "accommodations": "https://www.ada.gov/resources/testing-accommodations/#who-is-eligible-to-receive-testing-accommodations", "effDate": "July 1, 2025", "hours": "9 to 24 months, requiring 1,000 to 1,500+ hours of education", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies completion of hairstyling training and passage of Maryland state licensing examination.", "careerPaths": "Hairstylist, Hair Cutter, Salon Specialist, Hair Color Specialist, Salon Manager", "goodFitFor": "Beauty and personal services career pathways; Entrepreneurship and small business programs; Community-based training partnerships", "detailedDesc": "This credential validates specialized skills in cutting, styling, and treating hair for diverse clients and textures. Issued by the Maryland Department of Labor, it requires specific training hours and passage of written and practical exams. Hairstylists earn competitive wages with flexibility and strong tipping potential, plus pathways to salon management or ownership. Programs should partner with beauty schools and established salons to provide mentorship."}, {"name": "Hazardous Material Operations", "code": "IRC-1124", "cluster": "Public Service & Safety", "link": "https://www.mfri.org/", "issuer": "Maryland Fire and Rescue Institute", "cost": "Cost not listed for high school students.", "accommodations": "https://www.mfri.org/equity/", "effDate": "July 1, 2025", "hours": "Often 24 hours of training (classroom or online)", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Maryland Fire and Rescue Institute credential for emergency responders to safely operate at hazardous materials incidents at the operations level.", "careerPaths": "Firefighter, Emergency Responder, HAZMAT Technician, Environmental Emergency Responder, Safety Officer", "goodFitFor": "Programs with fire science, emergency services, or public safety career tracks; programs partnered with fire departments or emergency response agencies; pre-apprenticeship programs for fire service careers; programs serving youth 16+ interested in public safety", "detailedDesc": "The Hazardous Material Operations credential, offered through the Maryland Fire and Rescue Institute (MFRI), certifies emergency responders to operate at the perimeter of hazardous materials incidents, take defensive actions, and support HAZMAT technicians. It is required for firefighters and emergency responders who may encounter hazardous materials at emergency scenes. This credential is best suited for programs actively building fire service or emergency response career pathways and ideally delivered in partnership with local fire departments or emergency management agencies."}, {"name": "Hazardous Materials Handler Certification", "code": "IRC-1125", "cluster": "Supply Chain & Transportation", "link": "https://www.oshaeducationcenter.com/hazmat/dot-hazmat/#:~:text=About%20DOT%20HAZMAT%20Transportation:%20All,Certified%20Safety%20Professionals%20(BCSP).", "issuer": "Multiple: Must be Department of Transportation Approved", "cost": "The cost range from $30 to $100", "accommodations": "https://mva.maryland.gov/about-mva/Pages/Persons-With-Disabilities.aspx", "effDate": "July 1, 2025", "hours": "3 to 40+ hours depending on the regulation (DOT vs. OSHA) and role complexity. Basic DOT awareness training takes 3\u20134 hours, while comprehensive, job-specific training often requires 7\u20138 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies knowledge of hazardous materials identification, handling, storage, and transportation regulations.", "careerPaths": "Hazmat Handler, Transportation Specialist, Warehouse Manager, Safety Compliance Officer", "goodFitFor": "Workforce development and supply chain programs; Transportation career pathways; Manufacturing or chemical handling partnerships", "detailedDesc": "This DOT-approved credential validates understanding of hazardous materials regulations, safety procedures, and proper documentation for handling and transporting dangerous goods. It's essential for careers in transportation, chemical manufacturing, and industrial supply. The certification demonstrates regulatory compliance and safety awareness critical in many industries. Programs should emphasize real-world scenarios and regulatory updates as DOT rules frequently change."}, {"name": "Hospitality & Tourism Specialist Exam", "code": "IRC-1126", "cluster": "Hospitality, Events, and Tourism", "link": "https://ahlei.servsafebrands.com/training-and-certification-overview", "issuer": "American Hotel & Lodging Educational Institute", "cost": "The cost is $87", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations", "effDate": "July 1, 2025", "hours": "one- to two-year (approx. 360-hour) curriculum for high school students", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates foundational knowledge of hospitality operations, customer service, and tourism industry practices.", "careerPaths": "Front Desk Agent, Guest Services Specialist, Reservation Agent, Hotel Staff, Hospitality Associate", "goodFitFor": "Hospitality and hotel management career pathways; Customer service and tourism programs; Event and leisure programs", "detailedDesc": "This credential, issued by the American Hotel & Lodging Educational Institute, tests knowledge of hotel operations, guest relations, communication, and hospitality fundamentals. It provides a recognized starting point for hotel and resort careers with potential advancement to management. The credential is portable across the national hospitality industry, valuable as travel and tourism rebound. Programs should partner with hotels, resorts, and tourism venues for real-world training."}, {"name": "I-CAR Aluminum GMA (MIG) Welding Certificate", "code": "IRC-1127", "cluster": "Supply Chain & Transportation", "link": "https://www.i-car.com/", "issuer": "Inter-Industry Conference on Auto Collision Repair  (I-CAR)", "cost": "Cost is $1495 for Aluminum GMA Welding certification", "accommodations": "https://ed.sc.gov/instruction/career-and-technical-education/performance-accountability/career-and-technical-education-technical-skill-assessments/i-car-testing-information-form/#:~:text=What%20accommodations%20do%20you%20routinely,CAR%20or%20the%20proctor%20/%20instructor.", "effDate": "July 1, 2025", "hours": "6-hour to 8-hour, one-day, in-person, hands-on training session, often preceded by online or theoretical prerequisites", "trainingNotes": null, "prereqs": "Often requires completion of \"Aluminum GMA (MIG) Welding Theory\" beforehand, followed by the practical, in-shop training.", "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies ability to perform aluminum gas metal arc (GMA/MIG) welding to automotive and construction standards.", "careerPaths": "Automotive Body Repair Technician, Welding Technician, Sheet Metal Worker, Collision Repair Specialist, Aluminum Welding Specialist", "goodFitFor": "Welding and metal fabrication career pathways; Automotive collision repair programs; Supply chain and manufacturing skills programs", "detailedDesc": "This credential, issued by I-CAR (Inter-Industry Conference on Auto Collision Repair), validates aluminum welding skills critical for modern automobile repair where lightweight aluminum is increasingly used. It's required by many collision repair shops and leads to strong-paying technical careers. As automotive technology evolves, aluminum welding skills are in high demand with good wages and job stability. Programs should provide hands-on practice with proper ventilation and safety equipment."}, {"name": "I-CAR Non-Structural Technician Platinum ProLevel 1 Credential", "code": "IRC-1128", "cluster": "Supply Chain & Transportation", "link": "https://www.i-car.com/", "issuer": "Inter-Industry Conference on AutoCollision Repair      (I-CAR)", "cost": "Per student fee is $50 for the Intro. To Collision Repair Series", "accommodations": "https://ed.sc.gov/instruction/career-and-technical-education/performance-accountability/career-and-technical-education-technical-skill-assessments/i-car-testing-information-form/#:~:text=What%20accommodations%20do%20you%20routinely,CAR%20or%20the%20proctor%20/%20instructor.", "effDate": "July 1, 2025", "hours": "The full Non-Structural PL1 learning plan involves roughly 17 hours of coursework.", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Entry-level I-CAR credential validating foundational skills in non-structural vehicle collision repair, including panel replacement and cosmetic damage repair.", "careerPaths": "Auto Body Technician, Collision Repair Technician, Non-Structural Repair Specialist, Auto Refinish Technician, Automotive Service Technician", "goodFitFor": "Programs with automotive or collision repair career tracks; programs partnered with auto body shops or dealerships; workforce development programs serving youth interested in skilled trades; pre-apprenticeship programs in the automotive sector", "detailedDesc": "The I-CAR Non-Structural Technician Platinum ProLevel 1 credential from the Inter-Industry Conference on Auto Collision Repair validates a student's entry-level competency in non-structural collision repair, covering panel replacement, cosmetic damage assessment, and basic repair techniques. I-CAR credentials are the gold standard in the collision repair industry and are recognized by dealerships, insurance companies, and independent auto body shops nationwide. Preparation requires completing I-CAR ProLevel 1 training modules and hands-on skill demonstrations. This credential is ideal for programs with automotive shops or partnerships with local collision repair businesses."}, {"name": "I-CAR Refinish Technician Platinum ProLevel 1 Credential", "code": "IRC-1129", "cluster": "Supply Chain & Transportation", "link": "https://www.i-car.com/", "issuer": "Inter-Industry Conference on Auto Collision Repair     (I-CAR)", "cost": "ProLevel 1 certificate costs is $499", "accommodations": "https://ed.sc.gov/instruction/career-and-technical-education/performance-accountability/career-and-technical-education-technical-skill-assessments/i-car-testing-information-form/#:~:text=What%20accommodations%20do%20you%20routinely,CAR%20or%20the%20proctor%20/%20instructor.", "effDate": "July 1, 2025", "hours": "9 hours and 15 minutes of training time", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies advanced refinishing skills including color mixing, application techniques, and quality standards for vehicle repair.", "careerPaths": "Refinish Technician, Collision Repair Specialist, Paint Technician, Quality Control Inspector", "goodFitFor": "Automotive and collision repair programs; Trade-focused afterschool partnerships; Programs connected with body shop employers", "detailedDesc": "This I-CAR credential validates professional-level paint and refinish skills for collision repair. The Platinum ProLevel 1 demonstrates competency in modern refinishing techniques, safety protocols, and quality assurance. Issued by I-CAR (Insurance Institute for Highway Safety), it's recognized nationwide by collision repair shops and insurers. Programs benefit from I-CAR's curriculum resources and industry-aligned standards."}, {"name": "I-CAR Steel GMA Welding Certificate", "code": "IRC-1130", "cluster": "Supply Chain & Transportation", "link": "https://www.i-car.com/", "issuer": "Inter-Industry Conference on Auto Collision Repair     (I-CAR)", "cost": "Certification costs is $235", "accommodations": "https://ed.sc.gov/instruction/career-and-technical-education/performance-accountability/career-and-technical-education-technical-skill-assessments/i-car-testing-information-form/#:~:text=What%20accommodations%20do%20you%20routinely,CAR%20or%20the%20proctor%20/%20instructor.", "effDate": "July 1, 2025", "hours": "4-hour hands-on training and testing session", "trainingNotes": null, "prereqs": "Participants often take the 1-hour \"Steel GMA Welding Theory\" course before attempting the hands-on certification.", "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies proficiency in steel gas metal arc (GMA/MIG) welding for automotive and structural applications.", "careerPaths": "Automotive Technician, Welder, Fabrication Technician, Collision Repair Technician, Manufacturing Technician", "goodFitFor": "Welding and metal fabrication career pathways; Automotive repair and maintenance programs; Manufacturing and industrial skills programs", "detailedDesc": "This credential, issued by I-CAR, demonstrates steel MIG welding competency for automotive collision repair and structural welding applications. Steel welding is foundational to many trades and manufacturing sectors. Youth with this credential earn solid wages in automotive shops, fabrication facilities, and construction. Programs should emphasize safety protocols and proper equipment use alongside hands-on skill development."}, {"name": "ICS-100.C (Introduction to the Incident Command System); IS-200.C (Basic Incident Command System for Initial Response); S-700.B (Introduction to the National Incident Management System)", "code": "IRC-1131", "cluster": "Public Service & Safety", "link": "https://cdp.dhs.gov/femasid#:~:text=a%20FEMA%20SID?-,FEMA%20Student%20Identification%20(SID)%20number%20is%20a%20unique%20number%20generated,will%20be%20emailed%20to%20you.", "issuer": "National Disaster and Emergency Management University - Department of Homeland Security - FEMA", "cost": "Free to all test-takers", "accommodations": "https://training.fema.gov/iemc/accommodation.aspx", "effDate": "July 1, 2025", "hours": "approximately 10\u201314 hours, usually taken as self-paced, online courses", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "FEMA's foundational emergency management bundle covering incident command structures, first response protocols, and national disaster management systems.", "careerPaths": "Emergency Manager, First Responder, Public Safety Officer, Disaster Relief Coordinator, Public Health Emergency Worker, Military Personnel", "goodFitFor": "Programs with public safety, emergency management, or government career tracks; community-based programs interested in building youth emergency preparedness knowledge; programs partnered with FEMA, homeland security agencies, or emergency management offices; broadly accessible as online certifications", "detailedDesc": "This credential bundle\u2014ICS-100 (Introduction to Incident Command), IS-200 (Basic Incident Command for Initial Response), and IS-700 (Introduction to NIMS)\u2014is offered free online through FEMA's Emergency Management Institute and establishes the foundational framework for how emergency responders coordinate during disasters. These credentials are required for virtually all public safety and emergency management personnel and are increasingly valued in government, healthcare, and nonprofit disaster response roles. Because all three can be completed online at no cost, they are highly accessible for a wide range of OST programs as a supplement to other public safety credentials."}, {"name": "IEC Chesapeake Electrical Pre-Apprenticeship", "code": "IRC-1132", "cluster": "Construction", "link": "https://www.iecchesapeake.com", "issuer": "IEC Chesapeake", "cost": null, "accommodations": null, "effDate": "July 1, 2025", "hours": "160 to 200-hour training course designed to prepare individuals for entry-level electrical careers", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates competency in electrical fundamentals and safety required to enter union electrical apprenticeships.", "careerPaths": "Electrician, Residential Electrician, Commercial Electrician, Industrial Electrician, Electrical Apprentice, Maintenance Electrician", "goodFitFor": "Apprenticeship preparation programs; Union-partnered workforce development programs; Construction career pathways for youth ages 16+", "detailedDesc": "IEC Chesapeake's pre-apprenticeship curriculum covers electrical theory, safety, tools, and basic wiring to meet union electrical standards in the Chesapeake region and beyond. Graduates are positioned to apply for paid apprenticeships where they earn while completing on-the-job training. This credential bridges the gap between high school and skilled trades, opening pathways to union membership and strong career security. Programs should connect with local IEC chapters and union electrical contractors to ensure placement support."}, {"name": "IT Specialist: Cybersecurity", "code": "IRC-1133", "cluster": "Digital Technology", "link": "https://www.cisco.com/site/us/en/learn/training-certifications/certifications/cybersecurity/index.html", "issuer": "Cisco", "cost": "Starting at $470", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "120 hours of, or roughly 2-3 months of, dedicated study for entry-level roles", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": "Pass IT On", "oneLiner": "Certifies foundational cybersecurity knowledge and skills aligned with industry standards and job readiness.", "careerPaths": "Cybersecurity Analyst, IT Security Specialist, Network Security Technician, Security Operations Technician", "goodFitFor": "STEM and computer science programs; Workforce development partnerships; College preparation initiatives in tech fields", "detailedDesc": "Cisco's IT Specialist: Cybersecurity credential validates essential knowledge in network security, threat identification, and defense strategies. It introduces youth to cybersecurity career pathways and demonstrates foundational competency employers seek. The credential is aligned with the NIST cybersecurity framework and industry best practices. Programs benefit from Cisco's educational resources and connections to IT employer networks."}, {"name": "IT Specialist: Databases", "code": "IRC-1134", "cluster": "Digital Technology", "link": "https://certiport.pearsonvue.com/Certifications/ITSpecialist/Certification/Overview.aspx", "issuer": "Certiport", "cost": "Ranges from $245 to $326", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "16 to 40 hours of primary course content, often completed in 1\u20133 months", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Certiport credential validating foundational skills in database design, management, and querying using SQL and relational database concepts.", "careerPaths": "Database Administrator (entry), Data Analyst, IT Support Specialist, Business Intelligence Analyst, Software Developer", "goodFitFor": "Technology pathway programs for high school youth; STEM afterschool programs with data or programming tracks; programs partnered with tech or data-driven employers; summer coding or data science intensives", "detailedDesc": "The IT Specialist: Databases credential, offered through Certiport, validates a student's understanding of relational database concepts, SQL queries, data modeling, and database administration fundamentals. As data becomes foundational to every industry, database skills are among the most transferable in the technology sector. This credential is a strong entry point for youth interested in data analysis, software development, or IT administration careers. It pairs well with other IT Specialist credentials and introductory programming certifications."}, {"name": "IT Specialist: Java", "code": "IRC-1135", "cluster": "Digital Technology", "link": "https://certiport.pearsonvue.com/Certifications/ITSpecialist/Certification/Overview.aspx", "issuer": "Certiport", "cost": "Exam voucher cost is $133", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "40 to 150+ hours of study, typically spanning 4 days for accelerated courses to 3-6 months for self-paced learning", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies proficiency in Java programming and object-oriented development fundamentals.", "careerPaths": "Java Developer, Software Developer, Application Developer, Junior Programmer, Software Engineer, Web Developer", "goodFitFor": "Computer science and coding-focused youth programs; STEM pipelines with software development focus; Afterschool programs for older youth interested in tech careers", "detailedDesc": "CompTIA's IT Specialist Java credential validates practical programming skills in one of the most widely used languages across enterprise applications, web development, and Android app development. This Certiport credential demonstrates employer-recognized coding competency and is stackable with other IT Specialist credentials. Youth earning Java certification are prepared for developer roles or further computer science education. Programs should use accessible IDEs and real coding projects to teach practical skills."}, {"name": "IT Specialist: Network Security", "code": "IRC-1136", "cluster": "Digital Technology", "link": "https://certiport.pearsonvue.com/Certifications/ITSpecialist/Certification/Overview.aspx", "issuer": "Certiport", "cost": "Exam voucher cot is $133", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "between 6 weeks to 9 months", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates competency in network security principles, protocols, and defensive technologies.", "careerPaths": "Network Security Analyst, IT Security Specialist, Systems Security Engineer, Network Administrator, Security Technician, IT Security Officer", "goodFitFor": "Cybersecurity-focused programs; IT and technology career pathways; Corporate or government workforce development programs with security focus", "detailedDesc": "CompTIA's IT Specialist Network Security credential covers firewalls, intrusion detection, encryption, and security protocols essential for protecting modern networks. This Certiport certification demonstrates practical network defense knowledge and complements broader certifications like Security+. Youth with this credential show specialized security skills that employers value highly. Programs should include hands-on lab exercises with network simulation software and real-world security scenarios."}, {"name": "IT Specialist: Networking", "code": "IRC-1137", "cluster": "Digital Technology", "link": "https://certiport.pearsonvue.com/Certifications/ITSpecialist/Certification/Overview.aspx", "issuer": "Certiport", "cost": "Ranges from $133 to $151", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "25 hours of, primary training content. While some accelerated, instructor-led courses take 3 days, comprehensive preparation often involves, 150 hours of instruction or hands-on experience", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": "Pass IT On", "oneLiner": "Certiport credential that certifies foundational knowledge of networking concepts, protocols, and infrastructure setup.", "careerPaths": "Network Support Technician, IT Help Desk Specialist, Network Administrator, Systems Administrator (entry-level)", "goodFitFor": "STEM and technology afterschool programs; programs with IT career tracks serving high school youth; summer coding or tech intensives; programs partnered with telecom or IT employers", "detailedDesc": "The IT Specialist: Networking credential, offered through Certiport, validates a student's understanding of networking fundamentals including protocols, IP addressing, routing concepts, and basic network security. Core preparation content can be covered in approximately 25 hours, though comprehensive readiness may require additional hands-on practice. This credential is recognized by employers seeking entry-level IT support staff and aligns closely with industry networking standards. It is a strong foundation-level certification for youth pursuing careers in IT infrastructure."}, {"name": "IT Specialist: Python", "code": "IRC-1138", "cluster": "Digital Technology", "link": "https://certiport.pearsonvue.com/Certifications/ITSpecialist/Certification/Overview.aspx", "issuer": "Certiport", "cost": "The cost is $133", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "Approximately 24 hours of core content. Accelerated 4-day bootcamps are also available", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies proficiency in Python programming, data structures, and automation fundamentals.", "careerPaths": "Python Developer, Automation Engineer, Data Analyst, Software Developer, Systems Administrator, Machine Learning Engineer", "goodFitFor": "STEM programs with computer science focus; Data science or analytics programs; Workforce development programs emphasizing automation and coding", "detailedDesc": "CompTIA's IT Specialist Python credential validates one of the most in-demand programming languages, used across web development, data science, automation, and artificial intelligence. This Certiport certification is ideal for youth exploring coding careers and creates pathways to specialized fields like data science and machine learning. Python's readability and versatility make it excellent for youth learners. Programs can use free tools and emphasize real-world automation projects to keep learning practical."}, {"name": "Law and Public Safety Introductory Level Competency", "code": "IRC-1139", "cluster": "Public Service & Safety", "link": "https://lapsen.org/lpsilc-2/", "issuer": "Law and Public Safety Education Network (LAPSEN)", "cost": "LAPSEN members $16 and non-members $20", "accommodations": "https://lapsen.org/student-certification/", "effDate": "July 1, 2025", "hours": "20-40 hours of class time for high school students", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Entry-level competency credential from LAPSEN validating foundational knowledge across law enforcement, corrections, security, and emergency services fields.", "careerPaths": "Law Enforcement Officer (pathway), Security Officer, Corrections Officer (pathway), Emergency Services Worker, Criminal Justice Professional", "goodFitFor": "Programs with criminal justice or public safety career tracks; programs serving youth exploring public safety careers broadly; programs partnered with law enforcement, security, or corrections employers; community-based programs focused on justice and public safety", "detailedDesc": "The Law and Public Safety Introductory Level Competency credential, issued by the Law and Public Safety Education Network (LAPSEN), establishes baseline knowledge across the law and public safety sector including law enforcement, fire service, emergency medical services, corrections, and security. It is designed as an entry point for students beginning their exploration of public safety careers. This broad credential is a strong fit for programs that introduce youth to multiple public safety career pathways before specializing in a specific area such as law enforcement, fire, or EMS."}, {"name": "Leadership in Energy and Environmental Design (LEED) Green Associate Credential", "code": "IRC-1140", "cluster": "Construction", "link": "https://www.usgbc.org/credentials/leed-green-associate", "issuer": "U.S. Green Building Council (USGBC)", "cost": "The cost falls between $640 and $1000", "accommodations": "https://support.usgbc.org/hc/en-us/articles/6826338507155-Exam-Preparation#:~:text=Each%20request%20is%20evaluated%20individually,exam%20to%20a%20translated%20exam.", "effDate": "July 1, 2025", "hours": "30 to 50 hours of total preparation, typically spread over 2 to 6 weeks", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Entry-level green building credential from the U.S. Green Building Council validating knowledge of sustainable design, construction, and building operations.", "careerPaths": "Green Building Specialist, Sustainability Coordinator, Construction Project Manager (entry), Facilities Manager, Environmental Consultant", "goodFitFor": "Programs with construction, sustainability, or environmental career tracks; programs in communities focused on green infrastructure or climate resilience; STEM programs with environmental science or engineering components; programs partnered with construction or real estate employers", "detailedDesc": "The LEED Green Associate credential, issued by the U.S. Green Building Council (USGBC), validates foundational knowledge of green building principles, LEED rating systems, and sustainable design practices. As the construction and real estate industries shift toward sustainability, this credential is increasingly valued by employers in architecture, engineering, construction management, and facilities operations. Preparation typically takes 40\u201360 hours of study. This credential is a strong fit for OST programs that connect youth to careers in the built environment and can be particularly meaningful in communities addressing climate resilience and environmental justice."}, {"name": "LPI Linux Essentials", "code": "IRC-1141", "cluster": "Digital Technology", "link": "https://www.lpi.org/our-certifications/linux-essentials-overview/", "issuer": "Linux Professional Institute (LPI)", "cost": "The cost is $120", "accommodations": "https://www.pearsonvue.com/us/en/test-takers/accommodations/select-program.html", "effDate": "July 1, 2025", "hours": "1 to 4 weeks of study, requiring roughly 15 to 30 hours of focused preparation for beginners", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Entry-level Linux certification validating foundational knowledge of the Linux operating system, command-line basics, and open-source concepts.", "careerPaths": "Linux System Administrator (entry), IT Support Specialist, DevOps Engineer (entry), Cloud Engineer (entry), Cybersecurity Analyst", "goodFitFor": "Technology pathway programs for high school youth; coding and IT afterschool programs; programs with cybersecurity or cloud computing tracks; programs partnered with open-source technology or Linux-based employers", "detailedDesc": "The LPI Linux Essentials certification, issued by the Linux Professional Institute, validates foundational knowledge of the Linux operating system including command-line navigation, file management, scripting basics, and open-source software concepts. Linux is the operating system of the internet and cloud infrastructure, making Linux skills highly valuable for careers in system administration, cloud computing, and cybersecurity. This entry-level credential requires approximately 40\u201360 hours of preparation and is a strong gateway to more advanced LPI certifications. It pairs well with cloud credentials (AWS, Azure) and CompTIA Linux+."}, {"name": "Magnet Certified Forensics Examiner (MCFE)", "code": "IRC-1142", "cluster": "Digital Technology", "link": "https://training.magnetforensics.com/w/courses/64-magnet-certified-forensics-examiner-mcfe", "issuer": "Magnet Forensics", "cost": "The cost is free for those that have completed the prerequisite training courses.", "accommodations": "https://www.magnetforensics.com/accessibility/", "effDate": "July 1, 2025", "hours": "3-4 day, 24-32 hour, instructor-led, or equivalent self-paced, course", "trainingNotes": null, "prereqs": "To be eligible, you must complete one of the following training courses: AX200 (Magnet AXIOM Examinations), CY200 (Cloud Investigations), or BCERT (Magnet Basics)", "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies expertise in digital forensics examination and evidence handling using Magnet tools and methodologies.", "careerPaths": "Digital Forensics Examiner, Cybercrime Investigator, IT Forensics Specialist, Evidence Technician", "goodFitFor": "STEM programs focused on criminal justice; Law enforcement and public service partnerships; Advanced technology programs for older youth", "detailedDesc": "Magnet Certified Forensics Examiner (MCFE) validates advanced skills in digital investigation, evidence collection, and chain of custody procedures. This credential demonstrates readiness for forensics roles in law enforcement, cybersecurity, and legal investigations. Issued by Magnet Forensics, a recognized leader in digital forensics software, it carries significant industry weight. Programs should target motivated older youth (ages 17-21) with strong technical foundations."}, {"name": "Maintenance and Light Repair G1", "code": "IRC-1143", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/dates-fees-test-times", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The cost is $59, plus $34 registration fee, for a total of $93", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": "two years of on-the-job training. Training programs often last 18\u201324 weeks", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies entry-level automotive maintenance and light repair competencies for basic service work.", "careerPaths": "Automotive Service Technician, Maintenance Technician, Light Repair Specialist, Quick Lube Technician, Vehicle Care Assistant", "goodFitFor": "Automotive maintenance and light repair career pathways; Entry-level vehicle service programs; Youth beginning automotive trades", "detailedDesc": "This credential, issued by ASE (National Institute for Automotive Service Excellence), validates basic maintenance and light repair skills including tire service, fluid changes, and simple adjustments. It's the gateway ASE credential for youth new to automotive work. G1 holders can work independently on basic tasks and earn entry-level wages while pursuing advanced certifications. Programs should provide practical experience in working automotive service bays."}, {"name": "Manual Transmission and Transaxle Repair", "code": "IRC-1144", "cluster": "Supply Chain & Transportation", "link": "https://www.newfordtech.com/programs#:~:text=OUR%20PROGRAMS,The%20FACT%20Program", "issuer": "Ford Motor Company", "cost": "Cost varies", "accommodations": "https://www.newfordtech.com/", "effDate": "July 1, 2025", "hours": "between one to two years", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies competency in manual transmission diagnosis, repair, and assembly for Ford vehicles.", "careerPaths": "Transmission Technician, Automotive Technician, Drivetrain Specialist, Ford Service Technician, Repair Specialist", "goodFitFor": "Advanced automotive career pathways; Manufacturer-specific training and certification programs; Youth with mechanical aptitude", "detailedDesc": "This credential, issued by Ford Motor Company, certifies specific competency in Ford manual transmission systems through hands-on training and testing. Ford technicians gain manufacturer recognition and advancement within Ford dealerships nationwide. Manual transmission expertise is valuable across light-duty and commercial vehicles. Programs partnering with Ford dealerships can offer authentic training environments and potential employment pathways."}, {"name": "Medical Administrative Specialist (CMAS)", "code": "IRC-1145", "cluster": "Healthcare & Human Services", "link": "https://americanmedtech.org/medical-administrative-specialist", "issuer": "American Medical Technologists (AMT)", "cost": "The fee is $125", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations", "effDate": "July 1, 2025", "hours": "4 to 10 months", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates medical office administration, clinical support, and patient-centered care coordination skills.", "careerPaths": "Medical Administrative Specialist, Medical Office Manager, Patient Coordinator, Medical Records Specialist, Billing Specialist", "goodFitFor": "Healthcare administrative career pathways; Office management and professional services programs; Medical facility partnership programs", "detailedDesc": "This credential, issued by American Medical Technologists (AMT), tests comprehensive knowledge of medical office procedures, EHR systems, insurance, and patient communication. It combines administrative and light clinical knowledge, making it valuable for medical office coordinators. CMAS holders earn solid wages with growth into supervisory roles. Programs should integrate computer skills training with healthcare office simulations and placements."}, {"name": "Medical Assistant (RMA)", "code": "IRC-1146", "cluster": "Healthcare & Human Services", "link": "https://americanmedtech.org/medical-assistant", "issuer": "American Medical Technologists (AMT)", "cost": "The fee is $120", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations", "effDate": "July 1, 2025", "hours": "9 to 12 months", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies clinical and administrative competencies to support physicians and patient care delivery.", "careerPaths": "Registered Medical Assistant, Medical Assistant, Clinical Medical Assistant, Administrative Medical Assistant, Patient Care Coordinator", "goodFitFor": "Healthcare and clinical career pathways; Comprehensive medical skills programs; Programs with physician office and clinic partnerships", "detailedDesc": "This credential, issued by American Medical Technologists (AMT), validates both clinical skills (vital signs, EKGs, phlebotomy basics) and administrative competencies (scheduling, records, insurance). It's one of the most versatile healthcare entry credentials, opening roles across medical specialties. RMA positions offer steady employment, competitive pay, and clear advancement to nursing or medical specialization. Programs must provide hands-on clinical practice in real medical settings."}, {"name": "Microsoft Certified: Azure Fundamentals", "code": "IRC-1147", "cluster": "Digital Technology", "link": "https://learn.microsoft.com/en-us/credentials/certifications/azure-fundamentals/?practice-assessment-type=certification", "issuer": "Microsoft", "cost": "The cost is $99", "accommodations": "https://learn.microsoft.com/en-us/credentials/certifications/accommodations", "effDate": "July 1, 2025", "hours": "3\u20134 weeks for beginners. Total study time is estimated at 15\u201330 hours, with condensed training available in 1\u20132 days", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": "Pass IT On", "oneLiner": "Microsoft's foundational cloud computing credential validating knowledge of Azure services, cloud concepts, and basic cloud architecture.", "careerPaths": "Cloud Support Specialist, IT Support Analyst, Cloud Administrator (entry), DevOps Engineer (entry), Systems Analyst", "goodFitFor": "Technology pathway programs serving older high school youth (16\u201321); programs with IT or cybersecurity tracks; organizations partnered with tech employers or community colleges offering IT pathways", "detailedDesc": "The Microsoft Certified: Azure Fundamentals (AZ-900) is an entry-level cloud computing credential that validates understanding of cloud concepts, Azure services, pricing, compliance, and security basics. It requires 15\u201330 hours of study and can be prepared for in condensed 1\u20132 day bootcamp formats or over 3\u20134 weeks of self-paced learning. As cloud computing becomes central to virtually every industry, this credential helps youth demonstrate readiness for technology roles in businesses of all sizes. It is a strong complement to other IT certifications like CompTIA A+ or Security+."}, {"name": "Microsoft Office Associate", "code": "IRC-1148", "cluster": "Management and Entrepreneurship", "link": "https://learn.microsoft.com/en-us/credentials/certifications/microsoft-office-specialist-associate-2019/", "issuer": "Microsoft", "cost": "The cost is $100 per exam", "accommodations": "https://learn.microsoft.com/en-us/credentials/certifications/accommodations", "effDate": "July 1, 2025", "hours": "40 to 150+ hours of study, often spanning a few weeks to six months", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates proficiency in Microsoft Office applications including Word, Excel, or PowerPoint for workplace productivity tasks.", "careerPaths": "Administrative Assistant, Office Manager, Data Entry Specialist, Executive Assistant, Business Analyst, Customer Service Representative", "goodFitFor": "Broadly applicable to nearly any OST program serving high school youth; especially valuable for workforce development programs, programs focused on business/administrative careers, and programs in communities with high employer demand for office skills", "detailedDesc": "The Microsoft Office Specialist (MOS) Associate certification validates a student's proficiency in Microsoft Office applications\u2014Word, Excel, or PowerPoint\u2014at a level recognized by employers across virtually every industry. It is one of the most accessible and broadly relevant credentials available to youth, with exams available for individual applications. Microsoft Office skills are required in the majority of white-collar and administrative jobs, making this credential a practical addition to almost any youth workforce development program. Preparation can be completed in as few as 10\u201320 hours per application."}, {"name": "Nail Technician", "code": "IRC-1149", "cluster": "Hospitality, Events, and Tourism", "link": "https://www.labor.maryland.gov/license/cos/cosexam.shtml", "issuer": "Maryland Department of Labor", "cost": "Practical and Theory - $77", "accommodations": "https://www.ada.gov/resources/testing-accommodations/#who-is-eligible-to-receive-testing-accommodations", "effDate": "July 1, 2025", "hours": "3 to 9 months", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies competency in nail care services and salon professionalism through Maryland state licensing.", "careerPaths": "Nail Technician, Manicurist, Pedicurist, Nail Specialist, Salon Professional", "goodFitFor": "Beauty and personal services career pathways; Entrepreneurship and business ownership programs; Community-based service training", "detailedDesc": "This credential, issued by the Maryland Department of Labor, certifies skills in manicure, pedicure, nail art, and sanitation through classroom and practical training (typically 350 hours). Nail technicians have low barriers to entry, strong earning potential with tips, and easy transition to salon management or chair rental. The field welcomes diverse backgrounds and offers flexible scheduling. Programs should partner with nail salons and beauty schools for hands-on mentorship."}, {"name": "National Basic 9-1-1 Dispatch Certification", "code": "IRC-1150", "cluster": "Public Service & Safety", "link": "https://lapsen.org/neci911/", "issuer": "Law and Public Safety Education Network (LAPSEN)", "cost": "LAPSEN members $50 and non-members $75", "accommodations": "https://lapsen.org/student-certification/", "effDate": "July 1, 2025", "hours": "40 hours to complete", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates foundational knowledge and skills required to work as an emergency communications dispatcher in a 9-1-1 public safety answering point.", "careerPaths": "Emergency Dispatcher, 9-1-1 Call Taker, Public Safety Telecommunicator, Emergency Communications Specialist", "goodFitFor": "Programs with public safety or emergency communications career tracks; programs partnered with county or city emergency communications centers (9-1-1 centers); programs serving youth 18+ interested in emergency services careers; workforce development programs with public safety employer partnerships", "detailedDesc": "The National Basic 9-1-1 Dispatch Certification, issued by LAPSEN, validates the knowledge and communication skills needed to work as a public safety dispatcher, including call taking protocols, prioritizing emergencies, dispatching resources, and using communications equipment. Dispatchers are a critical but often overlooked part of the public safety workforce, and this credential provides a direct pathway into a stable, well-paying government career. This credential is best suited for older youth (18+) and programs with strong connections to local emergency communications agencies who can provide mentorship or internship opportunities."}, {"name": "National Basic Crime Scene Investigator", "code": "IRC-1151", "cluster": "Public Service & Safety", "link": "https://lapsen.org/bcsp/", "issuer": "Law and Public Safety Education Network (LAPSEN)", "cost": "LAPSEN members $20 and non-members $25", "accommodations": "https://lapsen.org/student-certification/", "effDate": "July 1, 2025", "hours": "40-hour (one-week) intensive course", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Entry-level law enforcement credential validating foundational skills in crime scene documentation, evidence collection, and forensic investigation procedures.", "careerPaths": "Crime Scene Investigator, Evidence Technician, Law Enforcement Officer, Forensic Science Technician, Criminal Justice Professional", "goodFitFor": "Programs with criminal justice or public safety career tracks; programs partnered with law enforcement agencies; programs serving youth interested in forensic science, criminology, or public safety careers; summer law enforcement pathway programs", "detailedDesc": "The National Basic Crime Scene Investigator credential, issued by the Law and Public Safety Education Network (LAPSEN), validates foundational knowledge of crime scene investigation including evidence collection, documentation, chain of custody, and basic forensic procedures. It is designed as an entry-level credential for students entering criminal justice and forensic science pathways. This credential is a strong fit for programs with public safety career tracks and can build on existing criminal justice coursework. It aligns well with other LAPSEN credentials for youth building toward law enforcement or forensic careers."}, {"name": "National Certified Medical Assistant (NCMA)", "code": "IRC-1152", "cluster": "Healthcare & Human Services", "link": "https://www.ncctinc.com/", "issuer": "National Center for Competency Testing (NCCT)", "cost": "The exam fee is $119", "accommodations": "https://www.ncctinc.com/documents/Accommodations%20Form.pdf", "effDate": "July 1, 2025", "hours": "9 to 12 months for a certificate program", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates comprehensive medical assistant competencies recognized at the national entry level.", "careerPaths": "National Certified Medical Assistant, Medical Assistant, Clinical Support Specialist, Patient Care Technician, Administrative Medical Assistant", "goodFitFor": "Healthcare and clinical career pathways; Entry-level medical certification programs; Programs with clinic and hospital partnerships", "detailedDesc": "This credential, issued by the National Center for Competency Testing (NCCT), provides nationally-recognized certification of medical assistant skills including clinical tasks, EHR proficiency, and administrative support. NCMA is highly valued by national healthcare employers and recognized across state lines. Youth gain immediate employment eligibility in hospitals, clinics, and specialty practices. Programs should emphasize hands-on clinical experience and electronic health record systems training."}, {"name": "National Entry Level Dental Assistant (DANB)", "code": "IRC-1153", "cluster": "Healthcare & Human Services", "link": "https://www.danb.org/exams/exam/nelda-exam", "issuer": "Dental Assisting National Board, Inc.", "cost": "The cost of initial exam is $400", "accommodations": "https://www.danb.org/exams/exam/cda-exam", "effDate": "July 1, 2025", "hours": "3 to 12 months", "trainingNotes": null, "prereqs": "Candidates must be high school graduates (or equivalent) and meet one of four pathways", "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies entry-level dental assistant knowledge and clinical readiness in chairside support.", "careerPaths": "Dental Assistant, Chairside Assistant, Dental Clinical Assistant, Sterilization Technician, Dental Support Specialist", "goodFitFor": "Health sciences and dental career pathways; Clinical skills and healthcare programs; Youth partnering with dental offices", "detailedDesc": "This credential, issued by the Dental Assisting National Board (DANB), is the national entry-level standard for dental assistants, testing knowledge of chair-side procedures, patient communication, and sterilization. It's portable across states and highly preferred by dental employers. Youth with this credential quickly find positions in private practices, community health centers, and specialty offices. Programs should partner with dental practices to provide supervised clinical experience and mentoring."}, {"name": "National ProStart Certificate of Achievement", "code": "IRC-1154", "cluster": "Hospitality, Events, and Tourism", "link": "https://myprostart.chooserestaurants.org/Students/Curriculum", "issuer": "National Restaurant Association", "cost": "Level 1 & 2 - $17.97 each", "accommodations": "https://assets-002.noviams.com/novi-file-uploads/ram/pdfs_and_documents/Prostart_Teachers/prostart_examadmin_hndbk-7fd4f31f.pdf", "effDate": "July 1, 2025", "hours": "two-year high school curriculum", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates foundational food safety, restaurant operations, and hospitality readiness for entry-level positions.", "careerPaths": "Line Cook, Kitchen Staff, Server, Prep Cook, Restaurant Assistant", "goodFitFor": "Hospitality, food service, and restaurant management career pathways; Community-based culinary programs; Youth employment readiness programs", "detailedDesc": "This credential, issued by the National Restaurant Association through the ProStart program, covers food safety certification and restaurant operations knowledge through online and classroom training. It's a national standard recognized by restaurant employers across the country. ProStart holders are ready for immediate food service employment and have clearer advancement pathways in the restaurant industry. Programs can integrate ProStart as part of broader hospitality training."}, {"name": "Nationally Registered Paramedic", "code": "IRC-1155", "cluster": "Public Service & Safety", "link": "https://www.nremt.org/Paramedic/Certification", "issuer": "National Registry of Emergency Medical Technicians", "cost": "The exam fee is $160", "accommodations": "https://content.nremt.org/static/documents/accommodations-policy.pdf#:~:text=The%20National%20Registry%20of%20Emergency%20Medical%20Technicians,by%20the%20Americans%20with%20Disabilities%20Act%20(ADA).&text=Only%20individuals%20with%20disabilities%20who%2C%20with%20or,the%20requested%20examination%20are%20eligible%20for%20accommodations.", "effDate": "July 1, 2025", "hours": "12 to 24 months to complete, often involving 1,100 to 1,800 hours of instruction", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies advanced paramedic knowledge and critical emergency care skills at the national standard.", "careerPaths": "Paramedic, Advanced Life Support Provider, Mobile Intensive Care Technician, Critical Care Technician, Flight Paramedic", "goodFitFor": "Emergency services and advanced medical career pathways; Intensive emergency response and trauma programs; Youth with medical interest and commitment to high-stakes work", "detailedDesc": "This credential, issued by the National Registry of EMTs (NREMT), validates paramedic-level emergency care including advanced airway management, medication administration, and critical care decision-making. Paramedics earn higher salaries than EMTs and work in hospitals, ambulances, helicopters, and rescue operations. The role combines medicine with rescue and demands continuous learning. Programs should emphasize the educational commitment and prerequisite EMT certification."}, {"name": "National Law Enforcement Certification", "code": "IRC-1156", "cluster": "Public Service & Safety", "link": "https://lapsen.org/national-le-certification/", "issuer": "Law and Public Safety Education Network (LAPSEN)", "cost": "LAPSEN members $20 and non-members $25", "accommodations": "https://lapsen.org/student-certification/", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "LAPSEN's credential validating foundational knowledge and competencies required for entry into law enforcement and public safety careers.", "careerPaths": "Law Enforcement Officer (pathway), Police Cadet, Security Officer, Corrections Officer (pathway), Criminal Justice Professional", "goodFitFor": "Programs with law enforcement or criminal justice career tracks; programs partnered with police departments, sheriff's offices, or state law enforcement agencies; community-based programs focused on justice careers; programs serving youth 16+ interested in public safety", "detailedDesc": "The National Law Enforcement Certification, issued by the Law and Public Safety Education Network (LAPSEN), validates entry-level competencies in law enforcement including legal knowledge, community policing, investigations fundamentals, and professional standards. It is designed to prepare students for careers in law enforcement and public safety at the local, state, and federal levels. This credential is a strong fit for programs that provide structured criminal justice coursework and have partnerships with law enforcement agencies willing to offer ride-alongs, internships, or mentorship. It serves as a key milestone for youth on a law enforcement career pathway."}, {"name": "Natural Resource Conservation Service (NRCS) Fundamentals of Conservation & Sustainability in Agriculture", "code": "IRC-1157", "cluster": "Agriculture", "link": "https://www.icevonline.com/nrcs", "issuer": "United States Department of Agriculture Natural Resources Conservation Service", "cost": "The initial certification cost is $100 & $10 for reexamination", "accommodations": "https://www.nrcs.usda.gov/state-offices/texas/news/new-nrcs-fundamentals-of-conservation#:~:text=The%20certification%20verifies%20individuals%20have%20obtained%20exceptional,including%20soil%2C%20water%2C%20air%2C%20plants%20and%20animals.&text=The%20Fundamentals%20of%20Conservation%20&%20Sustainability%20in,that%20will%20help%20feed%20the%20growing%20world.", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies foundational knowledge of conservation practices, soil management, and sustainable agricultural stewardship.", "careerPaths": "Conservation Specialist, Soil Technician, Sustainability Consultant, Environmental Technician", "goodFitFor": "Agriculture and environmental programs; Conservation and sustainability-focused pathways; USDA partnerships and rural programs", "detailedDesc": "The USDA Natural Resources Conservation Service credential validates understanding of soil conservation, water management, and sustainable agricultural practices. Youth learn environmental stewardship principles applicable to farming and land management. The USDA-issued credential carries strong credibility with government agencies and agricultural employers. Programs can emphasize environmental and sustainability careers."}, {"name": "NCCER Core plus Level 1 Carpentry", "code": "IRC-1158", "cluster": "Construction", "link": "https://www.nccer.org/", "issuer": "National Center for Construction Education & Research (NCCER)", "cost": "The Core Level test costs $27. Level 1 varies depending on the specific program", "accommodations": "https://nccer.my.site.com/Support/s/article/TestingFAQs", "effDate": "July 1, 2025", "hours": "4 to 8 months", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": "Safe Alternative Foundation for Education Inc", "oneLiner": "Certifies foundational carpentry skills and safety knowledge as the first step toward journeyperson status.", "careerPaths": "Carpenter, Construction Technician, Framing Specialist, Finish Carpenter", "goodFitFor": "Construction career pathways; Trade apprenticeship programs; Workforce development partnerships with construction employers", "detailedDesc": "NCCER's Core plus Level 1 Carpentry validates essential skills in safety, tools, materials, and basic construction techniques. This is often the entry point to union apprenticeships and construction careers. The credential demonstrates readiness for on-site work and leads to progressively advanced certifications. Programs should emphasize the credential's pathway to well-paying union trades and career advancement."}, {"name": "NCCER Core plus Level 1 Electrical", "code": "IRC-1159", "cluster": "Construction", "link": "https://www.nccer.org/", "issuer": "National Center for Construction Education & Research (NCCER)", "cost": "The Core Level test costs $27. Level 1 varies depending on the specific program", "accommodations": "https://nccer.my.site.com/Support/s/article/TestingFAQs", "effDate": "July 1, 2025", "hours": "Programs can be compressed into 4 weeks of full-time study or stretched over 8 to 10 months of evening classes.", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies mastery of foundational construction competencies and Level 1 electrical skills including circuit basics and wiring.", "careerPaths": "Electrician, Residential Electrician, Construction Laborer, Electrical Technician, Building Systems Technician, Maintenance Technician", "goodFitFor": "Construction career pipelines; Pre-apprenticeship programs; STEM programs with skilled trades focus; Urban youth development programs", "detailedDesc": "NCCER's tiered credential system begins with a core component covering essential construction safety and then advances to Level 1 electrical topics like circuits, grounding, and residential wiring. This stackable credential creates a clear pathway to further certifications and apprenticeships while validating foundational knowledge employers require. Youth earn a nationally recognized credential that transfers across states and employers. Programs typically partner with community colleges or contractors to deliver training and proctoring."}, {"name": "NCCER Core plus Level 1 HVAC", "code": "IRC-1160", "cluster": "Construction", "link": "https://www.nccer.org/", "issuer": "National Center for Construction Education & Research (NCCER)", "cost": "The Core Level test costs $27. Level 1 varies depending on the specific program", "accommodations": "https://nccer.my.site.com/Support/s/article/TestingFAQs", "effDate": "July 1, 2025", "hours": "5\u20138 weeks for full-time, intensive courses, or up to 6\u20138 months for part-time", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies foundational construction knowledge and Level 1 HVAC skills including system basics and safety.", "careerPaths": "HVAC Technician, Heating and Cooling Technician, Refrigeration Technician, Maintenance Technician, HVAC Apprentice, Building Systems Technician", "goodFitFor": "STEM programs with mechanical systems focus; Apprenticeship preparation pathways; Workforce development programs in suburban or rural areas with construction demand", "detailedDesc": "NCCER's HVAC credential starts with construction fundamentals then progresses to Level 1 topics covering HVAC system types, components, refrigeration basics, and safety protocols. This certification demonstrates foundational readiness for HVAC apprenticeships and technician entry positions in a field with consistent demand and solid wages. The stackable design allows youth to earn credentials at their own pace and continue to advanced levels. Programs need classroom space, some equipment for demonstration, and access to testing through NCCER centers."}, {"name": "NCCER Core plus Level 1 Industrial Maintenance", "code": "IRC-1161", "cluster": "Construction", "link": "https://www.nccer.org/", "issuer": "National Center for Construction Education & Research (NCCER)", "cost": "The Core Level test costs $27. Level 1 varies depending on the specific program", "accommodations": "https://nccer.my.site.com/Support/s/article/TestingFAQs", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates construction fundamentals and Level 1 industrial maintenance competencies including lubrication, alignment, and safety.", "careerPaths": "Industrial Maintenance Technician, Maintenance Mechanic, Facility Technician, Manufacturing Technician, Equipment Technician, Apprentice Mechanic", "goodFitFor": "Manufacturing career pathways; Industrial training programs; Workforce development programs in manufacturing regions with equipment-heavy industries", "detailedDesc": "NCCER's industrial maintenance credential covers essential mechanical knowledge needed in manufacturing plants, power facilities, and industrial settings. Level 1 topics include basic equipment operation, preventative maintenance, lubrication systems, and shaft alignment\u2014skills that employers seek in entry-level technician roles. This credential is particularly valuable in regions with strong manufacturing bases where technicians are in high demand. Programs typically partner with manufacturers or community colleges to provide hands-on equipment exposure."}, {"name": "NCCER Core plus Level 1 Masonry", "code": "IRC-1162", "cluster": "Construction", "link": "https://www.nccer.org/", "issuer": "National Center for Construction Education & Research (NCCER)", "cost": "The Core Level test costs $27. Level 1 varies depending on the specific program", "accommodations": "https://nccer.my.site.com/Support/s/article/TestingFAQs", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies construction fundamentals and Level 1 masonry skills including brick laying, mortar use, and safety protocols.", "careerPaths": "Mason, Brick Mason, Stone Mason, Tile Setter, Masonry Apprentice, Construction Laborer, Restoration Specialist", "goodFitFor": "Construction career pipelines; Apprenticeship preparation programs with masonry focus; Trade-oriented youth development programs in urban areas", "detailedDesc": "NCCER's masonry credential validates essential bricklaying, stone work, and mortar techniques required in residential and commercial construction. Level 1 covers tools, materials, bonding patterns, and safety\u2014foundational knowledge needed for masonry apprenticeships where youth earn while learning. This is a skilled trade with strong demand and good earning potential, particularly in regions with active construction. Programs need workspace for practice walls and partnerships with local masonry contractors for mentorship."}, {"name": "NCCER Core plus Level 1 Plumbing", "code": "IRC-1163", "cluster": "Construction", "link": "https://www.nccer.org/", "issuer": "National Center for Construction Education & Research (NCCER)", "cost": "The Core Level test costs $27. Level 1 varies depending on the specific program", "accommodations": "https://nccer.my.site.com/Support/s/article/TestingFAQs", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates construction fundamentals and Level 1 plumbing skills including piping systems, fittings, and safety.", "careerPaths": "Plumber, Apprentice Plumber, Pipe Fitter, Plumbing Technician, Maintenance Plumber, Construction Laborer", "goodFitFor": "Construction career pathways; Apprenticeship preparation programs; Workforce development programs serving youth seeking stable skilled trades", "detailedDesc": "NCCER's plumbing credential teaches essential piping knowledge, fitting types, water systems basics, and safety required for plumbing apprenticeships. Level 1 covers materials, codes, and practical skills that entry-level plumbers must know. Plumbing is a recession-resistant trade with excellent earning potential and job security, as demand for skilled plumbers remains consistently high. Programs need classroom space and partnerships with plumbing contractors to demonstrate real systems and provide mentorship."}, {"name": "NCCER Core plus Level 1 Welding", "code": "IRC-1164", "cluster": "Construction", "link": "https://www.nccer.org/", "issuer": "National Center for Construction Education & Research (NCCER)", "cost": "The Core Level test costs $27. Level 1 varies depending on the specific program", "accommodations": "https://nccer.my.site.com/Support/s/article/TestingFAQs", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies construction fundamentals and Level 1 welding competencies including processes, techniques, and safety.", "careerPaths": "Welder, Structural Welder, Fabrication Specialist, Welding Technician, Manufacturing Technician, Welding Apprentice", "goodFitFor": "Construction and manufacturing career programs; Apprenticeship preparation pathways; Skilled trades pipelines for youth 14+", "detailedDesc": "NCCER's welding credential provides structured progression starting with core construction knowledge before advancing to welding processes and techniques. Level 1 covers safety, equipment operation, and introductory process skills that prepare youth for further specialization through AWS certifications. This stackable approach allows youth to earn multiple credentials building toward journeyman status. Programs need welding equipment, certified instructors, and space to maintain safety standards."}, {"name": "NIMS CNC Milling: Operations with Measurement, Materials & Safety", "code": "IRC-1165", "cluster": "Advanced Manufacturing", "link": "https://www.nims-skills.org/", "issuer": "National Institute for Metalworking Skills Inc. (NIMS)", "cost": "The individual fee for one-time is $40", "accommodations": "https://www.nims-skills.org/sites/default/files/media/document/Policy%20-%20Paper%20Tests%20%26%20Accommodations_0.pdf", "effDate": "July 1, 2025", "hours": "15 weeks to one year", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies ability to operate and safely use CNC milling equipment including measurement and quality control.", "careerPaths": "CNC Machinist, Manufacturing Technician, Machining Operator, Quality Control Inspector", "goodFitFor": "Advanced manufacturing programs; Machining and precision manufacturing pathways; Programs with CNC equipment access", "detailedDesc": "NIMS' CNC Milling Operations credential validates hands-on ability to set up, operate, and measure work on CNC milling machines. Youth demonstrate safety competency, measurement accuracy, and quality control. This fundamental credential is essential for machining careers in aerospace, automotive, and precision manufacturing. Programs need functional CNC milling equipment for hands-on training."}, {"name": "NIMS CNC Milling: PGM Setup & Operations with Measurement, Materials & Safety", "code": "IRC-1166", "cluster": "Advanced Manufacturing", "link": "https://www.nims-skills.org/", "issuer": "National Institute for Metalworking Skills Inc. (NIMS)", "cost": "The individual fee for one-time is $40", "accommodations": "https://www.nims-skills.org/sites/default/files/media/document/Policy%20-%20Paper%20Tests%20%26%20Accommodations_0.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies advanced CNC milling skills including programming, setup, operations, and quality assurance.", "careerPaths": "CNC Programmer, Advanced Machinist, Manufacturing Engineer, Process Technician", "goodFitFor": "Advanced manufacturing programs with programming focus; Machining career pathways; Programs serving youth with strong technical foundations", "detailedDesc": "This advanced NIMS credential validates programming and setup skills in addition to operational competency on CNC mills. Youth can independently prepare and execute complex milling jobs. The credential demonstrates readiness for higher-wage machining and engineering technician roles. Programs should target youth with solid math and problem-solving skills."}, {"name": "NIMS CNC Turning: Operations with Measurement, Materials & Safety", "code": "IRC-1167", "cluster": "Advanced Manufacturing", "link": "https://www.nims-skills.org/", "issuer": "National Institute for Metalworking Skills Inc. (NIMS)", "cost": "The individual fee for one-time is $40", "accommodations": "https://www.nims-skills.org/sites/default/files/media/document/Policy%20-%20Paper%20Tests%20%26%20Accommodations_0.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies ability to operate and safely use CNC turning equipment including measurement and material handling.", "careerPaths": "CNC Lathe Operator, Machining Technician, Manufacturing Operator, Precision Machinist", "goodFitFor": "Advanced manufacturing programs; Machining pathways; Programs with CNC turning equipment access", "detailedDesc": "NIMS' CNC Turning Operations credential validates competency in operating CNC lathes, measuring work, handling materials, and maintaining safety standards. Youth learn precision turning operations essential in manufacturing. The credential opens entry-level positions in machining and manufacturing. Programs benefit from NIMS' structured skills assessments and hands-on requirements."}, {"name": "NIMS CNC Turning: Programming Setup & Operations with Measurement, Materials & Safety", "code": "IRC-1168", "cluster": "Advanced Manufacturing", "link": "https://www.nims-skills.org/", "issuer": "National Institute for Metalworking Skills Inc. (NIMS)", "cost": "The individual fee for one-time is $40", "accommodations": "https://www.nims-skills.org/sites/default/files/media/document/Policy%20-%20Paper%20Tests%20%26%20Accommodations_0.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies advanced CNC turning skills including programming, setup, operations, and precision measurement.", "careerPaths": "CNC Programmer, Advanced Lathe Operator, Manufacturing Engineer, Process Technician", "goodFitFor": "Advanced manufacturing programs with programming focus; Precision manufacturing pathways; Programs with advanced CNC capabilities", "detailedDesc": "This advanced NIMS credential combines programming knowledge with CNC turning operations, enabling youth to independently set up and execute complex turning jobs. The credential signals advanced technical readiness and programming capability. Youth with this credential qualify for higher-wage and supervisory manufacturing positions. Programs should emphasize the programming component and advanced skill development."}, {"name": "NIMS Drill Press Skills I with Measurement, Materials & Safety exam", "code": "IRC-1169", "cluster": "Advanced Manufacturing", "link": "https://www.nims-skills.org/", "issuer": "National Institute for Metalworking Skills Inc. (NIMS)", "cost": "The individual fee for one-time is $40", "accommodations": "https://www.nims-skills.org/sites/default/files/media/document/Policy%20-%20Paper%20Tests%20%26%20Accommodations_0.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies safe and competent operation of drill presses with proper measurement and material handling.", "careerPaths": "Machining Operator, Manufacturing Technician, Machine Tool Operator, Production Technician", "goodFitFor": "Advanced manufacturing programs; Entry-level machining pathways; Programs emphasizing foundational machine tool skills", "detailedDesc": "NIMS Drill Press Skills I validates foundational competency in drill press operation, safety protocols, and measurement accuracy. This entry-level credential builds toward advanced machining certifications and demonstrates basic machine tool competency. The credential is valued across manufacturing sectors. Programs can offer this as an accessible entry point to machining careers."}, {"name": "NIMS Grinding Skills I with Measurement, Materials & Safety exam", "code": "IRC-1170", "cluster": "Advanced Manufacturing", "link": "https://www.nims-skills.org/", "issuer": "National Institute for Metalworking Skills Inc. (NIMS)", "cost": "The individual fee for one-time is $40", "accommodations": "https://www.nims-skills.org/sites/default/files/media/document/Policy%20-%20Paper%20Tests%20%26%20Accommodations_0.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies ability to safely and accurately operate grinding equipment for precision finishing and material removal.", "careerPaths": "Grinding Operator, Machining Technician, Manufacturing Operator, Quality Assurance Technician", "goodFitFor": "Advanced manufacturing programs; Machining and precision finishing pathways; Programs with grinding equipment access", "detailedDesc": "NIMS Grinding Skills I validates competency in precision grinding operations, safety procedures, and measurement standards. Youth learn finishing techniques essential for producing precision parts. The credential demonstrates foundational expertise in specialized machining processes. Programs emphasize the high-precision nature of grinding work and its importance in manufacturing quality."}, {"name": "NIMS Job Planning, Benchwork & Layout with Measurement, Materials & Safety exam", "code": "IRC-1171", "cluster": "Advanced Manufacturing", "link": "https://www.nims-skills.org/", "issuer": "National Institute for Metalworking Skills Inc. (NIMS)", "cost": "The individual fee for one-time is $43", "accommodations": "https://www.nims-skills.org/sites/default/files/media/document/Policy%20-%20Paper%20Tests%20%26%20Accommodations_0.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies foundational skills in job planning, layout, benchwork, and safe use of hand tools in machining.", "careerPaths": "Machinist, Manufacturing Technician, Tool and Die Maker, Quality Control Inspector", "goodFitFor": "Advanced manufacturing programs; Machining pathways; Trade and apprenticeship programs emphasizing foundational skills", "detailedDesc": "NIMS Job Planning, Benchwork & Layout validates essential competencies for setting up manufacturing jobs, planning sequences, and using hand tools accurately. Youth learn the foundational thinking and planning skills underlying all machining work. The credential demonstrates readiness for manufacturing careers and apprenticeships. Programs often position this as preparation for advanced CNC certifications."}, {"name": "NIMS Manual Milling Skills I with Measurement, Materials & Safety exam", "code": "IRC-1172", "cluster": "Advanced Manufacturing", "link": "https://www.nims-skills.org/", "issuer": "National Institute for Metalworking Skills Inc. (NIMS)", "cost": "The individual fee for one-time is $40", "accommodations": "https://www.nims-skills.org/sites/default/files/media/document/Policy%20-%20Paper%20Tests%20%26%20Accommodations_0.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies ability to operate manual milling machines with proper measurement, safety, and material handling.", "careerPaths": "Manual Machinist, Manufacturing Technician, Milling Machine Operator, Precision Operator", "goodFitFor": "Advanced manufacturing programs; Machining career pathways; Programs with manual milling equipment access", "detailedDesc": "NIMS Manual Milling Skills I validates competency in manual milling operations, measurement accuracy, and safety procedures. Youth learn traditional milling skills valued across manufacturing. The credential builds foundational expertise and often precedes CNC milling certifications. Programs emphasize the skill and precision required in manual machining."}, {"name": "NIMS Turning Operations: Turning Between Centers with Measurement, Materials & Safety exam", "code": "IRC-1173", "cluster": "Advanced Manufacturing", "link": "https://www.nims-skills.org/", "issuer": "National Institute for Metalworking Skills Inc. (NIMS)", "cost": "The individual fee for one-time is $40", "accommodations": "https://www.nims-skills.org/sites/default/files/media/document/Policy%20-%20Paper%20Tests%20%26%20Accommodations_0.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies ability to perform turning operations between centers on lathes with proper technique and measurement.", "careerPaths": "Lathe Operator, Machinist, Manufacturing Technician, Precision Machinist", "goodFitFor": "Advanced manufacturing programs; Machining and turning pathways; Programs with manual lathe equipment", "detailedDesc": "NIMS Turning Between Centers validates foundational lathe operation skills and precision measurement in turning operations. Youth learn classic machining techniques still essential in manufacturing. The credential demonstrates readiness for machining roles and often leads to advanced certifications. Programs position this as a stepping stone toward CNC turning credentials."}, {"name": "NIMS Turning Operations: Turning Chucking Skills with Measurement, Materials & Safety exam", "code": "IRC-1174", "cluster": "Advanced Manufacturing", "link": "https://www.nims-skills.org/", "issuer": "National Institute for Metalworking Skills Inc. (NIMS)", "cost": "The individual fee for one-time is $40", "accommodations": "https://www.nims-skills.org/sites/default/files/media/document/Policy%20-%20Paper%20Tests%20%26%20Accommodations_0.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies ability to operate lathe chucking operations including work holding, turning, and precision measurement.", "careerPaths": "Lathe Operator, Machinist, Manufacturing Technician, Production Technician", "goodFitFor": "Advanced manufacturing programs; Machining and turning pathways; Trade apprenticeship programs", "detailedDesc": "NIMS Turning Chucking Skills validates competency in chuck operation, work holding methods, and turning processes. Youth master specialized lathe skills used across manufacturing industries. The credential demonstrates precision work capability and machine tool competency. Programs often sequence this with between-centers turning for comprehensive lathe training."}, {"name": "Non-Structural Analysis and Damage Repair student", "code": "IRC-1175", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/dates-fees-test-times", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The cost is $46 per test", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates entry-level non-structural damage assessment and repair skills for automotive collision work.", "careerPaths": "Collision Repair Technician, Damage Assessor, Auto Body Technician, Repair Estimator, Customer Service Specialist", "goodFitFor": "Automotive collision repair and body work career pathways; Entry-level damage assessment programs; Youth interested in visual inspection and estimation", "detailedDesc": "This credential, issued by ASE, certifies ability to assess and repair non-structural collision damage including dents, glass, trim, and paint. It's designed for aspiring body technicians and damage estimators. Non-structural specialists earn solid wages and can progress to structural repair or estimation roles. Programs should partner with collision shops for hands-on training and may incorporate digital measurement systems."}, {"name": "Occupational Safety and Health Administration (OSHA) 30 Certification", "code": "IRC-1176", "cluster": "Construction, Agriculture", "link": "https://www.oshaeducationcenter.com/osha-30-hour-training/", "issuer": "Occupational Safety and Health Administration", "cost": "The costs range from $159 to $800", "accommodations": "https://www.ada.gov/resources/testing-accommodations/", "effDate": "July 1, 2025", "hours": "30 hours of instruction to complete, typically taken over four days", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": "Safe Alternative Foundation for Education Inc", "oneLiner": "OSHA's comprehensive 30-hour safety training credential signaling advanced knowledge of workplace safety regulations and hazard prevention.", "careerPaths": "Construction Supervisor, Safety Manager, Site Foreman, Facilities Manager, Industrial Safety Specialist, Skilled Trades Worker", "goodFitFor": "Programs with construction, manufacturing, or trades career tracks; workforce development programs preparing youth for supervisory roles; programs partnered with construction companies or manufacturing employers; pre-apprenticeship programs", "detailedDesc": "The OSHA 30-Hour Certification, administered by the Occupational Safety and Health Administration, provides advanced workplace safety training covering hazard recognition, safety regulations, workers' rights, and industry-specific safety standards. It is recognized across the construction and general industry sectors as a mark of advanced safety awareness. While the OSHA 10-Hour certification is more common for entry-level workers, the 30-Hour credential signals readiness for supervisory or safety coordination roles and is increasingly required on major construction projects. Programs should determine whether to offer OSHA 10 or 30 based on youth experience level and employer expectations."}, {"name": "Oracle Certified Associate, Java SE 8 Programmer", "code": "IRC-1177", "cluster": "Digital Technology", "link": "https://education.oracle.com/oracle-certified-foundations-associate-database/trackp_371", "issuer": "Oracle", "cost": null, "accommodations": "https://www.pearsonvue.com/us/en/test-takers/accommodations.html", "effDate": "July 1, 2025", "hours": "3 to 5 days for accelerated bootcamps, or 1 to 3 months for self-paced study", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Entry-level Oracle certification validating Java programming skills including object-oriented design, data types, flow control, and exception handling.", "careerPaths": "Java Developer, Software Engineer (entry), Application Developer, Back-End Developer, IT Specialist", "goodFitFor": "Advanced coding programs for older high school youth; programs with software development career tracks; programs partnered with software companies or IT employers; competitive summer coding programs", "detailedDesc": "The Oracle Certified Associate, Java SE 8 Programmer credential validates a student's ability to write, compile, and debug Java programs at an entry-level professional standard. Java remains one of the most widely used programming languages in enterprise software, Android app development, and back-end systems. The exam covers object-oriented principles, data types, operators, flow control, arrays, and exception handling. This is a rigorous credential best suited for youth with substantial prior programming experience, ideally paired with a structured coding curriculum and instructor support."}, {"name": "Oracle Certified Associate, Database SQL", "code": "IRC-1178", "cluster": "Digital Technology", "link": "https://education.oracle.com/oracle-database-sql-certified-associate/trackp_457", "issuer": "Oracle", "cost": "The cost is $245", "accommodations": "https://www.oracle.com/corporate/accessibility/learning-support/", "effDate": "July 1, 2025", "hours": "With dedicated study of a few hours each day, a person might achieve the certification in 6 to 10 weeks", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates expertise in relational database design, SQL querying, and data management using Oracle databases.", "careerPaths": "Database Administrator, SQL Developer, Data Analyst, Database Designer, Database Specialist, Data Engineer", "goodFitFor": "Database or data science-focused programs; STEM pathways with IT or analytics focus; Corporate or enterprise IT workforce development programs", "detailedDesc": "Oracle's Database SQL certification demonstrates advanced SQL proficiency and understanding of relational database concepts essential in enterprise IT environments. Oracle is a leading database platform, making this credential valuable across industries. Youth earning this certification demonstrate sophisticated technical knowledge and readiness for database specialist roles. Programs should provide hands-on Oracle database labs and emphasize real-world query design and optimization."}, {"name": "Oracle Certified Foundations Associate, Database", "code": "IRC-1179", "cluster": "Digital Technology", "link": "https://education.oracle.com/oracle-certified-foundations-associate-database/trackp_371", "issuer": "Oracle", "cost": "The cost is $287", "accommodations": "https://www.oracle.com/corporate/accessibility/learning-support/", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies foundational knowledge of database concepts, architecture, and Oracle database fundamentals.", "careerPaths": "Database Technician, Junior Database Administrator, Data Analyst, IT Support Specialist, Systems Administrator, Database Developer", "goodFitFor": "Introduction to IT and technology programs; STEM pathways for younger or less experienced youth; Foundational workforce development programs in tech", "detailedDesc": "Oracle's Certified Foundations Associate Database credential provides entry-level validation of database concepts, structure, and Oracle-specific fundamentals. This credential is accessible for youth new to IT and creates a foundation for more advanced database certifications. The Foundations credential demonstrates motivation and foundational knowledge to employers. Programs can use Oracle's free learning resources and community edition database to provide hands-on experience."}, {"name": "Oracle Certified Foundations Associate, Java", "code": "IRC-1180", "cluster": "Digital Technology", "link": "https://education.oracle.com/oracle-certified-foundations-associate-java/trackp_372", "issuer": "Oracle", "cost": "The exam is $95", "accommodations": "https://www.oracle.com/corporate/accessibility/learning-support/", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates foundational Java programming concepts and object-oriented principles using Oracle's Java platform.", "careerPaths": "Junior Java Developer, Programmer, Application Developer, Software Engineer, Systems Developer, Web Developer", "goodFitFor": "Computer science and coding programs; Technology career pathways for younger youth; STEM programs introducing programming languages", "detailedDesc": "Oracle's Certified Foundations Associate Java credential validates fundamental Java concepts and object-oriented programming principles\u2014essential building blocks for software development careers. This entry-level credential is accessible for youth beginning programming education and demonstrates foundational competency to employers. The credential creates a clear pathway to more advanced Oracle Java certifications. Programs should emphasize hands-on coding projects and use free development tools."}, {"name": "Paramedic (MIEMSS)", "code": "IRC-1181", "cluster": "Public Service & Safety", "link": "https://www.miemss.org/home/ems-providers/initial-certification", "issuer": "Maryland Institute for Emergency Medical Services (MIEMSS)", "cost": "Cost not listed for high school students.", "accommodations": "https://www.nremt.org/Policies/Examination-Policies/ADA-Accommodations", "effDate": "July 1, 2025", "hours": "1,100 hours of training, often spanning 12 to 15 months", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies advanced paramedic skills and critical decision-making under Maryland's emergency medical systems authority.", "careerPaths": "Paramedic, Advanced Life Support Provider, Critical Care Technician, Mobile Intensive Care Technician, Emergency Medical Supervisor", "goodFitFor": "Emergency services and advanced medical career pathways; Maryland-specific EMS professional programs; Youth committed to advanced emergency response", "detailedDesc": "This credential, issued by the Maryland Institute for Emergency Medical Services Systems (MIEMSS), certifies paramedic-level competencies within Maryland's regulatory framework, including advanced airway management, cardiac care, and medication administration. It opens paramedic careers across Maryland's emergency services. MIEMSS paramedics are recognized leaders in emergency care and often transition to flight operations or critical care. Programs should connect EMT-certified youth to paramedic training opportunities."}, {"name": "ParaPro", "code": "IRC-1182", "cluster": "Education", "link": "https://parapro.ets.org/", "issuer": "Educational Testing Service (ETS)", "cost": "The test fee is $85", "accommodations": "https://parapro.ets.org/disability-accommodations/parapro-disability-accommodations.html", "effDate": "July 1, 2025", "hours": "130-hour, 6-month courses, 20-hour instructional aide training", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies knowledge of educational content and ability to support student learning as a paraprofessional.", "careerPaths": "Teaching Assistant, Paraprofessional, Instructional Assistant, Special Education Aide, Classroom Assistant, Education Support Professional", "goodFitFor": "Education career pipelines; Youth development and mentoring programs; School-based workforce programs preparing students for education careers", "detailedDesc": "The ParaPro certification, administered by Educational Testing Service, validates subject matter knowledge and instructional support skills required of paraprofessionals in schools. This credential qualifies youth for immediate employment as teaching assistants while they pursue teaching degrees or other education careers. ParaPro holders earn higher wages than uncredentialed aides and demonstrate commitment to education careers. Programs can coordinate with local schools to understand specific content needs and arrange para-educator internships."}, {"name": "Pharmacy Technician License", "code": "IRC-1183", "cluster": "Healthcare & Human Services", "link": "https://pharmacytechacademy.com/maryland-pharmacy-tech-requirements#:~:text=Complete%20a%20Maryland%2DSpecific%20Training,exposure%20in%20a%20pharmacy%20setting.", "issuer": "Maryland Board of Pharmacy", "cost": "The registration fee is $45", "accommodations": "https://bpsweb.org/apply-for-ada-accommodations/#:~:text=BPS%20complies%20with%20relevant%20provisions,inspection%20by%20test%20center%20staff.", "effDate": "July 1, 2025", "hours": "4 months to 1 year", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies competency in pharmacy operations, medication management, and regulatory compliance for Maryland practitioners.", "careerPaths": "Pharmacy Technician, Licensed Pharmacy Technician, Pharmacy Support Specialist, Medication Technician, Retail Pharmacy Assistant", "goodFitFor": "Healthcare and pharmaceutical pathways; State-specific credential programs; Programs with pharmacy partnerships", "detailedDesc": "This credential, issued by the Maryland Board of Pharmacy, is the state-regulated license for pharmacy technicians, requiring documented training and passage of a competency exam. It authorizes pharmacy technicians to perform specific duties under pharmacist supervision. Youth gain access to regulated healthcare careers with strong job prospects and advancement to pharmacy administration or specialized roles. Programs must ensure compliance with Maryland pharmacy board training requirements."}, {"name": "Phlebotomy Technician", "code": "IRC-1184", "cluster": "Healthcare & Human Services", "link": "https://americanmedtech.org/phlebotomy-technician", "issuer": "American Medical Technologists (AMT)", "cost": "Ranges from $119 to $125", "accommodations": "https://americanmedtech.org/resource-library/category/supplementary-forms/ada-testing-accommodation-form", "effDate": "July 1, 2025", "hours": "4 to 12 weeks for certificate programs, with accelerated options as fast as 3\u20134 weeks", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies skills in blood collection, specimen handling, and laboratory support procedures.", "careerPaths": "Phlebotomy Technician, Phlebotomist, Laboratory Technician, Patient Draw Specialist, Specimen Handler", "goodFitFor": "Healthcare and laboratory science career pathways; Medical science and diagnostics programs; Programs with hospital and lab partnerships", "detailedDesc": "This credential, issued by American Medical Technologists (AMT), validates proficiency in venipuncture, capillary collection, specimen labeling, and safety protocols. Phlebotomists work in hospitals, diagnostic labs, blood banks, and mobile collection units, with high demand and flexible scheduling. The role is an excellent entry point to laboratory science careers or nursing. Programs should provide hands-on practice with simulation kits and clinical rotations in actual lab settings."}, {"name": "PraxisCORE", "code": "IRC-1185", "cluster": "Education", "link": "https://praxis.ets.org/states/about/overview-tests.html", "issuer": "Educational Testing Service (ETS)", "cost": "The exam fee is $90", "accommodations": "https://praxis.ets.org/test-takers/disability-accommodations.html", "effDate": "July 1, 2025", "hours": "4 to 8 weeks of study, although some candidates manage in 1\u20133 weeks with intense preparation", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "ETS assessment measuring core academic skills in reading, writing, and mathematics as a prerequisite for teacher education programs.", "careerPaths": "Teacher (K-12), Paraprofessional Educator, Instructional Aide, Early Childhood Educator, Educational Specialist", "goodFitFor": "Programs preparing youth for careers in education; programs targeting older youth (18+) pursuing teacher preparation or paraprofessional roles; programs partnered with school districts or teacher preparation programs; community-based educator pipeline programs", "detailedDesc": "The Praxis Core Academic Skills for Educators (PraxisCORE) assessment, developed by ETS, measures reading, writing, and mathematics skills as a prerequisite for admission to teacher education programs and licensure in many states. While it is an assessment rather than a skills credential, it serves as an important milestone credential for youth pursuing education careers. This assessment is most appropriate for programs working with older youth (18+) who are actively pursuing teacher preparation. Programs should ensure participants have sufficient academic preparation before registration."}, {"name": "Principles of Livestock Selection & Evaluation Certification", "code": "IRC-1186", "cluster": "Agriculture", "link": "https://www.icevonline.com/livestock-evaluation", "issuer": "National Collegiate Livestock Coaches' Association (NCLCA)", "cost": "The exam voucher is $40 and non-subscriber, it is $50", "accommodations": "https://www.icevonline.com/accommodations", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies expertise in livestock evaluation, selection standards, and breeding principles.", "careerPaths": "Livestock Specialist, Breeding Consultant, Agricultural Technician, Farm Manager", "goodFitFor": "Agriculture and livestock programs; Animal science pathways; Agricultural education and 4-H partnerships", "detailedDesc": "The National Collegiate Livestock Coaches Association credential validates livestock evaluation skills and breeding knowledge essential for livestock agriculture. Youth learn to assess animal quality and make informed breeding and selection decisions. The credential demonstrates expertise in a technical agricultural specialty. Programs benefit from coaching resources and educational networks."}, {"name": "PrintED", "code": "IRC-1187", "cluster": "Arts, Entertainment & Design", "link": "https://printcommunications.org/education/", "issuer": "Printing & Graphic Communicaitons Association (PGCA)", "cost": "The PrintED assessment fee for students is $12", "accommodations": "https://printcommunications.org/education/", "effDate": "July 1, 2025", "hours": "4\u20137 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Industry credential validating knowledge and skills in printing and graphic communications, including prepress, press operations, and finishing.", "careerPaths": "Print Production Specialist, Prepress Technician, Graphic Communications Specialist, Press Operator, Print Shop Manager", "goodFitFor": "Programs with graphic communications, printing, or media production tracks; programs partnered with print shops or commercial printing businesses; CTE-aligned OST programs with graphic arts components; programs serving youth interested in production and design careers", "detailedDesc": "The PrintED credential, administered by the Printing & Graphic Communications Association (PGCA), validates student knowledge and skills in the printing and graphic communications industry, including prepress operations, printing processes, digital workflow, and finishing techniques. This industry-backed credential is recognized by printing employers and connects directly to careers in commercial printing, packaging, and graphic production. It is well-suited for OST programs with graphic arts or media production components and particularly valuable in communities with a printing or packaging industry presence."}, {"name": "Quickbooks Certified User Desktop Certification", "code": "IRC-1188", "cluster": "Management and Entrepreneurship, Financial Services", "link": "https://quickbookstraining.com/quickbooks-certification", "issuer": "Intuit", "cost": "The cost can range around $130", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "12 to 20 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates proficiency in QuickBooks Desktop for managing business accounts, payroll, invoices, and financial reporting in local business environments.", "careerPaths": "Bookkeeper, Accounting Assistant, Small Business Owner, Office Administrator, Accounts Payable/Receivable Clerk", "goodFitFor": "Programs focused on entrepreneurship, finance, or business skills; workforce development programs serving youth interested in business administration; programs partnered with small businesses, accounting firms, or nonprofits using QuickBooks Desktop", "detailedDesc": "The QuickBooks Certified User Desktop certification, issued by Intuit through Certiport, validates proficiency in QuickBooks Desktop software, which is widely used by small businesses, accounting firms, and nonprofits. It covers creating accounts, processing payroll, generating reports, and managing invoices within the desktop application. While QuickBooks Online is increasingly prevalent, many businesses\u2014particularly in industries like construction and healthcare\u2014continue to rely on the Desktop version. This credential is a practical complement to the QuickBooks Online certification and is valuable for youth pursuing bookkeeping or administrative roles."}, {"name": "Quickbooks Certified User Online Certification", "code": "IRC-1189", "cluster": "Management and Entrepreneurship, Financial Services", "link": "https://quickbookstraining.com/quickbooks-certification", "issuer": "Intuit", "cost": "Exam is $150", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "13 to 20 hours to complete", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "Yes", "cclExpert": "Pass IT On", "oneLiner": "Validates proficiency in using QuickBooks Online for business bookkeeping, invoicing, payroll, and financial reporting.", "careerPaths": "Bookkeeper, Accounting Assistant, Small Business Manager, Office Administrator, Accounts Payable/Receivable Clerk", "goodFitFor": "Programs focused on entrepreneurship, financial literacy, or business skills; workforce development programs serving youth interested in business administration; programs partnered with small businesses or nonprofits", "detailedDesc": "The QuickBooks Certified User (QBCU) Online Certification, issued by Intuit through Certiport, demonstrates a student's ability to manage business finances using QuickBooks Online, the most widely used small business accounting platform in the U.S. It covers core tasks including creating invoices, managing payroll, generating financial reports, and tracking expenses. Preparation typically takes 13\u201320 hours, making it one of the most time-efficient credentials on this list. This credential is valuable for youth entering administrative, bookkeeping, or small business management roles."}, {"name": "Rescue Tech - Site Ops", "code": "IRC-1190", "cluster": "Public Service & Safety", "link": "https://www.mfri.org/", "issuer": "Maryland Fire and Rescue Institute", "cost": "Cost not listed for high school students.", "accommodations": "https://www.mfri.org/equity/", "effDate": "July 1, 2025", "hours": "27 to 40 hours of instruction", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Maryland Fire and Rescue Institute credential certifying technical rescue operations competency for confined spaces, structural collapses, and complex rescue scenarios.", "careerPaths": "Firefighter/Rescue Specialist, Technical Rescue Technician, Emergency Responder, Urban Search and Rescue Specialist", "goodFitFor": "Programs with fire science or advanced emergency services career tracks; programs partnered with fire departments offering technical rescue training; youth fire cadet or Explorer programs; programs serving older youth (16+) pursuing firefighting careers", "detailedDesc": "The Rescue Tech \u2013 Site Ops credential, offered through the Maryland Fire and Rescue Institute (MFRI), certifies emergency responders in technical rescue operations at complex sites including confined spaces, structural collapses, and trench rescues. This credential is part of an advanced rescue training pathway within the fire service and is recognized across Maryland's emergency response community. It is best suited for programs actively preparing youth for firefighting or technical rescue careers and should be delivered in partnership with certified MFRI instructors or fire departments."}, {"name": "Rescue Tech - Vehicle and Machinery Extraction", "code": "IRC-1191", "cluster": "Public Service & Safety", "link": "https://www.mfri.org/", "issuer": "Maryland Fire and Rescue Institute", "cost": "Cost not listed for high school students.", "accommodations": "https://www.mfri.org/equity/", "effDate": "July 1, 2025", "hours": "16 to 40 hours, usually spread over 2 to 5 days", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Maryland Fire and Rescue Institute credential validating skills in safely extricating victims from vehicle crashes and machinery entrapments.", "careerPaths": "Firefighter/Rescue Specialist, EMS Technician, Technical Rescue Technician, Auto Extrication Specialist, Emergency Responder", "goodFitFor": "Programs with fire science or EMS career tracks; programs partnered with fire departments or emergency medical services; youth fire cadet or Explorer programs; programs near high-traffic transportation corridors where vehicle extrication is a common emergency response need", "detailedDesc": "The Rescue Tech \u2013 Vehicle and Machinery Extraction credential from the Maryland Fire and Rescue Institute (MFRI) certifies emergency responders in the specialized techniques needed to safely extract victims from motor vehicle crashes and machinery entrapments. This is a critical competency for firefighters and EMS personnel responding to traffic accidents and industrial incidents. The credential is best delivered in partnership with certified MFRI instructors or fire departments with extrication equipment. It is a strong fit for programs building fire service or EMS career pathways in Maryland."}, {"name": "Security Fundamentals - 98-367", "code": "IRC-1192", "cluster": "Digital Technology", "link": "https://trainingsupport.microsoft.com/en-us/mcp/forum/all/mta-security-fundamentals-98-367-certificate-exam/12de842c-4483-478a-b6d2-e97c66862f51", "issuer": "Microsoft", "cost": "The cost is around $127", "accommodations": "https://learn.microsoft.com/en-us/credentials/certifications/accommodations", "effDate": "July 1, 2025", "hours": "15 to 30 hours of study, depending on experience. While intensive, instructor-led training courses often run for 2-3 days", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Microsoft Technology Associate credential validating foundational knowledge of network security, operating system security, and software security concepts.", "careerPaths": "IT Security Technician, Network Support Specialist, Help Desk Technician, Security Analyst (entry), Systems Administrator (entry)", "goodFitFor": "Technology pathway programs with a cybersecurity or IT focus; programs serving youth building toward CompTIA Security+ or other cybersecurity credentials; STEM afterschool programs with networking or IT components", "detailedDesc": "The Microsoft Security Fundamentals (MTA 98-367) credential validates entry-level knowledge of core security concepts including network security principles, operating system security, and software security. While Microsoft has retired new registrations for this exam, many programs continue to use it as a foundational step in cybersecurity pathways. It covers topics that align closely with CompTIA Security+ preparation and helps youth build a conceptual security framework before tackling more advanced certifications. Programs should verify current exam availability with their Certiport center."}, {"name": "ServSafe Manager", "code": "IRC-1193", "cluster": "Hospitality, Events, and Tourism", "link": "https://www.servsafe.com/access/ss/Catalog/ProductList/10", "issuer": "ServSafe", "cost": "Online Proctored Exam $179", "accommodations": "https://www.servsafe.com/ServSafe/media/ServSafe/Documents/SSFS-Examinee-Handbook.pdf", "effDate": "July 1, 2025", "hours": "8\u201310 hours to complete online, covering 10 modules, with an additional 2-hour, 90-question proctored exam. In-person training is often structured as a 1-2 day class (16 hours total)", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "National Restaurant Association's food safety management credential, required or preferred for food service supervisors and managers nationwide.", "careerPaths": "Food Service Manager, Restaurant Supervisor, Kitchen Manager, Catering Coordinator, Food Production Supervisor, Dietary Manager", "goodFitFor": "Programs with culinary arts or hospitality career tracks; workforce development programs serving youth interested in food service careers; programs partnered with restaurants, catering companies, school cafeterias, or food manufacturers; broadly accessible for many OST program types with kitchen facilities", "detailedDesc": "The ServSafe Manager certification, issued by the National Restaurant Association, is the most widely recognized food safety credential in the U.S. and is required or strongly preferred by employers for supervisory roles in food service. It validates knowledge of foodborne illness prevention, proper food handling, sanitation, and food safety management systems (HACCP). Preparation typically takes 8\u201315 hours, and the proctored exam can be completed in a single session. This is an excellent credential for any OST program with a culinary or hospitality focus, offering strong ROI in terms of youth employability and employer recognition."}, {"name": "SFMA - Turfgrass Science Certification", "code": "IRC-1194", "cluster": "Agriculture", "link": "https://www.sportsfieldmanagement.org/turfgrass-science-certification/", "issuer": "Sports Field Management Association", "cost": "The cost is free for SFMA members & $60 for non-members", "accommodations": "https://www.sportsfieldmanagement.org/conferences/accommodations/", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies professional knowledge of turfgrass management, sports field maintenance, and landscape science.", "careerPaths": "Turf Manager, Grounds Keeper, Sports Field Specialist, Landscape Manager", "goodFitFor": "Agriculture and horticulture programs; Sports and recreation partnerships; Grounds management career pathways", "detailedDesc": "The Sports Field Management Association's turfgrass science credential validates professional knowledge of grass species, soil management, and sports field maintenance. Youth learn specialized skills in high-value sports and recreational turf management. The credential opens careers in golf courses, sports facilities, and university grounds departments. Programs can partner with local sports venues and golf facilities."}, {"name": "SOC Operating Analyst I", "code": "IRC-1195", "cluster": "Digital Technology", "link": "https://bcrcyber.com/training-certification/", "issuer": "BCR Cyber", "cost": null, "accommodations": "https://bcrcyber.com/training-certification/", "effDate": "July 1, 2025", "hours": "8 to 16 weeks for comprehensive bootcamps, or roughly 40\u201350 hours for accelerated, focused certification courses", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Entry-level cybersecurity operations credential validating skills in monitoring, detecting, and responding to cyber threats in a Security Operations Center environment.", "careerPaths": "SOC Analyst, Cybersecurity Analyst (entry), Threat Detection Specialist, Information Security Analyst, Incident Responder", "goodFitFor": "Cybersecurity pathway programs for older youth; programs partnered with cybersecurity employers, government agencies, or defense contractors; advanced STEM programs with hands-on cybersecurity components; youth apprenticeship programs in cybersecurity", "detailedDesc": "The SOC Operating Analyst I credential, issued by BCR Cyber, validates entry-level skills in Security Operations Center (SOC) environments including threat monitoring, alert triage, incident response, and security tool operation. The SOC analyst role is one of the fastest-growing and most in-demand positions in cybersecurity, and this credential provides a direct pathway into that career. It is best suited for programs with cybersecurity-focused coursework and strong employer partnerships in the tech or government sectors. It pairs naturally with CompTIA Security+ and CYSA+ for youth building cybersecurity careers."}, {"name": "Structural Analysis and Damage Repair student", "code": "IRC-1196", "cluster": "Supply Chain & Transportation", "link": "https://www.ase.com/dates-fees-test-times", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The cost is $46 per test", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": "5 days for specialized, hands-on workshops to 16 weeks for a semester-long college course", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies understanding of vehicle structural damage assessment and repair techniques at the student level.", "careerPaths": "Auto Body Technician, Structural Repair Specialist, Collision Repair Technician, Vehicle Restoration Technician", "goodFitFor": "Automotive and collision repair programs; Trade pathways in afterschool or summer programs; Partnerships with body shop and repair facilities", "detailedDesc": "This ASE credential focuses on structural analysis and damage repair, validating that students can assess vehicle frame damage and perform basic repair operations. It's an entry-level certification on the path to becoming a full auto body technician. The student-level designation allows youth to earn industry recognition while still developing skills. Programs can use this as a stepping stone toward advanced collision repair credentials."}, {"name": "The Council for Six Sigma Certification", "code": "IRC-1197", "cluster": "Management and Entrepreneurship", "link": "https://www.sixsigmacouncil.org/six-sigma-white-belt-certification/", "issuer": "Six Sigma - Sigma White", "cost": "Certification is free for the White Belt", "accommodations": "https://www.sixsigmacouncil.org/", "effDate": "July 1, 2025", "hours": "online certification programs for Green Belt typically take 2 to 7 weeks", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": "Pass IT On", "oneLiner": "Entry-level Six Sigma credential recognizing foundational knowledge of quality management, process improvement, and workplace efficiency principles.", "careerPaths": "Quality Assurance Technician, Manufacturing Associate, Process Improvement Analyst, Operations Coordinator, Business Analyst (entry)", "goodFitFor": "Workforce development programs focused on manufacturing or business operations; programs serving youth 16+ interested in quality management or business improvement; programs partnered with manufacturing or logistics employers", "detailedDesc": "The Six Sigma White Belt credential from the Council for Six Sigma Certification introduces students to the core principles of Six Sigma, a globally recognized methodology for eliminating defects and improving processes in business and manufacturing environments. It covers basic quality concepts, DMAIC problem-solving, and workplace efficiency tools. This entry-level certification is achievable in a relatively short time frame (1\u20132 weeks for the White Belt level) and is valued in manufacturing, healthcare, logistics, and business settings. It helps youth build a quality-focused mindset applicable across many industries."}, {"name": "Truck Company Fireground Ops", "code": "IRC-1198", "cluster": "Public Service & Safety", "link": "https://www.mfri.org/", "issuer": "Maryland Fire and Rescue Institute", "cost": "Cost not listed for high school students.", "accommodations": "https://www.mfri.org/equity/", "effDate": "July 1, 2025", "hours": "intensive 16-hour to 24-hour courses", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates knowledge and skills needed to safely operate at fireground scenes and perform firefighting tasks.", "careerPaths": "Firefighter, Fire Apparatus Operator, Fire Safety Officer, Emergency Response Coordinator", "goodFitFor": "Programs with public service career tracks; Fire and rescue partnerships; Youth interested in emergency services", "detailedDesc": "This credential certifies that firefighters can safely execute fireground operations including equipment handling, scene safety, and tactical response. Issued by the Maryland Fire and Rescue Institute, it's the foundational certification for entry-level firefighting roles in Maryland. Youth completing this credential demonstrate readiness for firefighting careers and can pursue additional certifications. Programs should partner with local fire departments for hands-on training components."}, {"name": "Unity Certified User Certification - Artist", "code": "IRC-1199", "cluster": "Arts, Entertainment & Design", "link": "https://unity.com/products/unity-certifications", "issuer": "Unity (Certiport)", "cost": "The cost is $130", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "150 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies proficiency in 3D art, animation, and visual design using the Unity game development platform.", "careerPaths": "3D Artist, Game Designer, Animator, Visual Effects Specialist", "goodFitFor": "Arts and design programs; Digital media and game development pathways; STEM programs emphasizing creative applications", "detailedDesc": "Unity's Certified User Certification for Artists validates skills in 3D modeling, animation, materials, and visual design within a professional game engine. Youth learn industry-standard tools and demonstrate portfolio-ready artistic competency. The credential opens careers in game development, animation, and digital design industries. Programs benefit from Unity's educational resources and industry partnerships."}, {"name": "Unity Certified User Certification - Programmer", "code": "IRC-1200", "cluster": "Arts, Entertainment & Design", "link": "https://unity.com/products/unity-certifications", "issuer": "Unity (Certiport)", "cost": "The cost is $130", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "150 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies proficiency in game development programming and software design using the Unity development platform.", "careerPaths": "Game Developer, Software Engineer, Application Developer, Technical Designer", "goodFitFor": "STEM and computer science programs; Game development and software pathways; Programs emphasizing advanced coding and development", "detailedDesc": "Unity's Certified User Certification for Programmers validates coding, game mechanics, and software development skills in a professional game engine. Youth demonstrate readiness for software development and game programming careers. The credential combines technical programming with portfolio-ready game projects. Programs should target youth with solid programming foundations and problem-solving skills."}, {"name": "Unity Certified User Certification - VR Developer", "code": "IRC-1201", "cluster": "Arts, Entertainment & Design", "link": "https://unity.com/products/unity-certifications", "issuer": "Unity (Certiport)", "cost": "The cost is $130", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations.aspx", "effDate": "July 1, 2025", "hours": "150 hours", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies competency in developing virtual reality applications using the Unity game engine.", "careerPaths": "VR Developer, Game Developer, Interactive Designer, 3D Application Developer, VR Experience Designer", "goodFitFor": "Arts and design-focused youth programs; STEM programs with game development or immersive media tracks; Technology-focused afterschool programs serving older youth", "detailedDesc": "This credential validates skills in using Unity to create VR applications, including environment design, interaction programming, and optimization. Unity Technologies offers this certification through Certiport to demonstrate professional-level VR development capabilities. It's valuable for youth interested in emerging careers in entertainment, gaming, and immersive media. Programs can integrate this credential with project-based learning where youth build and showcase VR prototypes."}, {"name": "USITT Backstage Theatre Certification", "code": "IRC-1202", "cluster": "Arts, Entertainment & Design", "link": "https://www.usitt.org/education-training/backstage/backstage-exam", "issuer": "United States Institute for Theatre Technology, Inc. (USITT)", "cost": "The fee is $30 per individual or bulk pricing for your class.", "accommodations": null, "effDate": "July 1, 2025", "hours": "USITT offers a 10-hour, two-day training program.", "trainingNotes": null, "prereqs": null, "under5weeks": "Yes", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates foundational technical theatre skills including stage management, rigging, lighting, sound, and scenic construction.", "careerPaths": "Stage Manager, Technical Director, Lighting Technician, Sound Technician, Set Designer, Theatre Production Specialist", "goodFitFor": "Performing arts and theatre afterschool programs; programs serving youth interested in entertainment technology and production careers; programs partnered with theatres, performing arts centers, or production companies; arts-focused community organizations", "detailedDesc": "The USITT Backstage Theatre Certification, issued by the United States Institute for Theatre Technology (USITT), validates foundational skills in technical theatre production including rigging, lighting, sound, stage management, and scenic construction. It is recognized by the entertainment and performing arts industries as an entry-level professional standard. This credential is an excellent fit for performing arts OST programs and positions youth for careers in live entertainment, film and television production, and event management. It gives technical theatre students a recognized credential to accompany their hands-on experience."}, {"name": "ASE A1 - Engine Repair", "code": "IRC-1203", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The tests are $59 each and a $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": "two years of on-the-job training", "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies advanced expertise in engine repair and diagnosis for automotive service professionals.", "careerPaths": "Engine Specialist, Advanced Service Technician, Engine Diagnostics Expert, Service Manager, Technical Instructor", "goodFitFor": "Advanced automotive specialization and diagnostic career pathways; Professional development for service technicians; Certification progression programs", "detailedDesc": "This credential, issued by ASE, represents advanced engine expertise requiring significant hands-on experience and mastery of complex systems. A1-certified technicians earn premium wages and often move into service management or technical leadership. The certification demonstrates commitment to professional development. Programs should position A1 as an advanced step for technicians progressing from entry-level."}, {"name": "ASE A2 - Automotive Transmission/Transaxle", "code": "IRC-1204", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The tests are $59 each and a $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates advanced transmission system expertise and complex repair competencies for automotive professionals.", "careerPaths": "Senior Transmission Technician, Transmission Specialist, Diagnostic Technician, Transmission Shop Manager, Technical Trainer", "goodFitFor": "Advanced automotive specialization; Transmission expertise and advanced repair career pathways; Professional development for transmission specialists", "detailedDesc": "This credential, issued by ASE, certifies advanced automatic transmission knowledge and complex repair skills. A2-certified technicians are highly valued by employers and earn premium wages with leadership opportunities. The specialty offers clear pathways to transmission shop management. Programs should emphasize systematic diagnosis and complex repair procedures."}, {"name": "ASE A3 - Manual Drive Train & Axles", "code": "IRC-1205", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The tests are $59 each and a $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies advanced manual drivetrain expertise including transmissions, clutches, and differentials.", "careerPaths": "Manual Drivetrain Specialist, Transmission Expert, Heavy-Duty Technician, Senior Service Technician, Fleet Specialist", "goodFitFor": "Advanced automotive specialization; Manual drivetrain and transmission expert pathway; Professional development for transmission specialists", "detailedDesc": "This credential, issued by ASE, certifies advanced manual transmission and drive train system expertise. A3-certified technicians earn above-average wages with strong job security and potential advancement to supervisory roles. The specialty is particularly valuable in heavy-duty trucking. Programs should provide advanced hands-on training on complex transmission systems."}, {"name": "ASE A4 - Suspension & Steering", "code": "IRC-1206", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The tests are $59 each and a $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates advanced suspension and steering system expertise for automotive technicians.", "careerPaths": "Senior Suspension Specialist, Alignment Expert, Steering Specialist, Fleet Maintenance Manager, Technical Trainer", "goodFitFor": "Advanced automotive specialization; Suspension and steering expertise career pathways; Professional development for suspension specialists", "detailedDesc": "This credential, issued by ASE, certifies advanced suspension and steering knowledge including complex diagnostics and alignment. A4-certified technicians earn solid wages with job security and potential management opportunities. Suspension expertise is critical to vehicle safety and customer satisfaction. Programs should integrate advanced diagnostic equipment and complex troubleshooting procedures."}, {"name": "ASE A5 - Brakes", "code": "IRC-1207", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The tests are $59 each and a $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies advanced brake system expertise and complex diagnostic competencies for automotive professionals.", "careerPaths": "Senior Brake Specialist, Brake Systems Expert, Diagnostic Technician, Fleet Safety Manager, Technical Trainer", "goodFitFor": "Advanced automotive specialization; Brake systems expertise and safety-focused career pathway; Professional development for brake specialists", "detailedDesc": "This credential, issued by ASE, certifies advanced brake system knowledge including hydraulic, pneumatic, and electronic systems. A5-certified technicians earn solid wages with excellent job security and management potential. Brake expertise is valued in fleet operations and safety-conscious employers. Programs should emphasize complex diagnostics and different brake technologies."}, {"name": "ASE A6 - Electrical/Electronic Systems", "code": "IRC-1208", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The tests are $59 each and a $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates advanced automotive electrical and electronic system expertise for modern vehicle service.", "careerPaths": "Senior Electrical Technician, Electronics Specialist, Diagnostic Expert, Fleet Tech Lead, Service Manager", "goodFitFor": "Advanced automotive specialization; Electrical and electronics expertise career pathway; STEM-focused advanced vehicle systems programs", "detailedDesc": "This credential, issued by ASE, certifies advanced electrical and electronic systems knowledge for increasingly complex modern vehicles. A6-certified technicians earn above-average wages with strong career progression. Electrical expertise is increasingly critical as vehicles become more computerized. Programs should integrate advanced diagnostic tools and complex circuit analysis."}, {"name": "ASE A7 - Heating & Air Conditioning", "code": "IRC-1209", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The tests are $59 each and a $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies advanced heating, ventilation, and air conditioning system expertise for vehicles.", "careerPaths": "Senior HVAC Technician, Climate Control Specialist, Refrigeration Expert, Fleet Maintenance Manager, Environmental Compliance Lead", "goodFitFor": "Advanced automotive specialization; HVAC and climate control expertise career pathway; Environmental compliance professional development", "detailedDesc": "This credential, issued by ASE, certifies advanced climate control system knowledge and complex repair procedures. A7-certified technicians earn solid wages with good job security and management potential. HVAC expertise is valuable in fleet operations. Programs should emphasize modern refrigerant systems and environmental compliance."}, {"name": "ASE A8 - Engine Performance", "code": "IRC-1210", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The tests are $59 each and a $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Validates advanced engine performance system expertise using sophisticated diagnostic methodologies.", "careerPaths": "Engine Performance Expert, Senior Diagnostic Technician, Technical Lead, Service Manager, Engineering Support Specialist", "goodFitFor": "Advanced automotive specialization; Engine performance and diagnostics expertise pathway; STEM-focused advanced troubleshooting programs", "detailedDesc": "This credential, issued by ASE, certifies advanced engine performance expertise including complex sensor systems and computer diagnostics. A8-certified technicians are highly valued, earn premium wages, and often move into technical leadership. The specialty reflects mastery of modern vehicle technology. Programs should emphasize advanced diagnostic tools and complex problem-solving."}, {"name": "ASE A9 - Light Vehicle Diesel Engines", "code": "IRC-1211", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/", "issuer": "National Institute for Automotive Service Excellence (ASE)", "cost": "The tests are $59 each and a $34 registration fee", "accommodations": "https://www.ase.com/dist/docs/ADA-Request-Form.pdf", "effDate": "July 1, 2025", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": "No", "cclModule": "No", "cclExpert": null, "oneLiner": "Certifies advanced diesel engine expertise for light and medium-duty diesel applications.", "careerPaths": "Senior Diesel Technician, Diesel Expert, Fleet Maintenance Specialist, Diesel Shop Manager, Heavy-Duty Technician", "goodFitFor": "Advanced automotive specialization; Diesel engine expertise career pathway; Commercial and fleet vehicle specialist programs", "detailedDesc": "This credential, issued by ASE, certifies advanced diesel engine systems knowledge and complex repair competencies. A9-certified technicians are in high demand, earn premium wages, and have pathways to fleet management. Diesel expertise is particularly valuable in commercial operations. Programs should provide advanced hands-on training on diesel-specific systems and diagnostics."}, {"name": "Pre-Apprenticeship Multi-Craft Core Curriculum (MC3)", "code": "IRC-1212", "cluster": "Construction", "link": "https://nabtu.personalearning.com/v3/home", "issuer": "North America's Building Trade Union, Tradesfutures", "cost": null, "accommodations": null, "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "North America's Building Trades Unions' nationally recognized pre-apprenticeship credential covering safety, tools, construction math, and multi-craft trade fundamentals.", "careerPaths": "Construction Trades Pre-Apprentice, Carpenter, Electrician, Plumber, HVAC Technician, Ironworker (pathway into union registered apprenticeship)", "goodFitFor": "Programs with construction or skilled trades career tracks; programs partnered with NABTU affiliates or building trades unions; pre-apprenticeship programs preparing youth for union registered apprenticeships; workforce development programs in the construction industry", "detailedDesc": "The Pre-Apprenticeship Multi-Craft Core Curriculum (MC3), developed by North America's Building Trades Unions (NABTU) in partnership with Tradesfutures, is a nationally recognized pre-apprenticeship credential covering construction safety, tools and materials, applied construction math, blue print reading, and trade-specific fundamentals across multiple crafts. It is designed to prepare youth for registered union apprenticeships in the building trades\u2014among the highest-paying career pathways available without a four-year degree. MC3 completion is recognized by NABTU affiliates nationwide as evidence of apprenticeship readiness. This credential is ideal for programs building direct pipelines into union apprenticeship programs."}, {"name": "Pre-Apprenticeship Interim Credentials", "code": "IRC-1213", "cluster": "Construction", "link": "https://info.interimcredentials.com", "issuer": "Electrical Training Alliance", "cost": null, "accommodations": null, "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Construction industry credential recognizing completion of foundational pre-apprenticeship training modules through the Electrical Training Alliance.", "careerPaths": "Electrician (pre-apprenticeship pathway), Electrical Helper, Construction Trainee, Facilities Maintenance Worker, Electrical Pre-Apprentice", "goodFitFor": "Programs with electrical or construction trades career tracks; programs partnered with the Electrical Training Alliance (IBEW/NECA) or local electrical contractors; pre-apprenticeship programs preparing youth for registered apprenticeship; workforce development programs in the construction industry", "detailedDesc": "The Pre-Apprenticeship Interim Credentials, offered through the Electrical Training Alliance (a partnership of IBEW and NECA), recognize completion of foundational electrical trade skills and academic preparation aligned with the electrical apprenticeship pathway. These credentials are designed to bridge youth from pre-apprenticeship preparation into IBEW registered apprenticeship programs. They are best suited for programs with direct partnerships with local IBEW/NECA chapters and serve as meaningful milestones for youth demonstrating readiness for union electrical apprenticeship. This credential signals both technical preparation and commitment to a high-wage trades career."}, {"name": "Microsoft Azure Data Fundamentals", "code": "IRC-1214", "cluster": "Digital Technology", "link": "https://certiport.pearsonvue.com/Certifications/Microsoft/MCF/Overview", "issuer": "Certiport", "cost": "$99.00", "accommodations": "https://certiport.pearsonvue.com/Educator-resources/Exam-policies/Accommodations", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Microsoft's foundational data services credential validating knowledge of core data concepts, relational and non-relational data, and Azure cloud data services.", "careerPaths": "Data Analyst (entry), Cloud Data Specialist, Business Intelligence Analyst, Database Administrator (entry), Data Engineer (entry)", "goodFitFor": "Technology pathway programs serving older high school youth; programs with data, cloud, or IT career tracks; programs partnered with tech employers using Microsoft Azure; summer data or cloud computing intensives", "detailedDesc": "The Microsoft Azure Data Fundamentals (DP-900) certification validates foundational knowledge of core data concepts and how they are implemented using Azure data services, including relational databases, non-relational data, analytics workloads, and data visualization. It requires approximately 15\u201330 hours of preparation and pairs naturally with the Azure Fundamentals (AZ-900) credential as part of a broader Microsoft cloud career pathway. As organizations move data infrastructure to the cloud, this credential positions youth for careers at the intersection of data and cloud computing. It is a strong addition to programs building technology and data literacy."}, {"name": "CompTIA Data+", "code": "IRC-1215", "cluster": "Digital Technology", "link": "https://www.comptia.org/en-us/certifications/data/v2/", "issuer": "Pearson Vue", "cost": "$255.00", "accommodations": "https://www.comptia.org/en-us/resources/test-policies/candidate-testing-policies/?_gl=1*s65sgv*_up*MQ..*_ga*MTYzNDcwNzk5Ni4xNzYxOTE5MTc2*_ga_Z1ZV6990VN*czE3NjE5MTkxNzUkbzEkZzAkdDE3NjE5MTkxNzUkajYwJGwwJGg0ODgzMTAyNDE.", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Validates foundational skills in data analysis, data management, visualization, and communicating data-driven insights in business contexts.", "careerPaths": "Data Analyst (entry), Business Intelligence Analyst, Data Reporting Specialist, Operations Analyst, Research Analyst, Marketing Analyst", "goodFitFor": "Technology pathway programs with data or analytics tracks; programs serving youth interested in business, tech, or research careers; programs partnered with data-driven employers in healthcare, finance, or tech; STEM programs with statistics or computer science components", "detailedDesc": "The CompTIA Data+ certification, issued by the Computing Technology Industry Association, validates entry-level proficiency in mining data, analyzing complex datasets, visualizing data, and communicating insights to support business decisions. It covers data concepts, data mining, data analysis, visualization tools, and data governance. As data literacy becomes a foundational skill across virtually every industry, Data+ gives youth a recognized credential for entry-level data roles. It is an excellent fit for programs that incorporate statistics, business analytics, or data visualization into their technology curriculum."}, {"name": "WISE Certification", "code": "IRC-1216", "cluster": "Digital Technology", "link": "https://www.wisecertification.com/", "issuer": "CTIA - The Wireless Association", "cost": null, "accommodations": "https://www.ctia.org/", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Industry credential from CTIA validating knowledge of wireless technology, mobile devices, and the wireless telecommunications ecosystem.", "careerPaths": "Wireless Sales Specialist, Mobile Device Technician, Retail Technology Associate, Telecommunications Specialist, Customer Service Representative (wireless)", "goodFitFor": "Programs with retail, technology, or telecommunications career tracks; programs partnered with wireless carriers or mobile device retailers; workforce development programs targeting employment in the consumer electronics and wireless industries; broadly accessible for programs with basic technology coursework", "detailedDesc": "The WISE (Wireless Industry Service Excellence) Certification, issued by CTIA \u2013 The Wireless Association, validates foundational knowledge of wireless devices, network technologies, and customer service skills specific to the wireless retail and service industry. It is recognized by major wireless carriers and retailers as an industry standard for sales and technical support roles. Preparation can be completed in 20\u201340 hours, making it one of the more accessible credentials for youth programs. The credential is particularly valuable in communities with significant retail employment in wireless and consumer electronics."}, {"name": "Community Health Worker", "code": "IRC-1217", "cluster": "Healthcare & Human Services", "link": "https://www.hopkinsmedicine.org/johns-hopkins-howard-county/services/population-health/community-care-team/chw-training-program#:~:text=Johns%20Hopkins%20Howard%20County%20Medical%20Center%20offers%20training%20and%20certification,weekly%2C%20discussion%20board%20posts%20online", "issuer": "Johns Hopkins Howard County Medical Center's CHW Training Program", "cost": null, "accommodations": "https://publichealth.jhu.edu/center-for-health-equity/community-health-workers", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Validates competency as a community health worker trained to connect individuals and families to healthcare services and social supports.", "careerPaths": "Community Health Worker, Health Navigator, Patient Advocate, Care Coordinator, Public Health Assistant, Social Services Case Aide", "goodFitFor": "Programs serving youth interested in healthcare, social work, or community service careers; programs in communities with health disparities or underserved populations; programs affiliated with health systems, community health centers, or public health agencies; workforce development programs for youth seeking healthcare entry points without a clinical degree", "detailedDesc": "The Community Health Worker (CHW) credential, offered through Johns Hopkins Howard County Medical Center's CHW Training Program, certifies graduates to serve as trusted bridges between communities and health and human service systems. CHWs provide health education, support care coordination, conduct outreach, and connect individuals to resources. This credential is particularly meaningful for youth from the communities they will serve, as lived experience is a core strength of effective CHW practice. It is an excellent fit for programs committed to advancing health equity and preparing youth for meaningful careers in community and public health."}, {"name": "National Association of Sports Medicine-Certified Personal Trainer", "code": "IRC-1218", "cluster": "Healthcare & Human Services", "link": "https://www.nasm.org/", "issuer": "National Association of Sports Medicine", "cost": null, "accommodations": "https://support.nasm.org/does-nasm-afaa-offer-any-special-accommodations", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "NASM's industry-leading personal training certification validating evidence-based knowledge of human movement, exercise science, and individualized fitness programming.", "careerPaths": "Personal Trainer, Fitness Coach, Wellness Specialist, Strength and Conditioning Coach, Group Fitness Instructor, Health Club Manager", "goodFitFor": "Programs focused on health, wellness, or sports science careers; recreation-based OST programs; programs partnered with gyms, recreation centers, or YMCAs; programs serving youth interested in fitness, sports performance, or health coaching careers", "detailedDesc": "The NASM Certified Personal Trainer (NASM-CPT) is one of the most widely recognized and respected personal training certifications in the fitness industry, grounded in NASM's Optimum Performance Training (OPT) model and evidence-based exercise science. The certification covers human movement science, fitness assessment, program design, and client behavior change. Preparation typically takes 3\u20136 months and requires passing a comprehensive proctored exam. NASM-CPT holders are recognized by employers at fitness centers, corporate wellness programs, sports performance facilities, and private coaching practices."}, {"name": "Emergency Telecommunicator Certificate (ETC)", "code": "IRC-1219", "cluster": "Public Service & Safety", "link": "https://www.emergencydispatch.org/home", "issuer": "International Academies of Emergency Dispatch (IAED)", "cost": null, "accommodations": "https://www.emergencydispatch.org/what-we-do/member-services", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Validates the foundational skills and knowledge required to professionally handle 9-1-1 calls and dispatch emergency services as an emergency telecommunications professional.", "careerPaths": "Emergency Dispatcher, 9-1-1 Call Taker, Emergency Telecommunications Officer, Public Safety Telecommunicator, Communications Center Specialist", "goodFitFor": "Programs with public safety or emergency communications career tracks; programs partnered with county or city 9-1-1 centers and emergency dispatch agencies; workforce development programs for older youth (18+) pursuing government and public safety careers; programs in communities where dispatcher hiring is active", "detailedDesc": "The Emergency Telecommunicator Certificate (ETC), issued by the International Academies of Emergency Dispatch (IAED), is a professional-level credential recognized by 9-1-1 communications centers and public safety answering points (PSAPs) worldwide. It validates competency in emergency call handling, dispatcher decision-making, and use of standardized dispatch protocols. This credential prepares youth for stable, well-paying government careers in emergency communications and is particularly meaningful for programs with connections to local 9-1-1 agencies. It pairs well with the National Basic 9-1-1 Dispatch Certification as part of a comprehensive dispatcher career pathway."}, {"name": "ASE Medium Heavy Truck T1 - Gasoline Engines", "code": "IRC-1220", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/test-series", "issuer": "National Institute for Automotive Service Excellence", "cost": "$62.00", "accommodations": "https://www.ase.com/ada2", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Validates technician-level knowledge of gasoline engine diagnosis, repair, and maintenance for medium and heavy-duty trucks.", "careerPaths": "Medium/Heavy Truck Technician, Diesel/Gas Engine Mechanic, Fleet Maintenance Technician, Commercial Vehicle Technician, Transportation Equipment Mechanic", "goodFitFor": "Programs with automotive or diesel technology career tracks serving older youth (16+); programs partnered with trucking fleets, commercial vehicle dealerships, or transportation companies; pre-apprenticeship programs in the transportation and logistics sector", "detailedDesc": "The ASE Medium/Heavy Truck T1 - Gasoline Engines certification, issued by the National Institute for Automotive Service Excellence (ASE), validates a technician's knowledge of gasoline engine systems in medium and heavy-duty commercial vehicles, including diagnosis, repair, and performance testing. It is part of ASE's professional-level medium/heavy truck certification series, which is widely recognized by commercial fleet operators and truck dealerships. This credential is best suited for programs serving older youth with prior automotive fundamentals who are building toward commercial vehicle careers. It pairs well with other ASE medium/heavy truck credentials (T2\u2013T6) for comprehensive fleet technician preparation."}, {"name": "ASE Medium Heavy Truck T2 - Diesel Engines", "code": "IRC-1221", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/test-series", "issuer": "National Institute for Automotive Service Excellence", "cost": "$62.00", "accommodations": "https://www.ase.com/ada2", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Validates expertise in diagnosing, repairing, and maintaining diesel engine systems in medium and heavy-duty commercial trucks.", "careerPaths": "Diesel Engine Technician, Commercial Truck Mechanic, Fleet Maintenance Technician, Heavy Equipment Technician, Transportation Equipment Mechanic", "goodFitFor": "Programs with diesel technology or commercial vehicle career tracks; programs partnered with trucking companies, bus fleets, or commercial equipment dealers; workforce development programs for older youth (16+) interested in high-wage transportation careers", "detailedDesc": "The ASE Medium/Heavy Truck T2 - Diesel Engines certification validates knowledge of diesel engine construction, fuel systems, air induction, exhaust, and engine diagnosis specific to medium and heavy-duty commercial vehicles. Diesel engine technology is central to commercial trucking, construction, and agriculture industries, and ASE T2-certified technicians are in high demand with strong earning potential. This credential is best suited for programs with diesel engine coursework or shop access and strong employer partnerships in the transportation or logistics sectors. It is a natural complement to ASE's full medium/heavy truck certification pathway."}, {"name": "ASE Medium Heavy Truck T3 - Drive Train", "code": "IRC-1222", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/test-series", "issuer": "National Institute for Automotive Service Excellence", "cost": "$62.00", "accommodations": "https://www.ase.com/ada2", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Validates skills in diagnosing and repairing clutch, transmission, driveshaft, and axle systems in medium and heavy-duty commercial trucks.", "careerPaths": "Commercial Truck Technician, Drive Train Mechanic, Fleet Maintenance Specialist, Heavy Equipment Technician, Transmission Technician", "goodFitFor": "Programs with commercial vehicle or diesel technology career tracks; programs partnered with trucking fleets, bus companies, or commercial vehicle repair shops; workforce development programs preparing older youth for well-paying transportation careers", "detailedDesc": "The ASE Medium/Heavy Truck T3 - Drive Train certification validates a technician's ability to diagnose and repair clutch assemblies, manual and automatic transmissions, driveshafts, differentials, and axle systems in medium and heavy commercial vehicles. Drive train systems are among the most complex and specialized components of commercial trucks, and technicians with this credential are highly valued in the transportation industry. This is an advanced credential best suited for programs with access to commercial vehicle components and instructors with fleet vehicle experience. It complements other ASE medium/heavy truck certifications."}, {"name": "ASE Medium Heavy Truck T4 - Brakes", "code": "IRC-1223", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/test-series", "issuer": "National Institute for Automotive Service Excellence", "cost": "$62.00", "accommodations": "https://www.ase.com/ada2", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Validates proficiency in inspecting, servicing, and repairing air and hydraulic brake systems on medium and heavy commercial trucks.", "careerPaths": "Commercial Truck Technician, Brake Specialist, Fleet Safety Technician, Commercial Vehicle Inspector, Transportation Equipment Mechanic", "goodFitFor": "Programs with commercial vehicle maintenance or transportation career tracks; programs partnered with trucking companies, bus fleets, or state vehicle inspection facilities; workforce development programs for older youth pursuing transportation and logistics careers", "detailedDesc": "The ASE Medium/Heavy Truck T4 - Brakes certification validates knowledge of air brakes, hydraulic brakes, anti-lock braking systems, and brake adjustment procedures specific to medium and heavy commercial vehicles. Brake safety is a federally regulated and critically important area of commercial vehicle maintenance, making this credential especially valued by fleet operators and inspection facilities. Technicians with this certification contribute directly to road safety and regulatory compliance. This credential pairs well with CDL preparation for youth pursuing comprehensive careers in commercial transportation."}, {"name": "ASE Medium Heavy Truck T5 - Suspension and Steering", "code": "IRC-1224", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/test-series", "issuer": "National Institute for Automotive Service Excellence", "cost": "$62.00", "accommodations": "https://www.ase.com/ada2", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Validates knowledge of suspension, steering, wheel alignment, and related systems on medium and heavy-duty commercial trucks.", "careerPaths": "Commercial Truck Technician, Suspension & Steering Specialist, Fleet Maintenance Technician, Heavy Vehicle Inspector, Transportation Equipment Mechanic", "goodFitFor": "Programs with commercial vehicle or heavy equipment career tracks; programs partnered with trucking fleets, bus companies, or commercial vehicle service centers; workforce development programs for older youth in transportation and logistics pathways", "detailedDesc": "The ASE Medium/Heavy Truck T5 - Suspension and Steering certification validates a technician's ability to diagnose and repair steering systems, front and rear suspensions, wheel alignments, and wheel bearings on medium and heavy commercial vehicles. Proper suspension and steering maintenance directly affects vehicle safety and cargo protection, making this a valued credential for fleet safety programs. This credential is part of the comprehensive ASE medium/heavy truck certification series and is best suited for programs with commercial vehicle components and partnerships with fleet operators or service centers."}, {"name": "ASE Medium Heavy Truck T6 - Electrical/Electronic Systems", "code": "IRC-1225", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/test-series", "issuer": "National Institute for Automotive Service Excellence", "cost": "$62.00", "accommodations": "https://www.ase.com/ada2", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Validates proficiency in diagnosing and repairing electrical, electronic, and multiplexing systems in medium and heavy commercial trucks.", "careerPaths": "Commercial Truck Electrician, Fleet Electronics Technician, Commercial Vehicle Technician, Diagnostic Technician, Transportation Equipment Mechanic", "goodFitFor": "Programs with commercial vehicle or advanced automotive technology career tracks; programs partnered with trucking companies, bus fleets, or dealerships using electronic diagnostic equipment; workforce development programs for youth with strong technical aptitude in transportation careers", "detailedDesc": "The ASE Medium/Heavy Truck T6 - Electrical/Electronic Systems certification validates expertise in diagnosing and servicing batteries, charging systems, starting systems, lighting, multiplexing networks, and advanced driver assistance systems on medium and heavy commercial trucks. As commercial vehicles become increasingly computerized, electrically-trained technicians are among the most sought-after in the transportation sector. This is an advanced credential that requires strong foundational electronics knowledge and is best delivered in programs with diagnostic equipment and experienced instructors. It completes a well-rounded medium/heavy truck technician credential portfolio."}, {"name": "ASE Medium Heavy Truck T1 - Gasoline Engines", "code": "IRC-1226", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/test-series", "issuer": "National Institute for Automotive Service Excellence", "cost": "$62.00", "accommodations": "https://www.ase.com/ada2", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Validates technician-level knowledge of gasoline engine diagnosis, repair, and maintenance for medium and heavy-duty trucks.", "careerPaths": "Medium/Heavy Truck Technician, Diesel/Gas Engine Mechanic, Fleet Maintenance Technician, Commercial Vehicle Technician, Transportation Equipment Mechanic", "goodFitFor": "Programs with automotive or diesel technology career tracks serving older youth (16+); programs partnered with trucking fleets, commercial vehicle dealerships, or transportation companies; pre-apprenticeship programs in the transportation and logistics sector", "detailedDesc": "The ASE Medium/Heavy Truck T1 - Gasoline Engines certification, issued by the National Institute for Automotive Service Excellence (ASE), validates a technician's knowledge of gasoline engine systems in medium and heavy-duty commercial vehicles, including diagnosis, repair, and performance testing. It is part of ASE's professional-level medium/heavy truck certification series, which is widely recognized by commercial fleet operators and truck dealerships. This credential is best suited for programs serving older youth with prior automotive fundamentals who are building toward commercial vehicle careers. It pairs well with other ASE medium/heavy truck credentials (T2\u2013T6) for comprehensive fleet technician preparation."}, {"name": "ASE Medium Heavy Truck T1 - Gasoline Engines", "code": "IRC-1227", "cluster": "Supply Chain & Transportation", "link": "https://ase.com/test-series", "issuer": "National Institute for Automotive Service Excellence", "cost": "$62.00", "accommodations": "https://www.ase.com/ada2", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "Validates technician-level knowledge of gasoline engine diagnosis, repair, and maintenance for medium and heavy-duty trucks.", "careerPaths": "Medium/Heavy Truck Technician, Diesel/Gas Engine Mechanic, Fleet Maintenance Technician, Commercial Vehicle Technician, Transportation Equipment Mechanic", "goodFitFor": "Programs with automotive or diesel technology career tracks serving older youth (16+); programs partnered with trucking fleets, commercial vehicle dealerships, or transportation companies; pre-apprenticeship programs in the transportation and logistics sector", "detailedDesc": "The ASE Medium/Heavy Truck T1 - Gasoline Engines certification, issued by the National Institute for Automotive Service Excellence (ASE), validates a technician's knowledge of gasoline engine systems in medium and heavy-duty commercial vehicles, including diagnosis, repair, and performance testing. It is part of ASE's professional-level medium/heavy truck certification series, which is widely recognized by commercial fleet operators and truck dealerships. This credential is best suited for programs serving older youth with prior automotive fundamentals who are building toward commercial vehicle careers. It pairs well with other ASE medium/heavy truck credentials (T2\u2013T6) for comprehensive fleet technician preparation."}, {"name": "Aluminum & Steel Small Dent Removal", "code": "IRC-1228", "cluster": "Supply Chain & Transportation", "link": "https://academy.i-car.com/schools/", "issuer": "I-CAR", "cost": "$286.00", "accommodations": "https://ed.sc.gov/instruction/career-and-technical-education/performance-accountability/career-and-technical-education-technical-skill-assessments/i-car-testing-information-form/#:~:text=What%20accommodations%20do%20you%20routinely,CAR%20or%20the%20proctor%20/%20instructor.", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "I-CAR credential validating skills in repairing minor dents in both aluminum and steel vehicle panels without damaging paint or body structure.", "careerPaths": "Auto Body Technician, Paintless Dent Repair Specialist, Collision Repair Technician, Vehicle Damage Appraiser, Body Shop Estimator", "goodFitFor": "Programs with automotive body or collision repair career tracks; programs partnered with auto body shops, dealerships, or fleet repair facilities; pre-apprenticeship programs in the collision repair industry; workforce development programs serving youth interested in skilled trades", "detailedDesc": "The I-CAR Aluminum & Steel Small Dent Removal credential validates a technician's ability to assess and repair minor dents in both aluminum and steel vehicle panels using appropriate techniques that preserve the original finish. As vehicles increasingly use lightweight aluminum construction, technicians proficient in both metals are in growing demand. This is an entry-to-intermediate level I-CAR credential suitable for programs with collision repair equipment and employer partnerships. It pairs well with other I-CAR credentials in the collision repair pathway."}, {"name": "Collision Repair Fundamentals", "code": "IRC-1229", "cluster": "Supply Chain & Transportation", "link": "https://academy.i-car.com/schools/", "issuer": "I-CAR", "cost": "$792.00", "accommodations": "https://ed.sc.gov/instruction/career-and-technical-education/performance-accountability/career-and-technical-education-technical-skill-assessments/i-car-testing-information-form/#:~:text=What%20accommodations%20do%20you%20routinely,CAR%20or%20the%20proctor%20/%20instructor.", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "I-CAR entry-level credential validating foundational knowledge of the collision repair process, repair planning, and industry terminology.", "careerPaths": "Auto Body Technician (entry), Collision Repair Technician, Body Shop Estimator (entry), Automotive Service Advisor, Fleet Repair Technician", "goodFitFor": "Programs with automotive or collision repair career tracks; programs introducing youth to the collision repair industry; programs partnered with auto body shops or insurance companies; pre-apprenticeship programs in automotive services", "detailedDesc": "The I-CAR Collision Repair Fundamentals credential introduces students to the core concepts of the collision repair industry, including damage assessment, repair planning, safety protocols, and an overview of repair processes for structural and non-structural damage. As the foundational entry point in I-CAR's training system, this credential is ideal for youth just beginning their exposure to collision repair careers. It lays the groundwork for more specialized I-CAR credentials and is well-suited for programs partnered with local body shops willing to provide mentorship or internship opportunities."}, {"name": "Disassembly and Reassembly", "code": "IRC-1230", "cluster": "Supply Chain & Transportation", "link": "https://academy.i-car.com/schools/", "issuer": "I-CAR", "cost": "$704.00", "accommodations": "https://ed.sc.gov/instruction/career-and-technical-education/performance-accountability/career-and-technical-education-technical-skill-assessments/i-car-testing-information-form/#:~:text=What%20accommodations%20do%20you%20routinely,CAR%20or%20the%20proctor%20/%20instructor.", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "I-CAR credential validating proper techniques for disassembling and reassembling vehicle components to facilitate collision repair work.", "careerPaths": "Auto Body Technician, Collision Repair Technician, Automotive Disassembly Technician, Parts Specialist, Fleet Maintenance Technician", "goodFitFor": "Programs with collision repair or automotive technology career tracks; programs partnered with auto body shops or dealerships; workforce development programs for youth interested in hands-on automotive careers; pre-apprenticeship programs in auto body repair", "detailedDesc": "The I-CAR Disassembly and Reassembly credential validates a student's ability to systematically disassemble and reassemble vehicle components for collision repair, including proper parts identification, removal sequences, and component reinstallation. This is a foundational hands-on skill in collision repair that reduces repair times and prevents secondary damage. The credential is recognized by auto body employers as a mark of shop-readiness and is suitable for programs with automotive bays or partnership access to collision repair facilities. It is a strong complement to other I-CAR credentials in the collision repair training sequence."}, {"name": "Plastic Repair", "code": "IRC-1231", "cluster": "Supply Chain & Transportation", "link": "https://academy.i-car.com/schools/", "issuer": "I-CAR", "cost": "$100.00", "accommodations": "https://ed.sc.gov/instruction/career-and-technical-education/performance-accountability/career-and-technical-education-technical-skill-assessments/i-car-testing-information-form/#:~:text=What%20accommodations%20do%20you%20routinely,CAR%20or%20the%20proctor%20/%20instructor.", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "I-CAR credential certifying skills in repairing plastic vehicle components including bumpers, fascias, and interior trim panels.", "careerPaths": "Auto Body Technician, Plastic Repair Specialist, Collision Repair Technician, Fleet Maintenance Technician, Automotive Refinish Technician", "goodFitFor": "Programs with collision repair or automotive technology career tracks; programs with automotive body shops or access to vehicles for hands-on practice; programs partnered with auto body or dealership employers; workforce development programs in automotive services", "detailedDesc": "The I-CAR Plastic Repair credential validates a technician's ability to repair damaged plastic components on vehicles, including bumper covers, fascias, cladding, and interior plastic trim, using bonding adhesives, plastic welding, and cosmetic finishing techniques. As modern vehicles use increasing amounts of plastic in their construction, plastic repair is a growing and highly practical skill in the collision repair industry. This credential is recognized by body shops and dealerships as evidence of hands-on competency. It pairs well with other I-CAR credentials for youth building a complete collision repair skill set."}, {"name": "Preparation for Refinish", "code": "IRC-1232", "cluster": "Supply Chain & Transportation", "link": "https://academy.i-car.com/schools/", "issuer": "I-CAR", "cost": "$100.00", "accommodations": "https://ed.sc.gov/instruction/career-and-technical-education/performance-accountability/career-and-technical-education-technical-skill-assessments/i-car-testing-information-form/#:~:text=What%20accommodations%20do%20you%20routinely,CAR%20or%20the%20proctor%20/%20instructor.", "effDate": "July 1, 2026", "hours": null, "trainingNotes": null, "prereqs": null, "under5weeks": null, "cclModule": null, "cclExpert": null, "oneLiner": "I-CAR credential validating skills in preparing vehicle surfaces for painting, including sanding, priming, masking, and surface correction.", "careerPaths": "Auto Refinish Technician, Prep Technician, Automotive Painter (entry), Collision Repair Technician, Body Shop Technician", "goodFitFor": "Programs with collision repair, auto body, or refinishing career tracks; programs partnered with auto body shops or refinishing facilities; workforce development programs serving youth pursuing skilled trades; pre-apprenticeship programs in the automotive sector", "detailedDesc": "The I-CAR Preparation for Refinish credential validates a student's ability to properly prepare vehicle surfaces for the refinish (painting) process, including sanding, surface cleaning, masking, and primer application. Proper surface preparation is one of the most critical steps in achieving a high-quality, durable paint finish, and prep technicians are in consistent demand at body shops. This credential is a strong fit for programs with refinishing equipment or partnerships with body shops that offer hands-on training. It connects naturally to the I-CAR Refinish Technician credential pathway."}];
